{
  "name": "SignSense AI - Holistic Recognizer",
  "description": "Real-time sign language landmark extraction using MediaPipe Holistic, tracking 543 keypoints across face, pose, and hands.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Point {
  x: number;
  y: number;
  z?: number;
  visibility?: number;
}

export interface HolisticResults {
  faceLandmarks?: Point[];
  poseLandmarks?: Point[];
  leftHandLandmarks?: Point[];
  rightHandLandmarks?: Point[];
  image: HTMLCanvasElement | HTMLVideoElement | ImageBitmap;
}

export interface LandmarkStats {
  face: number;
  pose: number;
  leftHand: number;
  rightHand: number;
  total: number;
}

import React, { useEffect, useRef, useState } from 'react';
import { Holistic, RESULTS_CANVAS, FACEMESH_TESSELATION, HAND_CONNECTIONS, POSE_CONNECTIONS } from '@mediapipe/holistic';
import { Camera } from '@mediapipe/camera_utils';
import { drawConnectors, drawLandmarks } from '@mediapipe/drawing_utils';
import { HolisticResults } from '../types';

interface HolisticCameraProps {
  onResults: (results: HolisticResults) => void;
  onFpsUpdate: (fps: number) => void;
}

const HolisticCamera: React.FC<HolisticCameraProps> = ({ onResults, onFpsUpdate }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Performance tracking
  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);

  useEffect(() => {
    if (!videoRef.current || !canvasRef.current) return;

    const holistic = new Holistic({
      locateFile: (file) => {
        return `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`;
      },
    });

    holistic.setOptions({
      modelComplexity: 1,
      smoothLandmarks: true,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
      refineFaceLandmarks: true,
    });

    holistic.onResults((results) => {
      onResults(results);

      // Update FPS
      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current >= 1000) {
        onFpsUpdate(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0;
        lastTimeRef.current = now;
      }

      const canvasCtx = canvasRef.current?.getContext('2d');
      if (!canvasCtx || !canvasRef.current) return;

      canvasCtx.save();
      canvasCtx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);

      // Mirror horizontal for natural preview
      canvasCtx.scale(-1, 1);
      canvasCtx.translate(-canvasRef.current.width, 0);

      // Draw the video frame
      canvasCtx.drawImage(results.image, 0, 0, canvasRef.current.width, canvasRef.current.height);

      // Drawing styles
      const landmarkStyle = { color: '#6366f1', lineWidth: 1, radius: 1 };
      const connectorStyle = { color: 'rgba(255, 255, 255, 0.2)', lineWidth: 1 };

      // 1. Draw Face Mesh (468 points)
      if (results.faceLandmarks) {
        drawConnectors(canvasCtx, results.faceLandmarks, FACEMESH_TESSELATION, { color: 'rgba(255, 255, 255, 0.1)', lineWidth: 0.5 });
      }

      // 2. Draw Pose (33 points)
      if (results.poseLandmarks) {
        drawConnectors(canvasCtx, results.poseLandmarks, POSE_CONNECTIONS, { color: '#4f46e5', lineWidth: 2 });
        drawLandmarks(canvasCtx, results.poseLandmarks, { ...landmarkStyle, color: '#f59e0b', radius: 2 });
      }

      // 3. Draw Left Hand (21 points)
      if (results.leftHandLandmarks) {
        drawConnectors(canvasCtx, results.leftHandLandmarks, HAND_CONNECTIONS, { color: '#ec4899', lineWidth: 2 });
        drawLandmarks(canvasCtx, results.leftHandLandmarks, { ...landmarkStyle, color: '#ec4899', radius: 2 });
      }

      // 4. Draw Right Hand (21 points)
      if (results.rightHandLandmarks) {
        drawConnectors(canvasCtx, results.rightHandLandmarks, HAND_CONNECTIONS, { color: '#06b6d4', lineWidth: 2 });
        drawLandmarks(canvasCtx, results.rightHandLandmarks, { ...landmarkStyle, color: '#06b6d4', radius: 2 });
      }

      canvasCtx.restore();
      if (isLoading) setIsLoading(false);
    });

    let camera: Camera | null = null;

    const startCamera = async () => {
      try {
        if (!videoRef.current) return;
        camera = new Camera(videoRef.current, {
          onFrame: async () => {
            if (videoRef.current) {
              await holistic.send({ image: videoRef.current });
            }
          },
          width: 1280,
          height: 720,
        });
        await camera.start();
      } catch (err) {
        console.error("Camera failed:", err);
        setError("Could not access camera. Please check permissions.");
        setIsLoading(false);
      }
    };

    startCamera();

    return () => {
      camera?.stop();
      holistic.close();
    };
  }, []);

  return (
    <div className="relative w-full h-full flex items-center justify-center bg-black">
      {isLoading && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900">
          <div className="relative w-20 h-20 mb-4">
            <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
            <div className="absolute inset-0 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
          <p className="text-indigo-400 font-bold tracking-widest text-sm animate-pulse uppercase">
            Initializing AI Models...
          </p>
        </div>
      )}

      {error && (
        <div className="absolute inset-0 z-30 flex flex-col items-center justify-center bg-slate-950 p-6 text-center">
          <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-4">
            <span className="text-3xl">ŌÜĀ’ĖÅ</span>
          </div>
          <h3 className="text-xl font-bold text-white mb-2">Hardware Error</h3>
          <p className="text-slate-400 max-w-xs leading-relaxed">{error}</p>
          <button 
            onClick={() => window.location.reload()}
            className="mt-6 px-6 py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg text-sm font-bold transition-all"
          >
            Retry Connection
          </button>
        </div>
      )}

      <video
        ref={videoRef}
        className="hidden"
        playsInline
        muted
      />
      <canvas
        ref={canvasRef}
        className="w-full h-full object-contain"
        width={1280}
        height={720}
      />
    </div>
  );
};

