      if (results.rightHandLandmarks && drawConnectors && drawLandmarks && HAND_CONNECTIONS) {
        drawConnectors(canvasCtx, results.rightHandLandmarks, HAND_CONNECTIONS, { color: '#06b6d4', lineWidth: 2 });
        drawLandmarks(canvasCtx, results.rightHandLandmarks, { color: '#06b6d4', lineWidth: 1, radius: 2 });
      }

      canvasCtx.restore();
      if (isLoading) setIsLoading(false);
    });

    let cameraInstance: any = null;

    const startCamera = async () => {
      try {
        if (!videoRef.current) return;

        const CameraClass = (CameraModule as any).Camera || (CameraModule as any).default?.Camera;
        if (!CameraClass) {
          throw new Error("Camera class not found in @mediapipe/camera_utils");
        }

        cameraInstance = new CameraClass(videoRef.current, {
          onFrame: async () => {
            if (videoRef.current) {
              await holistic.send({ image: videoRef.current });
            }
          },
          width: 1280,
          height: 720,
        });
        await cameraInstance.start();
      } catch (err) {
        console.error("Camera startup failed:", err);
        setError("Could not access camera. Please check permissions.");
        setIsLoading(false);
      }
    };

    startCamera();

    return () => {
      cameraInstance?.stop();
      holistic.close();
    };
  }, []);

  return (
    <div className="relative w-full h-full flex items-center justify-center bg-black">
      {isLoading && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900">
          <div className="relative w-20 h-20 mb-4">
            <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
            <div className="absolute inset-0 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
          <p className="text-indigo-400 font-bold tracking-widest text-sm animate-pulse uppercase">
            Initializing AI Models...
          </p>
        </div>
      )}

      {error && (
        <div className="absolute inset-0 z-30 flex flex-col items-center justify-center bg-slate-950 p-6 text-center">
          <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-4">
            <span className="text-3xl">ŌÜĀ’ĖÅ</span>
          </div>
          <h3 className="text-xl font-bold text-white mb-2">System Error</h3>
          <p className="text-slate-400 max-w-xs leading-relaxed">{error}</p>
          <button 
            onClick={() => window.location.reload()}
            className="mt-6 px-6 py-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg text-sm font-bold transition-all"
          >
            Retry Connection
          </button>
        </div>
      )}

      <video
        ref={videoRef}
        className="hidden"
        playsInline
        muted
      />
      <canvas
        ref={canvasRef}
        className="w-full h-full object-contain"
        width={1280}
        height={720}
      />
    </div>
  );
};

