        <div className="flex-1 relative bg-slate-900 rounded-2xl border border-slate-800 overflow-hidden shadow-2xl group z-0">
          <HolisticCamera 
            config={config}
            onResults={(res, filtered) => {
              setStats({
                face: res.faceLandmarks?.length || 0,
                pose: res.poseLandmarks?.length || 0,
                leftHand: res.leftHandLandmarks?.length || 0,
                rightHand: res.rightHandLandmarks?.length || 0,
                total: (res.faceLandmarks?.length || 0) + (res.poseLandmarks?.length || 0) + (res.leftHandLandmarks?.length || 0) + (res.rightHandLandmarks?.length || 0),
                activeFeatures: filtered.length
              });
            }}
            onFpsUpdate={setFps}
          />

          {/* Recognition HUD Overlay */}
          <div className="absolute inset-x-0 bottom-12 flex justify-center pointer-events-none">
            {prediction ? (
              <div className="bg-green-500 text-white px-8 py-4 rounded-2xl shadow-2xl animate-bounce-short border-4 border-white/20 backdrop-blur-xl">
                 <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-80 mb-1">RECOGNIZED SIGN</p>
                 <h2 className="text-4xl font-black tracking-tighter uppercase">{prediction.word}</h2>
                 <p className="text-xs font-bold opacity-60">Confidence: {(prediction.confidence * 100).toFixed(1)}%</p>
              </div>
            ) : (
              <div className="bg-slate-950/40 backdrop-blur-md px-6 py-2 rounded-full border border-white/10 text-white/40 text-xs font-bold uppercase tracking-widest">
                Waiting for gesture...
              </div>
            )}
          </div>
        </div>

        <aside className={`${showStats ? 'flex' : 'hidden md:flex'} absolute md:relative inset-x-2 bottom-2 md:inset-auto w-auto md:w-80 flex flex-col gap-4 z-10`}>
          <section className="bg-slate-900/95 backdrop-blur-xl border border-slate-800 rounded-2xl p-5 shadow-2xl">
            <h2 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2 mb-4">
              <Activity className="w-4 h-4 text-indigo-500" />
              Feature Extraction
            </h2>

            <div className="space-y-4">
              <StatItem label="Tensor Input Features" value={stats.activeFeatures} target={config.model_config.input_shape[2]} color="indigo" />
              <div className="grid grid-cols-2 gap-3">
                <MiniStat label="Pose" value={stats.pose} active={config.keypoints_config.pose_indices !== "NONE"} />
                <MiniStat label="Face" value={stats.face} active={config.keypoints_config.face_indices !== "NONE"} />
                <MiniStat label="L-Hand" value={stats.leftHand} active={config.keypoints_config.leftHand_indices !== "NONE"} />
                <MiniStat label="R-Hand" value={stats.rightHand} active={config.keypoints_config.rightHand_indices !== "NONE"} />
              </div>
            </div>
          </section>

          <section className="bg-slate-900/50 border border-slate-800/50 rounded-2xl p-5 flex-1 overflow-auto">
            <h3 className="text-xs font-bold text-slate-500 uppercase mb-4 flex items-center gap-2">
              <Terminal className="w-4 h-4" />
              Engine Configuration
            </h3>
            <div className="space-y-3 font-mono text-[10px]">
               <div className="flex justify-between border-b border-white/5 pb-1.5">
                  <span className="text-slate-500">Model</span>
                  <span className="text-indigo-400 truncate ml-4">{config.model_config.model_filename}</span>
               </div>
               <div className="flex justify-between border-b border-white/5 pb-1.5">
                  <span className="text-slate-500">Shape</span>
                  <span className="text-slate-300">[{config.model_config.input_shape.join(', ')}]</span>
               </div>
               <div className="flex justify-between border-b border-white/5 pb-1.5">
                  <span className="text-slate-500">Threshold</span>
                  <span className="text-slate-300">{config.inference_logic.confidence_threshold}</span>
               </div>
               <div className="flex justify-between border-b border-white/5 pb-1.5">
                  <span className="text-slate-500">Normalization</span>
                  <span className="text-green-500 uppercase">{config.preprocessing.normalization.method}</span>
               </div>
            </div>
          </section>
        </aside>
      </main>
    </div>
  );
};

const StatItem: React.FC<{ label: string; value: number; target: number; color: string }> = ({ label, value, target, color }) => (
  <div>
    <div className="flex justify-between items-end mb-1.5">
      <span className="text-[10px] text-slate-500 font-bold uppercase">{label}</span>
      <span className="text-sm font-mono font-bold text-indigo-400">{value} / {target}</span>
    </div>
    <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
      <div 
        className={`h-full bg-indigo-500 transition-all duration-300 ease-out shadow-[0_0_8px_rgba(99,102,241,0.4)]`}
        style={{ width: `${Math.min(100, (value / target) * 100)}%` }}
      />
    </div>
  </div>
);

const MiniStat: React.FC<{ label: string; value: number; active: boolean }> = ({ label, value, active }) => (
  <div className={`p-3 rounded-xl border transition-colors ${active ? 'bg-slate-800/30 border-indigo-500/20' : 'bg-slate-900/50 border-slate-800 grayscale'}`}>
    <p className={`text-[9px] font-bold uppercase mb-0.5 ${active ? 'text-indigo-400' : 'text-slate-600'}`}>{label}</p>
    <p className={`text-sm font-mono font-bold ${active ? 'text-white' : 'text-slate-700'}`}>{value}</p>
  </div>
);

export default App;

