export interface Point {
  x: number;
  y: number;
  z?: number;
  visibility?: number;
}

export interface HolisticResults {
  faceLandmarks?: Point[];
  poseLandmarks?: Point[];
  leftHandLandmarks?: Point[];
  rightHandLandmarks?: Point[];
  image: HTMLCanvasElement | HTMLVideoElement | ImageBitmap;
}

export interface LandmarkStats {
  face: number;
  pose: number;
  leftHand: number;
  rightHand: number;
  total: number;
  activeFeatures: number;
}

export interface AppConfig {
  app_settings: {
    app_name: string;
    version: string;
    debug_mode: boolean;
  };
  model_config: {
    model_filename: string;
    labels_filename: string;
    input_shape: number[];
    is_quantized: boolean;
  };
  keypoints_config: {
    pose_indices: "ALL" | "NONE" | number[];
    face_indices: "ALL" | "NONE" | number[];
    leftHand_indices: "ALL" | "NONE" | number[];
    rightHand_indices: "ALL" | "NONE" | number[];
    flattening_order: string[];
  };
  // Added missing preprocessing definition to satisfy App.tsx requirements
  preprocessing: {
    normalization: {
      method: string;
    };
  };
  inference_logic: {
    confidence_threshold: number;
    trigger_threshold_y: number;
    prediction_debounce_ms: number;
  };
  ui_feedback: {
    success_message_duration_ms: number;
    silouhette_guide_enabled: boolean;
  };
}

import React, { useEffect, useRef, useState } from 'react';
import * as HolisticModule from '@mediapipe/holistic';
import * as CameraModule from '@mediapipe/camera_utils';
import * as DrawingModule from '@mediapipe/drawing_utils';
import { HolisticResults, AppConfig } from '../types';

interface HolisticCameraProps {
  config: AppConfig;
  onResults: (results: HolisticResults, filteredPoints: number[]) => void;
  onFpsUpdate: (fps: number) => void;
}

const HolisticCamera: React.FC<HolisticCameraProps> = ({ config, onResults, onFpsUpdate }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isActive, setIsActive] = useState(false);

  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);

  // Helper to filter points based on config indices
  const filterPoints = (landmarks: any[] | undefined, filter: "ALL" | "NONE" | number[]): any[] => {
    if (!landmarks || filter === "NONE") return [];
    if (filter === "ALL") return landmarks;
    return filter.map(idx => landmarks[idx]).filter(p => !!p);
  };

  useEffect(() => {
    if (!videoRef.current || !canvasRef.current) return;

    const HolisticClass = (HolisticModule as any).Holistic || (HolisticModule as any).default?.Holistic;
    const FACEMESH_TESSELATION = (HolisticModule as any).FACEMESH_TESSELATION || (HolisticModule as any).default?.FACEMESH_TESSELATION;
    const HAND_CONNECTIONS = (HolisticModule as any).HAND_CONNECTIONS || (HolisticModule as any).default?.HAND_CONNECTIONS;
    const POSE_CONNECTIONS = (HolisticModule as any).POSE_CONNECTIONS || (HolisticModule as any).default?.POSE_CONNECTIONS;
    const drawConnectors = (DrawingModule as any).drawConnectors || (DrawingModule as any).default?.drawConnectors;
    const drawLandmarks = (DrawingModule as any).drawLandmarks || (DrawingModule as any).default?.drawLandmarks;

    if (!HolisticClass) {
      setError("Failed to initialize tracking models.");
      return;
    }

    const holistic = new HolisticClass({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`,
    });

    holistic.setOptions({
      modelComplexity: 1,
      smoothLandmarks: true,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
      refineFaceLandmarks: config.keypoints_config.face_indices !== "NONE",
    });

    holistic.onResults((results: any) => {
      // 1. Process Filtered Points for Model
      const filteredData: number[] = [];
      const kpCfg = config.keypoints_config;

      kpCfg.flattening_order.forEach(key => {
        let raw;
        let filter;
        if (key === "pose") { raw = results.poseLandmarks; filter = kpCfg.pose_indices; }
        else if (key === "face") { raw = results.faceLandmarks; filter = kpCfg.face_indices; }
        // Fix: Use correct camelCase property name for leftHand_indices
        else if (key === "leftHand") { raw = results.leftHandLandmarks; filter = kpCfg.leftHand_indices; }
        // Fix: Use correct camelCase property name for rightHand_indices
        else if (key === "rightHand") { raw = results.rightHandLandmarks; filter = kpCfg.rightHand_indices; }

        const filtered = filterPoints(raw, filter as any);
        filtered.forEach(p => {
          filteredData.push(p.x, p.y, p.z || 0);
        });
      });

      // Trigger threshold check (check if hands are high enough)
      const leftY = results.leftHandLandmarks?.[0]?.y || 1.0;
      const rightY = results.rightHandLandmarks?.[0]?.y || 1.0;
      const isHandActive = leftY < (0.5 + config.inference_logic.trigger_threshold_y) || 
                           rightY < (0.5 + config.inference_logic.trigger_threshold_y);
      setIsActive(isHandActive);

      onResults(results, filteredData);

      // Update FPS
      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current >= 1000) {
        onFpsUpdate(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0;
        lastTimeRef.current = now;
      }

      const canvasCtx = canvasRef.current?.getContext('2d');
      if (!canvasCtx || !canvasRef.current) return;

      canvasCtx.save();
      canvasCtx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      canvasCtx.scale(-1, 1);
      canvasCtx.translate(-canvasRef.current.width, 0);

      // Draw Video
      canvasCtx.drawImage(results.image, 0, 0, canvasRef.current.width, canvasRef.current.height);

      // 2. Draw Landmark Overlays
      if (results.faceLandmarks && kpCfg.face_indices !== "NONE" && drawConnectors && FACEMESH_TESSELATION) {
        drawConnectors(canvasCtx, results.faceLandmarks, FACEMESH_TESSELATION, { color: '#00FF0033', lineWidth: 0.5 });
      }

      if (results.poseLandmarks && kpCfg.pose_indices !== "NONE" && drawConnectors && POSE_CONNECTIONS) {
        drawConnectors(canvasCtx, results.poseLandmarks, POSE_CONNECTIONS, { color: '#4f46e5', lineWidth: 2 });
      }

      const handColor = isHandActive ? '#22c55e' : '#64748b';

      if (results.leftHandLandmarks && drawConnectors && HAND_CONNECTIONS) {
        drawConnectors(canvasCtx, results.leftHandLandmarks, HAND_CONNECTIONS, { color: handColor, lineWidth: 2 });
        drawLandmarks(canvasCtx, results.leftHandLandmarks, { color: handColor, lineWidth: 1, radius: 2 });
      }

      if (results.rightHandLandmarks && drawConnectors && HAND_CONNECTIONS) {
        drawConnectors(canvasCtx, results.rightHandLandmarks, HAND_CONNECTIONS, { color: handColor, lineWidth: 2 });
        drawLandmarks(canvasCtx, results.rightHandLandmarks, { color: handColor, lineWidth: 1, radius: 2 });
      }

      // 3. Draw Silhouette Guide if enabled
      if (config.ui_feedback.silouhette_guide_enabled) {
        canvasCtx.restore();
        canvasCtx.save();
        canvasCtx.strokeStyle = isHandActive ? 'rgba(34, 197, 94, 0.4)' : 'rgba(100, 116, 139, 0.2)';
        canvasCtx.lineWidth = 4;
        canvasCtx.setLineDash([15, 10]);
        // Draw simple human silhouette shape
        const w = canvasRef.current.width;
        const h = canvasRef.current.height;
        canvasCtx.beginPath();
        canvasCtx.arc(w/2, h/4, h/8, 0, Math.PI * 2); // Head
        canvasCtx.moveTo(w/2 - w/4, h); // Body outline
        canvasCtx.lineTo(w/2 - w/5, h/2.5);
        canvasCtx.lineTo(w/2 + w/5, h/2.5);
        canvasCtx.lineTo(w/2 + w/4, h);
        canvasCtx.stroke();
      }

      canvasCtx.restore();
      if (isLoading) setIsLoading(false);
    });

    let cameraInstance: any = null;
    const startCamera = async () => {
      try {
        const CameraClass = (CameraModule as any).Camera || (CameraModule as any).default?.Camera;
        cameraInstance = new CameraClass(videoRef.current!, {
          onFrame: async () => { if (videoRef.current) await holistic.send({ image: videoRef.current }); },
          width: 1280, height: 720,
        });
        await cameraInstance.start();
      } catch (err) {
        setError("Could not access camera.");
        setIsLoading(false);
      }
    };

    startCamera();
    return () => { cameraInstance?.stop(); holistic.close(); };
  }, [config]);

  return (
    <div className="relative w-full h-full bg-black overflow-hidden">
      {isLoading && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900">
          <div className="relative w-20 h-20 mb-4">
            <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
            <div className="absolute inset-0 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
          <p className="text-indigo-400 font-bold tracking-widest text-sm animate-pulse uppercase">Loading ISLR Config...</p>
        </div>
      )}

      {error && <div className="absolute inset-0 z-30 flex flex-col items-center justify-center bg-slate-950 text-white p-6 text-center">{error}</div>}

      <video ref={videoRef} className="hidden" playsInline muted />
      <canvas ref={canvasRef} className="w-full h-full object-contain" width={1280} height={720} />

      {/* Activity Indicator Overlay */}
      <div className={`absolute bottom-6 right-6 px-4 py-2 rounded-lg backdrop-blur-md border transition-all duration-500 ${isActive ? 'bg-green-500/20 border-green-500/50' : 'bg-slate-900/50 border-slate-700'}`}>
         <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isActive ? 'bg-green-500 animate-ping' : 'bg-slate-600'}`}></div>
            <span className={`text-xs font-bold uppercase tracking-widest ${isActive ? 'text-green-400' : 'text-slate-500'}`}>
              {isActive ? 'Capturing Sign' : 'System Idle'}
            </span>
         </div>
      </div>
    </div>
  );
};

export default HolisticCamera;

