import React, { useEffect, useRef, useState } from 'react';
import * as HolisticModule from '@mediapipe/holistic';
import * as CameraModule from '@mediapipe/camera_utils';
import * as DrawingModule from '@mediapipe/drawing_utils';
import { UserX, AlertCircle } from 'lucide-react';
import { HolisticResults, AppConfig, ViewportStatus } from '../types';

interface HolisticCameraProps {
  config: AppConfig;
  facingMode: 'user' | 'environment';
  prediction: { word: string, confidence: number } | null;
  onViewportStatusChange: (status: ViewportStatus) => void;
  onResults: (results: HolisticResults, filteredPoints: number[]) => void;
  onFpsUpdate: (fps: number) => void;
}

const HolisticCamera: React.FC<HolisticCameraProps> = ({ config, facingMode, prediction, onViewportStatusChange, onResults, onFpsUpdate }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [viewportStatus, setViewportStatus] = useState<ViewportStatus>({ state: 'NOT_DETECTED', instruction: 'Detecting...' });

  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);
  const cameraInstanceRef = useRef<any>(null);

  const filterPoints = (landmarks: any[] | undefined, filter: "ALL" | "NONE" | number[]): any[] => {
    if (!landmarks || filter === "NONE") return [];
    if (filter === "ALL") return landmarks;
    return filter.map(idx => landmarks[idx]).filter(p => !!p);
  };

  const checkViewportLogic = (poseLandmarks: any[] | undefined): ViewportStatus => {
    if (!poseLandmarks || poseLandmarks.length === 0) {
      return { state: 'NOT_DETECTED', instruction: 'User Not Found' };
    }

    const nose = poseLandmarks[0];
    const lShoulder = poseLandmarks[11];
    const rShoulder = poseLandmarks[12];

    if (!nose || !lShoulder || !rShoulder) {
      return { state: 'NOT_DETECTED', instruction: 'Show Upper Body' };
    }

    const shoulderCenterX = (lShoulder.x + rShoulder.x) / 2;
    if (shoulderCenterX < 0.30) return { state: 'MOVE_RIGHT', instruction: 'ADJUST RIGHT' };
    if (shoulderCenterX > 0.70) return { state: 'MOVE_LEFT', instruction: 'ADJUST LEFT' };

    const shoulderWidth = Math.abs(lShoulder.x - rShoulder.x);
    if (shoulderWidth > 0.85) return { state: 'TOO_CLOSE', instruction: 'MOVE BACK' };
    if (shoulderWidth < 0.15) return { state: 'TOO_FAR', instruction: 'MOVE CLOSER' };

    if (nose.y < 0.02) return { state: 'TOO_CLOSE', instruction: 'POSITION LOWER' };
    if (nose.y > 0.65) return { state: 'TOO_FAR', instruction: 'POSITION HIGHER' };

    return { state: 'READY', instruction: 'READY' };
  };

  useEffect(() => {
    if (!videoRef.current || !canvasRef.current) return;

    const HolisticClass = (HolisticModule as any).Holistic || (HolisticModule as any).default?.Holistic;
    const POSE_CONNECTIONS = (HolisticModule as any).POSE_CONNECTIONS || (HolisticModule as any).default?.POSE_CONNECTIONS;
    const HAND_CONNECTIONS = (HolisticModule as any).HAND_CONNECTIONS || (HolisticModule as any).default?.HAND_CONNECTIONS;
    const FACEMESH_TESSELATION = (HolisticModule as any).FACEMESH_TESSELATION || (HolisticModule as any).default?.FACEMESH_TESSELATION;
    const drawConnectors = (DrawingModule as any).drawConnectors || (DrawingModule as any).default?.drawConnectors;
    const drawLandmarks = (DrawingModule as any).drawLandmarks || (DrawingModule as any).default?.drawLandmarks;

    if (!HolisticClass) {
      setError("Failed to load tracking engine.");
      return;
    }

    const holistic = new HolisticClass({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`,
    });

    holistic.setOptions({
      modelComplexity: 1,
      smoothLandmarks: true,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
      refineFaceLandmarks: config.keypoints_config.face_indices !== "NONE",
    });

    holistic.onResults((results: any) => {
      const currentStatus = checkViewportLogic(results.poseLandmarks);
      if (currentStatus.state !== viewportStatus.state) {
        setViewportStatus(currentStatus);
        onViewportStatusChange(currentStatus);
      }

      const filteredData: number[] = [];
      const kpCfg = config.keypoints_config;

      kpCfg.flattening_order.forEach(key => {
        let raw;
        let filter;
        if (key === "pose") { raw = results.poseLandmarks; filter = kpCfg.pose_indices; }
        else if (key === "face") { raw = results.faceLandmarks; filter = kpCfg.face_indices; }
        else if (key === "leftHand") { raw = results.leftHandLandmarks; filter = kpCfg.leftHand_indices; }
        else if (key === "rightHand") { raw = results.rightHandLandmarks; filter = kpCfg.rightHand_indices; }

        const filtered = filterPoints(raw, filter as any);
        filtered.forEach(p => {
          filteredData.push(p.x, p.y, p.z || 0);
        });
      });

      onResults(results, filteredData);

      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current >= 1000) {
        onFpsUpdate(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0;
        lastTimeRef.current = now;
      }

      const canvasCtx = canvasRef.current?.getContext('2d');
      if (!canvasCtx || !canvasRef.current) return;

      canvasCtx.save();
      canvasCtx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);

      if (facingMode === 'user') {
        canvasCtx.scale(-1, 1);
        canvasCtx.translate(-canvasRef.current.width, 0);
      }

      canvasCtx.drawImage(results.image, 0, 0, canvasRef.current.width, canvasRef.current.height);

      const { colors, drawing } = config.visual_config;

      if (results.poseLandmarks && drawConnectors && POSE_CONNECTIONS) {
        drawConnectors(canvasCtx, results.poseLandmarks, POSE_CONNECTIONS, { 
          color: colors.pose, lineWidth: drawing.connector_line_width 
        });
        drawLandmarks(canvasCtx, results.poseLandmarks, { 
          color: colors.pose, lineWidth: drawing.line_width, radius: drawing.landmark_radius 
        });
      }

      if (results.leftHandLandmarks && drawConnectors && HAND_CONNECTIONS) {
        drawConnectors(canvasCtx, results.leftHandLandmarks, HAND_CONNECTIONS, { 
          color: colors.hands, lineWidth: drawing.connector_line_width 
        });
        drawLandmarks(canvasCtx, results.leftHandLandmarks, { 
          color: colors.hands, lineWidth: drawing.line_width, radius: drawing.landmark_radius 
        });
      }

      if (results.rightHandLandmarks && drawConnectors && HAND_CONNECTIONS) {
        drawConnectors(canvasCtx, results.rightHandLandmarks, HAND_CONNECTIONS, { 
          color: colors.hands, lineWidth: drawing.connector_line_width 
        });
        drawLandmarks(canvasCtx, results.rightHandLandmarks, { 
          color: colors.hands, lineWidth: drawing.line_width, radius: drawing.landmark_radius 
        });
      }

      canvasCtx.restore();
      canvasCtx.save();

      const isReady = currentStatus.state === 'READY';
      const borderThickness = 12;
      const w = canvasRef.current.width;
      const h = canvasRef.current.height;

      const mainColor = isReady ? colors.ready : colors.error;
      // Ultra dark deep colors: Red 950 (#450a0a) or Green 950 (#052e16)
      const iconColor = isReady ? '#052e16' : '#450a0a'; 
      const icon = isReady ? '­¤æŹ' : '­¤æÄ';
      const message = currentStatus.instruction.toUpperCase();

      canvasCtx.font = 'bold 36px sans-serif';
      const iconMetrics = canvasCtx.measureText(icon);
      const textMetrics = canvasCtx.measureText(message);
      const padding = 24;
      const spacing = 16;
      const totalWidth = iconMetrics.width + textMetrics.width + spacing + (padding * 2);
      const centerX = w / 2;

      // Move even further down to clear any browser UI or notches
      const topY = 50; 

      canvasCtx.lineWidth = borderThickness;
      canvasCtx.strokeStyle = mainColor + '88';

      canvasCtx.beginPath();
      canvasCtx.moveTo(centerX + totalWidth / 2, topY);
      canvasCtx.lineTo(w - borderThickness / 2, topY); 
      canvasCtx.lineTo(w - borderThickness / 2, h - borderThickness / 2); 
      canvasCtx.lineTo(borderThickness / 2, h - borderThickness / 2); 
      canvasCtx.lineTo(borderThickness / 2, topY); 
      canvasCtx.lineTo(centerX - totalWidth / 2, topY); 
      canvasCtx.stroke();

      if (isReady && prediction) {
        canvasCtx.strokeStyle = colors.ready;
        canvasCtx.lineWidth = borderThickness / 2;
        const perimeter = (w + h) * 2;
        const dashLen = perimeter * prediction.confidence;
        canvasCtx.setLineDash([dashLen, perimeter - dashLen]);
        canvasCtx.strokeRect(borderThickness * 1.5, topY + borderThickness, w - borderThickness * 3, h - topY - borderThickness * 2);
      } else if (!isReady && currentStatus.state !== 'NOT_DETECTED') {
        const pulse = 0.5 + 0.5 * Math.sin(Date.now() / 200);
        canvasCtx.strokeStyle = colors.error;
        canvasCtx.globalAlpha = 0.3 + pulse * 0.4;
        canvasCtx.lineWidth = borderThickness / 3;
        canvasCtx.strokeRect(borderThickness * 1.5, topY + borderThickness, w - borderThickness * 3, h - topY - borderThickness * 2);
        canvasCtx.globalAlpha = 1.0;
      }

      if (currentStatus.state !== 'NOT_DETECTED') {
        canvasCtx.textAlign = 'left';
        canvasCtx.textBaseline = 'middle';

        const startX = centerX - totalWidth / 2 + padding;
        const textY = topY;

        // Ensure clear drawing with no alpha artifacts from pulse logic
        canvasCtx.globalAlpha = 1.0;

        // Draw Message Text (Standard Brightness)
        canvasCtx.fillStyle = mainColor;
        canvasCtx.fillText(message, startX, textY);

        // Draw Icon Second (Ultra Dark/Deep Color)
        canvasCtx.fillStyle = iconColor;
        canvasCtx.fillText(icon, startX + textMetrics.width + spacing, textY);
      }

      canvasCtx.restore();
      if (isLoading) setIsLoading(false);
    });

    const startCamera = async () => {
      if (cameraInstanceRef.current) await cameraInstanceRef.current.stop();
      try {
        const CameraClass = (CameraModule as any).Camera || (CameraModule as any).default?.Camera;
        cameraInstanceRef.current = new CameraClass(videoRef.current!, {
          onFrame: async () => { if (videoRef.current) await holistic.send({ image: videoRef.current }); },
          width: 1280, height: 720,
          facingMode: facingMode
        });
        await cameraInstanceRef.current.start();
      } catch (err) {
        setError("Camera Access Denied");
        setIsLoading(false);
      }
    };

    startCamera();
    return () => { 
      cameraInstanceRef.current?.stop(); 
      holistic.close(); 
    };
  }, [config, facingMode, prediction]);

  return (
    <div className="relative w-full h-full bg-black overflow-hidden">
      {isLoading && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-950">
          <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4" />
          <p className="text-indigo-400 font-bold tracking-widest text-[10px] uppercase animate-pulse">Initializing Engine...</p>
        </div>
      )}

      {error && (
        <div className="absolute inset-0 z-30 flex flex-col items-center justify-center bg-slate-950 text-white p-10 text-center">
          <AlertCircle className="w-12 h-12 text-red-500 mb-4" />
          <h2 className="text-xl font-black uppercase mb-2">Hardware Error</h2>
          <p className="text-slate-400 text-sm">{error}</p>
        </div>
      )}

      <video ref={videoRef} className="hidden" playsInline muted />
      <canvas ref={canvasRef} className="w-full h-full object-cover" width={1280} height={720} />

      {!isLoading && viewportStatus.state === 'NOT_DETECTED' && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none bg-slate-950/60 backdrop-blur-sm transition-all duration-700">
           <div className="text-center">
              <UserX className="w-16 h-16 text-slate-700 mx-auto mb-4" />
              <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.4em]">Searching for Signer</p>
           </div>
        </div>
      )}
    </div>
  );
};

export default HolisticCamera;

