import React, { useEffect, useRef, useState } from 'react';
import * as HolisticModule from '@mediapipe/holistic';
import * as CameraModule from '@mediapipe/camera_utils';
import * as DrawingModule from '@mediapipe/drawing_utils';
import { UserX, AlertCircle } from 'lucide-react';
import { HolisticResults, AppConfig, ViewportStatus, PredictionResult } from '../types';

interface HolisticCameraProps {
  config: AppConfig;
  facingMode: 'user' | 'environment';
  prediction: PredictionResult | null;
  isAnalyzing: boolean;
  onViewportStatusChange: (status: ViewportStatus) => void;
  onResults: (results: HolisticResults, filteredPoints: number[]) => void;
  onSequenceComplete: (sequence: number[][]) => void;
  onFpsUpdate: (fps: number) => void;
}

const HolisticCamera: React.FC<HolisticCameraProps> = ({ 
  config, facingMode, prediction, isAnalyzing, 
  onViewportStatusChange, onResults, onSequenceComplete, onFpsUpdate 
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [viewportStatus, setViewportStatus] = useState<ViewportStatus>({ state: 'NOT_DETECTED', instruction: 'Detecting...' });

  // Recognition Buffer
  const sequenceBuffer = useRef<number[][]>([]);
  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);
  const cameraInstanceRef = useRef<any>(null);

  const filterPoints = (landmarks: any[] | undefined, filter: "ALL" | "NONE" | number[]): any[] => {
    if (!landmarks || filter === "NONE") return [];
    if (filter === "ALL") return landmarks;
    return filter.map(idx => landmarks[idx]).filter(p => !!p);
  };

  const checkViewportLogic = (poseLandmarks: any[] | undefined): ViewportStatus => {
    if (!poseLandmarks || poseLandmarks.length === 0) return { state: 'NOT_DETECTED', instruction: 'User Not Found' };
    const nose = poseLandmarks[0];
    const lS = poseLandmarks[11];
    const rS = poseLandmarks[12];
    if (!nose || !lS || !rS) return { state: 'NOT_DETECTED', instruction: 'Show Upper Body' };

    const shoulderCenterX = (lS.x + rS.x) / 2;
    if (shoulderCenterX < 0.25) return { state: 'MOVE_RIGHT', instruction: 'ADJUST RIGHT' };
    if (shoulderCenterX > 0.75) return { state: 'MOVE_LEFT', instruction: 'ADJUST LEFT' };

    const shoulderWidth = Math.abs(lS.x - rS.x);
    if (shoulderWidth > 0.85) return { state: 'TOO_CLOSE', instruction: 'MOVE BACK' };
    if (shoulderWidth < 0.15) return { state: 'TOO_FAR', instruction: 'MOVE CLOSER' };

    if (nose.y < 0.02) return { state: 'TOO_CLOSE', instruction: 'POSITION LOWER' };
    if (nose.y > 0.65) return { state: 'TOO_FAR', instruction: 'POSITION HIGHER' };

    return { state: isAnalyzing ? 'ANALYZING' : 'READY', instruction: isAnalyzing ? 'ANALYZING' : 'READY' };
  };

  useEffect(() => {
    let active = true; // Guard flag to prevent calling deleted holistic instance
    if (!videoRef.current || !canvasRef.current) return;

    const HolisticClass = (HolisticModule as any).Holistic || (HolisticModule as any).default?.Holistic;
    const POSE_CONNECTIONS = (HolisticModule as any).POSE_CONNECTIONS || (HolisticModule as any).default?.POSE_CONNECTIONS;
    const HAND_CONNECTIONS = (HolisticModule as any).HAND_CONNECTIONS || (HolisticModule as any).default?.HAND_CONNECTIONS;
    const drawConnectors = (DrawingModule as any).drawConnectors || (DrawingModule as any).default?.drawConnectors;
    const drawLandmarks = (DrawingModule as any).drawLandmarks || (DrawingModule as any).default?.drawLandmarks;

    const holistic = new HolisticClass({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`,
    });

    const currentProfile = config.keypoints_config.profiles[config.model_config.profile];

    holistic.setOptions({
      modelComplexity: 1,
      smoothLandmarks: true,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
      refineFaceLandmarks: false,
    });

    holistic.onResults((results: any) => {
      if (!active) return; // Prevent processing results if instance is being disposed

      const currentStatus = checkViewportLogic(results.poseLandmarks);
      if (currentStatus.state !== viewportStatus.state) {
        setViewportStatus(currentStatus);
        onViewportStatusChange(currentStatus);
      }

      const frameData: number[] = [];
      config.keypoints_config.flattening_order.forEach(key => {
        let raw, filter;
        if (key === "pose") { raw = results.poseLandmarks; filter = currentProfile.pose_indices; }
        else if (key === "leftHand") { raw = results.leftHandLandmarks; filter = currentProfile.leftHand_indices; }
        else if (key === "rightHand") { raw = results.rightHandLandmarks; filter = currentProfile.rightHand_indices; }

        filterPoints(raw, filter as any).forEach(p => frameData.push(p.x, p.y, p.z || 0));
      });

      // Buffer Logic
      if (currentStatus.state === 'READY' && !isAnalyzing) {
        sequenceBuffer.current.push(frameData);
        if (sequenceBuffer.current.length > config.model_config.target_frames) {
          sequenceBuffer.current.shift();
        }

        if (sequenceBuffer.current.length === config.model_config.target_frames) {
          const hasHand = !!results.leftHandLandmarks || !!results.rightHandLandmarks;
          if (hasHand) {
            onSequenceComplete([...sequenceBuffer.current]);
            sequenceBuffer.current = [];
          }
        }
      } else if (currentStatus.state !== 'ANALYZING') {
        sequenceBuffer.current = [];
      }

      onResults(results, frameData);

      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current >= 1000) {
        onFpsUpdate(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0;
        lastTimeRef.current = now;
      }

      const canvasCtx = canvasRef.current?.getContext('2d');
      if (!canvasCtx || !canvasRef.current) return;

      canvasCtx.save();
      canvasCtx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      if (facingMode === 'user') {
        canvasCtx.scale(-1, 1);
        canvasCtx.translate(-canvasRef.current.width, 0);
      }
      canvasCtx.drawImage(results.image, 0, 0, canvasRef.current.width, canvasRef.current.height);

      const drawSet = (pts: any[], conn: any, color: string) => {
        if (!pts) return;
        drawConnectors(canvasCtx, pts, conn, { color, lineWidth: config.visual_config.drawing.connector_line_width });
        drawLandmarks(canvasCtx, pts, { color, lineWidth: config.visual_config.drawing.line_width, radius: config.visual_config.drawing.landmark_radius });
      };

      drawSet(results.poseLandmarks, POSE_CONNECTIONS, config.visual_config.colors.pose);
      drawSet(results.leftHandLandmarks, HAND_CONNECTIONS, config.visual_config.colors.hands);
      drawSet(results.rightHandLandmarks, HAND_CONNECTIONS, config.visual_config.colors.hands);

      canvasCtx.restore();
      canvasCtx.save();

      const w = canvasRef.current.width;
      const h = canvasRef.current.height;
      const borderThickness = 12;
      const statusColor = isAnalyzing ? config.visual_config.colors.analyzing : (currentStatus.state === 'READY' ? config.visual_config.colors.ready : config.visual_config.colors.error);
      const iconColor = isAnalyzing ? '#1e3a8a' : (currentStatus.state === 'READY' ? '#052e16' : '#450a0a');
      const icon = isAnalyzing ? 'Ōīø' : (currentStatus.state === 'READY' ? '­¤æŹ' : '­¤æÄ');
      const message = currentStatus.instruction.toUpperCase();

      canvasCtx.font = 'bold 36px sans-serif';
      const textMetrics = canvasCtx.measureText(message);
      const iconMetrics = canvasCtx.measureText(icon);
      const totalWidth = textMetrics.width + iconMetrics.width + 60;
      const centerX = w / 2;
      const topY = 55;

      canvasCtx.lineWidth = borderThickness;
      canvasCtx.strokeStyle = statusColor + '88';
      canvasCtx.beginPath();
      canvasCtx.moveTo(centerX + totalWidth/2, topY);
      canvasCtx.lineTo(w - borderThickness/2, topY);
      canvasCtx.lineTo(w - borderThickness/2, h - borderThickness/2);
      canvasCtx.lineTo(borderThickness/2, h - borderThickness/2);
      canvasCtx.lineTo(borderThickness/2, topY);
      canvasCtx.lineTo(centerX - totalWidth/2, topY);
      canvasCtx.stroke();

      if (currentStatus.state === 'READY' && !isAnalyzing) {
        const progress = sequenceBuffer.current.length / config.model_config.target_frames;
        canvasCtx.lineWidth = borderThickness / 2;
        canvasCtx.strokeStyle = config.visual_config.colors.ready;
        const perimeter = (w + h) * 2;
        canvasCtx.setLineDash([perimeter * progress, perimeter * (1 - progress)]);
        canvasCtx.strokeRect(borderThickness * 1.5, topY + borderThickness, w - borderThickness * 3, h - topY - borderThickness * 2);
      }

      if (currentStatus.state !== 'NOT_DETECTED') {
        canvasCtx.textAlign = 'left';
        canvasCtx.textBaseline = 'middle';
        const startX = centerX - totalWidth/2 + 30;
        canvasCtx.fillStyle = statusColor;
        canvasCtx.fillText(message, startX, topY);
        canvasCtx.fillStyle = iconColor;
        canvasCtx.fillText(icon, startX + textMetrics.width + 15, topY);
      }

      canvasCtx.restore();
      if (isLoading) setIsLoading(false);
    });

    const startCamera = async () => {
      if (cameraInstanceRef.current) await cameraInstanceRef.current.stop();
      const CameraClass = (CameraModule as any).Camera || (CameraModule as any).default?.Camera;
      cameraInstanceRef.current = new CameraClass(videoRef.current!, {
        onFrame: async () => { 
          if (videoRef.current && active) {
            try {
              await holistic.send({ image: videoRef.current }); 
            } catch (e) {
              console.warn("Holistic send failed, engine may be closing", e);
            }
          }
        },
        width: 1280, height: 720,
        facingMode
      });
      cameraInstanceRef.current.start().catch(() => setError("Camera Access Denied"));
    };

    startCamera();

    return () => { 
      active = false;
      // Order is important: stop camera before closing holistic
      if (cameraInstanceRef.current) {
        cameraInstanceRef.current.stop();
      }
      holistic.close(); 
    };
  }, [config, facingMode, isAnalyzing]);

  return (
    <div className="relative w-full h-full bg-black overflow-hidden">
      {isLoading && <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-950"><div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"/><p className="text-indigo-400 font-bold uppercase tracking-widest text-[10px]">Initializing AI...</p></div>}
      {error && <div className="absolute inset-0 z-30 flex flex-col items-center justify-center bg-slate-950 text-white"><AlertCircle className="w-12 h-12 text-red-500 mb-4"/><h2 className="text-xl font-black uppercase">{error}</h2></div>}
      <video ref={videoRef} className="hidden" playsInline muted />
      <canvas ref={canvasRef} className="w-full h-full object-cover" width={1280} height={720} />
      {!isLoading && viewportStatus.state === 'NOT_DETECTED' && <div className="absolute inset-0 flex items-center justify-center bg-slate-950/60 backdrop-blur-sm"><div className="text-center"><UserX className="w-16 h-16 text-slate-700 mx-auto mb-4"/><p className="text-slate-500 text-xs font-bold uppercase tracking-[0.4em]">Searching for Signer</p></div></div>}
    </div>
  );
};

