import * as ort from 'onnxruntime-web';
import { GoogleGenAI } from "@google/genai";
import { PredictionResult, AppConfig } from "../types";

export class SignEngine {
  private ai: GoogleGenAI;
  private session: ort.InferenceSession | null = null;
  private isModelLoaded = false;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: (process.env as any).API_KEY });
    this.initLocalModel();
  }

  private async initLocalModel() {
    try {
      // Assuming model is at /models/model.onnx
      this.session = await ort.InferenceSession.create('./models/model.onnx', {
        executionProviders: ['wasm'],
        graphOptimizationLevel: 'all'
      });
      this.isModelLoaded = true;
      console.log("Local ONNX model loaded successfully.");
    } catch (e) {
      console.warn("Failed to load local ONNX model, falling back to Gemini reasoning.", e);
    }
  }

  private softmax(arr: number[]): number[] {
    const maxLogit = Math.max(...arr);
    const exps = arr.map(x => Math.exp(x - maxLogit));
    const sumExps = exps.reduce((a, b) => a + b, 0);
    return exps.map(x => x / sumExps);
  }

  async predict(sequence: number[][], config: AppConfig): Promise<PredictionResult | null> {
    // 1. Try Local Inference First
    if (this.isModelLoaded && this.session) {
      try {
        // Flatten 64x225 sequence to Float32Array
        const flattened = new Float32Array(config.model_config.target_frames * 225);
        sequence.forEach((frame, i) => {
          flattened.set(frame, i * 225);
        });

        const tensor = new ort.Tensor('float32', flattened, [1, 64, 225]);
        const feeds: Record<string, ort.Tensor> = {};
        feeds[this.session.inputNames[0]] = tensor;

        const results = await this.session.run(feeds);
        const output = results[this.session.outputNames[0]].data as Float32Array;
        const probs = this.softmax(Array.from(output));

        const maxProb = Math.max(...probs);
        const labelIdx = probs.indexOf(maxProb);

        if (maxProb >= config.inference_logic.confidence_threshold) {
          return {
            word: config.model_config.labels[labelIdx] || "Unknown",
            confidence: maxProb
          };
        }
      } catch (err) {
        console.error("Local inference failed:", err);
      }
    }

    // 2. Fallback to Gemini Cloud Inference
    return this.predictCloud(sequence, config);
  }

  private async predictCloud(sequence: number[][], config: AppConfig): Promise<PredictionResult | null> {
    try {
      const step = Math.max(1, Math.floor(sequence.length / 16));
      const subsampled = sequence.filter((_, i) => i % step === 0).slice(0, 16);

      const prompt = `
        Analyze this sign language landmark sequence (16 frames, 75 pts each).
        The data is normalized [x,y,z].

        Potential signs: ${config.model_config.labels.join(", ")}.

        Data: ${JSON.stringify(subsampled.map(frame => frame.map(v => v.toFixed(2))))}

        Identify the sign and provide confidence (0-1).
        Return ONLY valid JSON: {"word": "string", "confidence": number}
      `;

      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          temperature: 0.1,
        }
      });

      const result = JSON.parse(response.text || "{}");
      if (result.word && result.confidence >= config.inference_logic.confidence_threshold) {
        return result;
      }
      return null;
    } catch (error) {
      console.error("Cloud Fallback Error:", error);
      return null;
    }
  }

  public getEngineStatus() {
    return this.isModelLoaded ? 'Local (ONNX)' : 'Cloud (Gemini)';
  }
}

export const signEngine = new SignEngine();

import React, { useState, useEffect } from 'react';
