      feeds[this.session.inputNames[0]] = tensor;

      const results = await this.session.run(feeds);
      const output = results[this.session.outputNames[0]].data as Float32Array;
      const probs = this.softmax(Array.from(output));

      const maxProb = Math.max(...probs);
      const labelIdx = probs.indexOf(maxProb);

      if (maxProb >= config.inference_logic.confidence_threshold) {
        return {
          word: config.model_config.labels[labelIdx] || "Unknown Sign",
          confidence: maxProb
        };
      }
    } catch (err) {
      console.error("Inference execution failed:", err);
    }

    return null;
  }

  public getEngineStatus() {
    if (this.isInitializing) return 'INITIALIZING...';
    return this.isModelLoaded ? 'LOCAL (ONNX)' : 'DISCONNECTED';
  }
