    try {
      console.log("SignEngine: Starting model fetch...");

      // We fetch the model manually as an ArrayBuffer.
      // This is much more reliable in browser environments than passing a string path
      // to ort.InferenceSession.create, as it bypasses internal fetch logic bugs.
      const response = await fetch('./models/model.onnx');

      if (!response.ok) {
