ort.env.wasm.wasmPaths = 'https://cdn.jsdelivr.net/npm/onnxruntime-web@1.20.0/dist/';

/**
 * FIX: 't.getValue is not a function' often occurs due to SharedArrayBuffer 
 * requirements not being met in the host environment (missing Cross-Origin-Opener-Policy headers).
 * Forcing numThreads to 1 disables the need for SharedArrayBuffer and multi-threading.
 */
ort.env.wasm.numThreads = 1;

export class SignEngine {
  private session: ort.InferenceSession | null = null;
  private isModelLoaded = false;
  private isInitializing = true;
  private initializationError: string | null = null;

  constructor() {
    this.initLocalModel();
  }

  private async initLocalModel() {
    try {
      console.log("SignEngine: Fetching model binary...");

      const response = await fetch('./models/model.onnx');

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: Failed to fetch models/model.onnx`);
      }

      const modelBuffer = await response.arrayBuffer();

      /**
       * FIX: Convert ArrayBuffer to Uint8Array. 
       * Some environments or versions of ORT prefer a TypedArray over a raw ArrayBuffer 
       * when initializing the session.
       */
      const modelUint8 = new Uint8Array(modelBuffer);

      console.log(`SignEngine: Model binary loaded (${(modelUint8.byteLength / 1024 / 1024).toFixed(2)} MB)`);

      // Initialize session with forced WASM and single thread
      this.session = await ort.InferenceSession.create(modelUint8, {
        executionProviders: ['wasm'],
        graphOptimizationLevel: 'all'
      });

      this.isModelLoaded = true;
      console.log("SignEngine: Local ONNX session ready.");
    } catch (e: any) {
      this.initializationError = e.message || "Session initialization failed";
      console.error("SignEngine Initialization Error:", this.initializationError);
      this.isModelLoaded = false;
    } finally {
      this.isInitializing = false;
    }
  }

  private softmax(arr: number[]): number[] {
    const maxLogit = Math.max(...arr);
    const exps = arr.map(x => Math.exp(x - maxLogit));
    const sumExps = exps.reduce((a, b) => a + b, 0);
    return exps.map(x => x / sumExps);
  }

  async predict(sequence: number[][], config: AppConfig): Promise<PredictionResult | null> {
    if (!this.isModelLoaded || !this.session) {
      return null;
    }

    try {
      const totalFeatures = 225; // 75 landmarks * 3 coords
      const targetFrames = config.model_config.target_frames;

      // Ensure the data is a Float32Array
      const flattened = new Float32Array(targetFrames * totalFeatures);

      for (let i = 0; i < targetFrames; i++) {
        if (sequence[i]) {
          flattened.set(sequence[i], i * totalFeatures);
        }
      }

      const tensor = new ort.Tensor('float32', flattened, [1, targetFrames, totalFeatures]);

      const inputName = this.session.inputNames[0];
      const feeds: Record<string, ort.Tensor> = { [inputName]: tensor };

      const results = await this.session.run(feeds);

      const outputName = this.session.outputNames[0];
      const outputTensor = results[outputName];

      if (!outputTensor || !outputTensor.data) {
        throw new Error("Model returned invalid output tensor");
      }

      const outputData = outputTensor.data as Float32Array;
      const probs = this.softmax(Array.from(outputData));

      const maxProb = Math.max(...probs);
      const labelIdx = probs.indexOf(maxProb);

      if (maxProb >= config.inference_logic.confidence_threshold) {
        return {
          word: config.model_config.labels[labelIdx] || `Sign #${labelIdx}`,
          confidence: maxProb
        };
      }
    } catch (err) {
      console.error("SignEngine: Prediction failed", err);
    }

    return null;
  }

  public getEngineStatus() {
    if (this.isInitializing) return 'BOOTING...';
    if (this.initializationError) return 'ENGINE ERROR';
    return this.isModelLoaded ? 'LOCAL (ONNX READY)' : 'UNLOADED';
  }
}

