import * as ort from 'onnxruntime-web';
import { PredictionResult, AppConfig } from "../types";

// Force specific ONNX Runtime Web configuration BEFORE session creation.
// These settings are critical for preventing the 't.getValue' error which 
// usually occurs when the library tries to use multi-threading/workers 
// in an environment that isn't cross-origin isolated.

// 1. Set paths to exact version matching the library.
ort.env.wasm.wasmPaths = 'https://cdn.jsdelivr.net/npm/onnxruntime-web@1.20.0/dist/';

// 2. Disable multi-threading (prevents SharedArrayBuffer/COOP/COEP requirements).
ort.env.wasm.numThreads = 1;

// 3. Disable WASM Proxy (fixes the 't.getValue' error by running WASM on the main thread).
