  }

  private async initLocalModel() {
    try {
      console.log("SignEngine: Initializing Local WASM Backend...");

      const response = await fetch('./models/model.onnx');
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: Failed to fetch models/model.onnx`);
      }

      const modelBuffer = await response.arrayBuffer();
      const modelUint8 = new Uint8Array(modelBuffer);

      console.log(`SignEngine: Model binary received (${(modelUint8.byteLength / 1024 / 1024).toFixed(2)} MB)`);

      // Initialize session with explicit settings
      this.session = await ort.InferenceSession.create(modelUint8, {
        executionProviders: ['wasm'],
        graphOptimizationLevel: 'all',
        enableCpuMemArena: true,
        enableMemPattern: true
      });

      this.isModelLoaded = true;
      console.log("SignEngine: Local ONNX session successfully initialized.");
    } catch (e: any) {
