import React, { useEffect, useRef, useState, useCallback } from 'react';
import * as HolisticModule from '@mediapipe/holistic';
import * as CameraModule from '@mediapipe/camera_utils';
import * as DrawingModule from '@mediapipe/drawing_utils';
import { Circle } from 'lucide-react';
import { HolisticResults, AppConfig, ViewportStatus, PredictionResult, SessionState } from '../types';

interface HolisticCameraProps {
  config: AppConfig;
  facingMode: 'user' | 'environment';
  prediction: PredictionResult | null;
  isAnalyzing: boolean;
  onViewportStatusChange: (status: ViewportStatus) => void;
  onResults: (results: HolisticResults, filteredPoints: number[]) => void;
  onSequenceComplete: (sequence: number[][]) => void;
  onFpsUpdate: (fps: number) => void;
}

const HolisticCamera: React.FC<HolisticCameraProps> = ({ 
  config, facingMode, prediction, isAnalyzing, 
  onViewportStatusChange, onResults, onSequenceComplete, onFpsUpdate 
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<{ type: string; message: string } | null>(null);
  const [sessionState, setSessionState] = useState<SessionState>('IDLE');

  // Use refs to avoid closure stalls and excessive re-renders during high-freq processing
  const sessionStateRef = useRef<SessionState>('IDLE');
  const lastViewportStateRef = useRef<string>('');
  const sequenceBuffer = useRef<number[][]>([]);
  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);
  const cameraInstanceRef = useRef<any>(null);

  const filterPoints = (landmarks: any[] | undefined, filter: "ALL" | "NONE" | number[]): any[] => {
    if (!landmarks || filter === "NONE") return [];
    if (filter === "ALL") return landmarks;
    return filter.map(idx => landmarks[idx]).filter(p => !!p);
  };

  const checkHandActivity = (results: any): boolean => {
    if (!results.poseLandmarks) return false;
    const lS = results.poseLandmarks[11];
    const rS = results.poseLandmarks[12];
    if (!lS || !rS) return false;

    // A hand is "active" if it is above the chest line (shoulder y + small offset)
    const threshold = Math.min(lS.y, rS.y) + 0.15;
    const leftActive = results.leftHandLandmarks && results.leftHandLandmarks.some((p: any) => p.y < threshold);
    const rightActive = results.rightHandLandmarks && results.rightHandLandmarks.some((p: any) => p.y < threshold);

    return !!(leftActive || rightActive);
  };

  const resampleSequence = (sequence: number[][], target: number): number[][] => {
    if (sequence.length === target) return sequence;
    const resampled: number[][] = [];
    for (let i = 0; i < target; i++) {
      const index = Math.floor((i / (target - 1)) * (sequence.length - 1));
      resampled.push(sequence[index]);
    }
    return resampled;
  };

  const checkViewportLogic = (poseLandmarks: any[] | undefined): ViewportStatus => {
    if (!poseLandmarks || poseLandmarks.length === 0) return { state: 'NOT_DETECTED', instruction: 'User Not Found' };
    const nose = poseLandmarks[0];
    const lS = poseLandmarks[11];
    const rS = poseLandmarks[12];
    if (!nose || !lS || !rS) return { state: 'NOT_DETECTED', instruction: 'Show Upper Body' };

    const shoulderCenterX = (lS.x + rS.x) / 2;
    if (shoulderCenterX < 0.25) return { state: 'MOVE_RIGHT', instruction: 'ADJUST RIGHT' };
    if (shoulderCenterX > 0.75) return { state: 'MOVE_LEFT', instruction: 'ADJUST LEFT' };

    const shoulderWidth = Math.abs(lS.x - rS.x);
    if (shoulderWidth > 0.85) return { state: 'TOO_CLOSE', instruction: 'MOVE BACK' };
    if (shoulderWidth < 0.15) return { state: 'TOO_FAR', instruction: 'MOVE CLOSER' };

    if (sessionStateRef.current === 'RECORDING') return { state: 'RECORDING', instruction: 'RECORDING...' };
    if (isAnalyzing) return { state: 'ANALYZING', instruction: 'ANALYZING...' };

    return { state: 'READY', instruction: 'READY' };
  };

  const initHolistic = () => {
    const HolisticClass = (HolisticModule as any).Holistic || (HolisticModule as any).default?.Holistic;
    const POSE_CONNECTIONS = (HolisticModule as any).POSE_CONNECTIONS || (HolisticModule as any).default?.POSE_CONNECTIONS;
    const HAND_CONNECTIONS = (HolisticModule as any).HAND_CONNECTIONS || (HolisticModule as any).default?.HAND_CONNECTIONS;
    const drawConnectors = (DrawingModule as any).drawConnectors || (DrawingModule as any).default?.drawConnectors;
    const drawLandmarks = (DrawingModule as any).drawLandmarks || (DrawingModule as any).default?.drawLandmarks;

    const holistic = new HolisticClass({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`,
    });

    const currentProfile = config.keypoints_config.profiles[config.model_config.profile];
    holistic.setOptions({
      modelComplexity: 1,
      smoothLandmarks: true,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
      refineFaceLandmarks: false,
    });

    return { holistic, POSE_CONNECTIONS, HAND_CONNECTIONS, drawConnectors, drawLandmarks, currentProfile };
  };

  const startCamera = async (holisticInstance: any, active: { current: boolean }) => {
    try {
      const CameraClass = (CameraModule as any).Camera || (CameraModule as any).default?.Camera;
      cameraInstanceRef.current = new CameraClass(videoRef.current!, {
        onFrame: async () => { 
          if (videoRef.current && active.current) {
            try { await holisticInstance.send({ image: videoRef.current }); } catch (e) {}
          }
        },
        width: 1280,
        height: 720,
        facingMode
      });
      await cameraInstanceRef.current.start();
    } catch (err: any) {
      setError({ type: 'HARDWARE', message: 'Camera access error.' });
      setIsLoading(false);
    }
  };

  useEffect(() => {
    const active = { current: true };
    if (!videoRef.current || !canvasRef.current) return;

    const { holistic, POSE_CONNECTIONS, HAND_CONNECTIONS, drawConnectors, drawLandmarks, currentProfile } = initHolistic();

    holistic.onResults((results: any) => {
      if (!active.current) return;

      // 1. Optimized Viewport Status Change detection
      const viewport = checkViewportLogic(results.poseLandmarks);
      if (viewport.state !== lastViewportStateRef.current) {
          lastViewportStateRef.current = viewport.state;
          onViewportStatusChange(viewport);
      }

      // 2. Feature Extraction
      const frameData: number[] = [];
      config.keypoints_config.flattening_order.forEach(key => {
        let raw, filter;
        if (key === "pose") { raw = results.poseLandmarks; filter = currentProfile.pose_indices; }
        else if (key === "leftHand") { raw = results.leftHandLandmarks; filter = currentProfile.leftHand_indices; }
        else if (key === "rightHand") { raw = results.rightHandLandmarks; filter = currentProfile.rightHand_indices; }
        filterPoints(raw, filter as any).forEach(p => frameData.push(p.x, p.y, p.z || 0));
      });

      // 3. Trigger Logic (optimized to minimize setStates)
      const handsActive = checkHandActivity(results);
      const currentSessionState = sessionStateRef.current;

      if (currentSessionState === 'IDLE' && handsActive && viewport.state === 'READY') {
        sessionStateRef.current = 'RECORDING';
        setSessionState('RECORDING');
        sequenceBuffer.current = [frameData];
      } 
      else if (currentSessionState === 'RECORDING') {
        sequenceBuffer.current.push(frameData);

        if (!handsActive || sequenceBuffer.current.length > 150) {
          const finalSeq = [...sequenceBuffer.current];
          if (finalSeq.length > 15) { 
            sessionStateRef.current = 'ANALYZING';
            setSessionState('ANALYZING');
            onSequenceComplete(resampleSequence(finalSeq, config.model_config.target_frames));

            setTimeout(() => {
                sessionStateRef.current = 'IDLE';
                setSessionState('IDLE');
                sequenceBuffer.current = [];
            }, config.inference_logic.prediction_cooldown_ms);
          } else {
            sessionStateRef.current = 'IDLE';
            setSessionState('IDLE');
            sequenceBuffer.current = [];
          }
        }
      }

      // 4. Pass results to parent (Throttled conceptually by only passing necessary data)
      onResults(results, frameData);

      // 5. FPS Tracking
      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current >= 1000) {
        onFpsUpdate(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0;
        lastTimeRef.current = now;
      }

      // 6. Canvas Drawing (Optimization: No heavy background fill)
      const canvasCtx = canvasRef.current?.getContext('2d');
      if (!canvasCtx || !canvasRef.current) return;

      canvasCtx.save();
      canvasCtx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);

      if (facingMode === 'user') {
        canvasCtx.scale(-1, 1);
        canvasCtx.translate(-canvasRef.current.width, 0);
      }

      canvasCtx.drawImage(results.image, 0, 0, canvasRef.current.width, canvasRef.current.height);

      const drawSet = (pts: any[], conn: any, color: string) => {
        if (!pts) return;
        drawConnectors(canvasCtx, pts, conn, { color, lineWidth: config.visual_config.drawing.connector_line_width });
        drawLandmarks(canvasCtx, pts, { color, lineWidth: config.visual_config.drawing.line_width, radius: config.visual_config.drawing.landmark_radius });
      };

      drawSet(results.poseLandmarks, POSE_CONNECTIONS, config.visual_config.colors.pose);
      drawSet(results.leftHandLandmarks, HAND_CONNECTIONS, config.visual_config.colors.hands);
      drawSet(results.rightHandLandmarks, HAND_CONNECTIONS, config.visual_config.colors.hands);

      canvasCtx.restore();

      if (isLoading) setIsLoading(false);
    });

    startCamera(holistic, active);
    return () => { 
      active.current = false;
      if (cameraInstanceRef.current) cameraInstanceRef.current.stop();
      holistic.close(); 
    };
  }, [config, facingMode]); // Only depend on static-ish config

  return (
    <div className={`relative w-full h-full bg-black overflow-hidden transition-all duration-300 ${sessionState === 'RECORDING' ? 'ring-2 ring-red-500 ring-inset' : ''}`}>
      {isLoading && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-950">
          <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"/>
          <p className="text-indigo-400 font-bold uppercase tracking-widest text-[10px]">Initializing Engine...</p>
        </div>
      )}

      {/* Subtle Recording Indicator */}
      {sessionState === 'RECORDING' && (
          <div className="absolute top-24 left-1/2 -translate-x-1/2 z-30 flex items-center gap-2 bg-slate-900/90 backdrop-blur-md px-4 py-2 rounded-full border border-red-500/30 shadow-2xl">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-red-500"></span>
              </span>
              <span className="text-white text-[10px] font-black uppercase tracking-[0.2em]">Recording Gesture</span>
          </div>
      )}

      {error && (
        <div className="absolute inset-0 z-30 flex flex-col items-center justify-center bg-slate-950/90 backdrop-blur-xl text-white p-8">
          <div className="bg-slate-900 border border-slate-800 p-8 rounded-3xl shadow-2xl max-w-md w-full text-center">
            <h2 className="text-xl font-black uppercase tracking-tight mb-4">Hardware Error</h2>
            <button onClick={() => window.location.reload()} className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white font-bold py-4 rounded-2xl shadow-xl shadow-indigo-600/20">RELOAD</button>
          </div>
        </div>
      )}

      <video ref={videoRef} className="hidden" playsInline muted />
      <canvas ref={canvasRef} className="w-full h-full object-cover" width={1280} height={720} />

      {!isLoading && !error && sessionState === 'IDLE' && (
        <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
            <div className="w-64 h-64 border-2 border-white/5 rounded-full flex items-center justify-center">
                <div className="w-48 h-48 border border-white/5 rounded-full animate-pulse" />
            </div>
        </div>
      )}
    </div>
  );
};

export default HolisticCamera;

