    } catch (e: any) {
      this.initializationError = e.message || "Failed to initialize ONNX Runtime";
      console.error("SignEngine Critical Failure:", this.initializationError);
      this.isModelLoaded = false;
    } finally {
      this.isInitializing = false;
    }
  }

  private softmax(arr: number[]): number[] {
    const maxLogit = Math.max(...arr);
    const exps = arr.map(x => Math.exp(x - maxLogit));
    const sumExps = exps.reduce((a, b) => Math.max(a + b, 0.000001), 0);
    return exps.map(x => x / sumExps);
  }

  async predict(sequence: number[][], config: AppConfig): Promise<PredictionResult | null> {
    if (!this.isModelLoaded || !this.session) return null;

    try {
      const targetFrames = config.model_config.target_frames;
      const landmarkCount = 75; // Pose(33) + LH(21) + RH(21)
      const coordCount = 3;
      const totalFeatures = landmarkCount * coordCount; 

      const flattened = new Float32Array(targetFrames * totalFeatures);
      for (let i = 0; i < targetFrames; i++) {
        if (sequence[i]) {
          flattened.set(sequence[i], i * totalFeatures);
        }
      }

      // Input Shape: [1, 64, 75, 3]
      const tensor = new ort.Tensor('float32', flattened, [1, targetFrames, landmarkCount, coordCount]);
      const inputName = this.session.inputNames[0];
      const feeds: Record<string, ort.Tensor> = { [inputName]: tensor };

      const results = await this.session.run(feeds);
      const outputName = this.session.outputNames[0];
      const outputTensor = results[outputName];

      const outputData = outputTensor.data as Float32Array;
      const probs = this.softmax(Array.from(outputData));

      const maxProb = Math.max(...probs);
      const labelIdx = probs.indexOf(maxProb);
      const label = config.model_config.labels[labelIdx];

      console.log(`75-KP Inference | Prediction: ${label} | Prob: ${maxProb.toFixed(4)}`);

      if (maxProb >= config.inference_logic.confidence_threshold) {
        return {
          word: label || `Unknown (${labelIdx})`,
          confidence: maxProb
        };
      }
    } catch (err) {
      console.error("SignEngine Prediction Loop Error:", err);
    }
    return null;
  }

  public getEngineStatus() {
    if (this.isInitializing) return 'BOOTING...';
    if (this.initializationError) return 'INIT FAILED';
    return this.isModelLoaded ? 'READY (75-KP)' : 'OFFLINE';
  }
}

