  };

  if (!config) return <div className="h-screen bg-slate-950 flex items-center justify-center text-indigo-400 font-black tracking-widest uppercase text-xs">Loading Config...</div>;

  const isNA = prediction?.word === 'NA' || prediction?.word === 'ERROR';

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-950 text-slate-100 font-sans selection:bg-indigo-500/30 overflow-hidden">
      <header className="absolute top-4 inset-x-4 flex items-center justify-between z-30 pointer-events-none">
        <div className="flex items-center gap-3 bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 p-2 pr-4 rounded-2xl pointer-events-auto shadow-2xl">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-600/20"><Zap className="w-5 h-5 text-white" /></div>
          <div>
            <h1 className="text-sm font-black tracking-tighter uppercase italic text-white leading-none">{config.app_settings.app_name}</h1>
            <p className="text-[9px] text-indigo-400 font-bold uppercase tracking-[0.2em]">SignX v{config.app_settings.version}</p>
          </div>
        </div>

        <div className="flex items-center gap-2 pointer-events-auto">
          <button 
            onClick={() => setIsMirrored(!isMirrored)} 
            className={`px-3 py-2 rounded-xl text-[10px] font-black uppercase transition-all border hidden sm:block ${isMirrored ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400' : 'bg-slate-900/80 border-slate-700 text-slate-500'}`}
          >
