                 <p className="text-[10px] font-black uppercase tracking-[0.4em] text-white/60 mb-1">
                    {prediction.word === 'ERROR' ? 'PROCESS ERROR' : (isNA ? "No match detected" : "SIGN DETECTED")}
                 </p>
                 <h2 className="text-6xl font-black tracking-tighter uppercase drop-shadow-2xl text-white">
