          const hasHands = meta.lh > 0 || meta.rh > 0;
          addLog(
            `Frame ${frameIdx + 1}/64: Pose[${meta.pose}] Hands[${hasHands ? 'YES' : 'NO'}] LH:${meta.lh} RH:${meta.rh}`,
            'frame'
          );
        }
      );

