                        </div>
                        <div className="h-2 w-full bg-black/30 rounded-full overflow-hidden">
                            <div className="h-full bg-white transition-all duration-1000 ease-out" style={{ width: `${prediction.confidence * 100}%` }} />
                        </div>
                    </div>
                 )}
                 <button 
                  onClick={() => setPrediction(null)}
                  className="mt-6 text-[8px] font-bold uppercase tracking-widest text-white/40 hover:text-white transition-colors"
                 >
                   Clear & Dismiss
                 </button>
              </div>
            ) : (
              appMode === 'LIVE' && (
                <div className={`px-10 py-4 rounded-full border-2 backdrop-blur-xl transition-all duration-500 shadow-2xl flex items-center gap-3 ${
                    viewportStatus.state === 'READY' 
                        ? 'bg-indigo-500/20 border-indigo-500/50 text-indigo-300' 
                        : (viewportStatus.state === 'RECORDING' 
                            ? 'bg-red-500/20 border-red-500/50 text-red-300 scale-110' 
                            : (viewportStatus.state === 'ANALYZING' || viewportStatus.state === 'PROCESSING_FILE'
                                ? 'bg-blue-500/20 border-blue-500/50 text-blue-300'
                                : 'bg-slate-900/60 border-slate-700/50 text-slate-500'))
                    }`}>
                    {(viewportStatus.state === 'ANALYZING' || viewportStatus.state === 'PROCESSING_FILE') && <RefreshCw className="w-4 h-4 animate-spin" />}
                    <span className="text-xs font-black uppercase tracking-[0.4em]">
                    {viewportStatus.instruction}
                    </span>
                </div>
              )
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

