import React, { useState, useEffect, useRef } from 'react';
import { Zap, RefreshCw, Database, SearchX, Upload, Play, CheckCircle2, Settings, X, Loader2, Video, VideoOff, Terminal, Activity, FileVideo, Trash2 } from 'lucide-react';
