          )}

          {/* Centered Results / Status Banner */}
          <div className="absolute inset-x-0 bottom-12 flex justify-center pointer-events-none px-6 z-40">
            {prediction ? (
              <div className={`flex flex-col items-center justify-center p-8 rounded-[3rem] shadow-2xl border-4 backdrop-blur-3xl max-w-sm w-full text-center animate-in fade-in zoom-in slide-in-from-bottom-12 duration-500 transition-colors pointer-events-auto ${
                isNA ? 'bg-slate-900/90 border-slate-700/50' : 'bg-indigo-600/90 border-white/30'
              }`}>
                 <div className="mb-4">
                    {isNA ? (
                        <div className="p-4 bg-slate-800 rounded-2xl"><SearchX className="w-8 h-8 text-slate-400 mx-auto" /></div>
                    ) : (
                        <div className="bg-white/20 px-4 py-1 rounded-full"><span className="text-[9px] font-black uppercase tracking-[0.3em] text-white">High Confidence Match</span></div>
                    )}
                 </div>
                 <p className="text-[10px] font-black uppercase tracking-[0.5em] text-white/60 mb-1">
                    {prediction.word === 'ERROR' ? 'PROCESS ERROR' : (isNA ? "UNCERTAIN RESULT" : "RECOGNIZED SIGN")}
                 </p>
                 <h2 className="text-6xl font-black tracking-tighter uppercase drop-shadow-2xl text-white">
                    {prediction.word}
                 </h2>
                 {!isNA && (
                    <div className="mt-6 w-full">
                        <div className="flex justify-between items-center mb-2 text-[9px] font-bold text-white/50 uppercase tracking-widest px-2">
                            <span>Engine Reliability</span>
                            <span>{Math.round(prediction.confidence * 100)}%</span>
                        </div>
                        <div className="h-2.5 w-full bg-black/40 rounded-full overflow-hidden border border-white/10">
                            <div className="h-full bg-white transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(255,255,255,0.5)]" style={{ width: `${prediction.confidence * 100}%` }} />
                        </div>
                    </div>
                 )}
                 <button 
                  onClick={() => { setPrediction(null); setUploadedFile(null); }}
                  className="mt-8 text-[10px] font-black uppercase tracking-[0.2em] text-white/40 hover:text-white transition-all flex items-center gap-2 bg-white/5 px-6 py-2 rounded-full hover:bg-white/10"
                 >
                   <RefreshCw className="w-3 h-3" />
                   {appMode === 'UPLOAD' ? 'Reset Interface' : 'Clear Result'}
                 </button>
              </div>
            ) : (
              appMode === 'LIVE' && (
                <div className={`px-10 py-4 rounded-full border-2 backdrop-blur-xl transition-all duration-500 shadow-2xl flex items-center gap-3 ${
                    viewportStatus.state === 'READY' 
                        ? 'bg-indigo-500/20 border-indigo-500/50 text-indigo-300' 
                        : (viewportStatus.state === 'RECORDING' 
                            ? 'bg-red-500/20 border-red-500/50 text-red-300 scale-110' 
                            : (viewportStatus.state === 'ANALYZING' || viewportStatus.state === 'PROCESSING_FILE'
                                ? 'bg-blue-500/20 border-blue-500/50 text-blue-300'
                                : 'bg-slate-900/60 border-slate-700/50 text-slate-500'))
                    }`}>
                    {(viewportStatus.state === 'ANALYZING' || viewportStatus.state === 'PROCESSING_FILE') && <RefreshCw className="w-4 h-4 animate-spin" />}
                    <span className="text-xs font-black uppercase tracking-[0.4em]">
                    {viewportStatus.instruction}
                    </span>
                </div>
              )
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Zap, RefreshCw, Database, SearchX, Upload, Play, CheckCircle2, Settings, X, Loader2, Video, VideoOff, Terminal, Activity, FileVideo, Trash2, BarChart3, Target } from 'lucide-react';
import HolisticCamera from './components/HolisticCamera';
import { signEngine } from './services/SignEngine';
import { videoProcessor } from './services/VideoProcessor';
import { LandmarkStats, AppConfig, ViewportStatus, PredictionResult } from './types';

type AppMode = 'LIVE' | 'UPLOAD';

interface ProcessLog {
  id: number;
  message: string;
  type: 'info' | 'success' | 'warning' | 'frame' | 'result';
}

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig | null>(null);
  const [appMode, setAppMode] = useState<AppMode>('LIVE');
  const [stats, setStats] = useState<LandmarkStats>({
    face: 0, pose: 0, leftHand: 0, rightHand: 0, total: 0, activeFeatures: 0
  });
  const [fps, setFps] = useState<number>(0);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('user');
  const [isMirrored, setIsMirrored] = useState(true);
  const [viewportStatus, setViewportStatus] = useState<ViewportStatus>({ state: 'NOT_DETECTED', instruction: 'Detecting...' });
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [engineStatus, setEngineStatus] = useState<string>('Initializing...');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [uploadProgress, setUploadProgress] = useState<number>(0);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [logs, setLogs] = useState<ProcessLog[]>([]);

  const lastStatsUpdate = useRef<number>(0);
  const logEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetch('./app_config.json')
      .then(r => r.json())
      .then(setConfig);

    const interval = setInterval(() => {
      setEngineStatus(signEngine.getEngineStatus());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  const addLog = (message: string, type: ProcessLog['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-199), { id: Date.now() + Math.random(), message, type }]);
  };

  const handleSequence = async (sequence: number[][]) => {
    if (!config || appMode !== 'LIVE') return;
    setIsAnalyzing(true);
    try {
        const result = await signEngine.predict(sequence, config);
        setPrediction(result || { word: 'NA', confidence: 0 });
        setTimeout(() => setPrediction(null), 5000);
    } catch (e) {
        setPrediction({ word: 'NA', confidence: 0 });
    } finally {
        setIsAnalyzing(false);
    }
  };

  const handleResults = (res: any, filtered: number[]) => {
    const now = Date.now();
    if (now - lastStatsUpdate.current < 250) return;
    lastStatsUpdate.current = now;

    setStats({
      face: res.faceLandmarks?.length || 0,
      pose: res.poseLandmarks?.length || 0,
      leftHand: res.leftHandLandmarks?.length || 0,
      rightHand: res.rightHandLandmarks?.length || 0,
      total: (res.faceLandmarks?.length || 0) + (res.poseLandmarks?.length || 0) + (res.leftHandLandmarks?.length || 0) + (res.rightHandLandmarks?.length || 0),
      activeFeatures: filtered.length
    });
  };

  const onFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setUploadedFile(e.target.files[0]);
      setPrediction(null);
      setLogs([]);
      addLog(`File loaded: ${e.target.files[0].name}`, 'success');
      addLog(`Size: ${(e.target.files[0].size / (1024 * 1024)).toFixed(2)} MB`, 'info');
      addLog(`Click 'Start Engine' to process 64-frame sequence.`, 'info');
    }
  };

  const handleAnalyzeVideo = async () => {
    if (!uploadedFile || !config) return;

    setIsAnalyzing(true);
    setPrediction(null);
    setLogs([]);
    addLog("Initializing High-Precision Batch Processor...", "info");
    addLog("Allocating MediaPipe Holistic thread...", "info");

    try {
      const sequence = await videoProcessor.processVideo(
        uploadedFile, 
        config, 
        (p) => setUploadProgress(p),
        (frameIdx, meta) => {
          const hasHands = meta.lh > 0 || meta.rh > 0;
          addLog(
            `F[${(frameIdx + 1).toString().padStart(2, '0')}/64]: POSE:${meta.pose} | HANDS:${hasHands ? 'YES' : 'NO'} (L:${meta.lh} R:${meta.rh})`,
            'frame'
          );
        }
      );

      addLog("Landmark extraction complete. Running ONNX Session...", "success");
      const result = await signEngine.predict(sequence, config);

      const finalResult = result || { word: 'NA', confidence: 0 };

      addLog("--------------------------------", "info");
      addLog("CLASSIFICATION COMPLETE", "success");
      addLog(`PRIMARY PREDICTION: ${finalResult.word}`, "result");
      addLog(`CONFIDENCE: ${Math.round(finalResult.confidence * 100)}%`, "result");

      if (finalResult.word === 'NA') {
        addLog("ADVICE: Try ensuring the signer is clearly visible in the center of the frame.", "warning");
      } else {
        addLog(`Match successful for label: ${finalResult.word}`, "success");
      }
      addLog("--------------------------------", "info");

      setPrediction(finalResult);

    } catch (err) {
      addLog(`Critical Failure: ${err instanceof Error ? err.message : 'Processing failed'}`, 'warning');
      setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
      setIsAnalyzing(false);
      setUploadProgress(0);
    }
  };

  if (!config) return <div className="h-screen bg-slate-950 flex items-center justify-center text-indigo-400 font-black tracking-widest uppercase text-xs">SignSense BOOTING...</div>;

  const isNA = prediction?.word === 'NA' || prediction?.word === 'ERROR';

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-950 text-slate-100 font-sans selection:bg-indigo-500/30 overflow-hidden">
      <header className="absolute top-4 inset-x-4 flex items-center justify-between z-30 pointer-events-none">
        <div className="flex items-center gap-3 bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 p-2 pr-4 rounded-2xl pointer-events-auto shadow-2xl">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-600/20"><Zap className="w-5 h-5 text-white" /></div>
          <div>
            <h1 className="text-sm font-black tracking-tighter uppercase italic text-white leading-none">{config.app_settings.app_name}</h1>
            <p className="text-[9px] text-indigo-400 font-bold uppercase tracking-[0.2em]">SignX v{config.app_settings.version}</p>
          </div>
        </div>

        <div className="flex items-center gap-2 pointer-events-auto bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 p-1 rounded-2xl shadow-xl">
            <button 
                onClick={() => { setAppMode('LIVE'); setPrediction(null); setLogs([]); }}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${appMode === 'LIVE' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Video className="w-3 h-3" /> Live
            </button>
            <button 
                onClick={() => { setAppMode('UPLOAD'); setPrediction(null); }}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${appMode === 'UPLOAD' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Upload className="w-3 h-3" /> Upload
            </button>
        </div>

        <div className="flex items-center gap-2 pointer-events-auto">
          {appMode === 'LIVE' && (
            <>
              <button 
                onClick={() => setIsMirrored(!isMirrored)} 
                className={`px-3 py-2 rounded-xl text-[10px] font-black uppercase transition-all border hidden sm:block ${isMirrored ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400' : 'bg-slate-900/80 border-slate-700 text-slate-500'}`}
              >
                {isMirrored ? 'Mirrored' : 'Original'}
              </button>
              <button onClick={() => setFacingMode(f => f === 'user' ? 'environment' : 'user')} className="p-3 bg-slate-900/80 hover:bg-slate-800 border border-slate-700/50 rounded-xl transition-all shadow-xl"><RefreshCw className="w-5 h-5 text-indigo-400" /></button>
            </>
          )}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-3 lg:hidden bg-slate-900/80 border border-slate-700/50 rounded-xl"><Settings className="w-5 h-5 text-indigo-400" /></button>
        </div>
      </header>

      <main className="flex-1 relative flex overflow-hidden">
        {/* Sidebar */}
        <div className={`
          fixed lg:relative lg:flex z-50 lg:z-10 w-80 h-full border-r border-slate-800 bg-slate-950/95 lg:bg-slate-900/50 backdrop-blur-xl 
          transition-transform duration-300 ease-in-out
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
        `}>
          <div className="flex flex-col p-6 w-full">
            <div className="flex items-center justify-between mb-8">
                <h2 className="text-xs font-black uppercase tracking-[0.2em] text-slate-500">System Metrics</h2>
                <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-500 hover:text-white"><X className="w-5 h-5"/></button>
            </div>

            <div className="space-y-6">
              <div className="bg-slate-900/60 backdrop-blur-md border border-white/5 p-5 rounded-2xl shadow-2xl">
                  <div className="flex items-center gap-2 mb-4"><Database className="w-3.5 h-3.5 text-indigo-400" /><span className="text-[10px] font-black uppercase tracking-widest text-slate-400">TELEMETRY</span></div>
                  <div className="space-y-4">
                     <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">Engine</span><span className="text-[10px] font-bold text-indigo-300">{engineStatus}</span></div>
                     <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">Input Mode</span><span className="text-[10px] font-bold text-indigo-400">{appMode}</span></div>
                     <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">Tensors</span><span className="text-[10px] font-mono text-indigo-300">64x225</span></div>
                     {appMode === 'LIVE' && <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">Stream FPS</span><span className="text-[10px] font-bold text-indigo-400 font-mono">{fps}</span></div>}
                  </div>
               </div>

               <div className="bg-slate-900/40 p-5 rounded-2xl border border-slate-800/50">
                  <div className="flex items-center gap-2 mb-4"><Activity className="w-3.5 h-3.5 text-slate-500" /><span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Live Load</span></div>
                  <div className="space-y-2">
                    <div className="h-1 w-full bg-slate-800 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-500/50 transition-all duration-300" style={{ width: `${(stats.activeFeatures / 225) * 100}%` }} />
                    </div>
                    <p className="text-[8px] text-slate-600 uppercase font-black">Feature Map Utilization: {stats.activeFeatures}/225 pts</p>
                  </div>
               </div>
            </div>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="flex-1 relative bg-black overflow-hidden z-0">
          {appMode === 'LIVE' ? (
            <HolisticCamera 
              enabled={true}
              config={config}
              facingMode={facingMode}
              isMirrored={isMirrored}
              prediction={prediction}
              isAnalyzing={isAnalyzing}
              onViewportStatusChange={setViewportStatus}
              onSequenceComplete={handleSequence}
              onResults={handleResults}
              onFpsUpdate={setFps}
            />
          ) : (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-950 p-6 sm:p-12 overflow-hidden">
              <div className="w-full h-full max-w-6xl grid grid-cols-1 lg:grid-cols-12 gap-6 animate-in fade-in duration-500">

                {/* Section 1: Uploading & File Controls (Left/Top) */}
                <div className="lg:col-span-5 flex flex-col gap-6 overflow-y-auto custom-scrollbar">
                    {!uploadedFile ? (
                        <label className="block w-full group cursor-pointer h-full">
                            <div className="h-full border-2 border-dashed border-slate-800 group-hover:border-indigo-500 rounded-[3rem] flex flex-col items-center justify-center transition-all bg-slate-900/20 backdrop-blur-3xl hover:bg-slate-900/40 p-8 text-center">
                                <div className="w-24 h-24 bg-indigo-600/10 rounded-[2.5rem] flex items-center justify-center border border-indigo-500/10 mb-6 group-hover:scale-110 transition-transform">
                                    <FileVideo className="w-10 h-10 text-indigo-400" />
                                </div>
                                <h2 className="text-2xl font-black uppercase tracking-tight text-white mb-2">Select Video</h2>
                                <p className="text-slate-500 text-xs font-bold leading-relaxed max-w-xs mx-auto">
                                    Upload MP4/WebM sign language footage for high-precision sequence analysis.
                                </p>
                                <div className="mt-8 px-10 py-4 bg-indigo-600 rounded-full text-white text-[10px] font-black uppercase tracking-widest shadow-2xl shadow-indigo-600/20">
                                    Browse Files
                                </div>
                            </div>
                            <input type="file" accept="video/*" onChange={onFileUpload} className="hidden" />
                        </label>
                    ) : (
                        <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800 p-8 rounded-[3.5rem] flex flex-col h-full">
                            <div className="flex items-center justify-between mb-8">
                                <div className="flex items-center gap-3">
                                    <div className="p-3 bg-green-500/10 rounded-2xl"><CheckCircle2 className="w-5 h-5 text-green-500" /></div>
                                    <h3 className="text-sm font-black uppercase tracking-widest">Video Ready</h3>
                                </div>
                                <button onClick={() => { setUploadedFile(null); setPrediction(null); setLogs([]); }} className="p-3 hover:bg-red-500/10 text-slate-500 hover:text-red-400 transition-colors rounded-xl"><Trash2 className="w-5 h-5"/></button>
                            </div>

                            <div className="flex-1 space-y-6">
                                <div className="p-6 bg-black/40 rounded-3xl border border-slate-800/50">
                                    <p className="text-[10px] text-slate-500 font-black uppercase mb-2 tracking-widest">Selected Footage</p>
                                    <p className="text-lg font-bold text-white truncate mb-1">{uploadedFile.name}</p>
                                    <p className="text-[10px] text-indigo-400 font-mono">{(uploadedFile.size / (1024 * 1024)).toFixed(2)} MB</p>
                                </div>

                                <div className="space-y-4">
                                    <div className="flex items-center gap-4 text-slate-400">
                                        <div className="w-10 h-10 bg-slate-800 rounded-xl flex items-center justify-center"><Activity className="w-5 h-5 text-indigo-500" /></div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] font-black uppercase text-white">Landmark Profile</span>
                                            <span className="text-[9px] text-slate-500 uppercase">64 Temporal Steps</span>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4 text-slate-400">
                                        <div className="w-10 h-10 bg-slate-800 rounded-xl flex items-center justify-center"><Database className="w-5 h-5 text-indigo-500" /></div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] font-black uppercase text-white">Feature Vectors</span>
                                            <span className="text-[9px] text-slate-500 uppercase">225 Coords/Frame</span>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="mt-8 space-y-3">
                                <button 
                                    onClick={handleAnalyzeVideo}
                                    disabled={isAnalyzing}
                                    className="w-full bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-700 text-white font-black uppercase py-6 rounded-[2.5rem] transition-all flex items-center justify-center gap-3 shadow-2xl shadow-indigo-600/30 active:scale-95"
                                >
                                    {isAnalyzing ? <Loader2 className="w-6 h-6 animate-spin" /> : <Play className="w-6 h-6 fill-current" />}
                                    <span>{isAnalyzing ? "Processing..." : "Start Engine"}</span>
                                </button>
                                {prediction && (
                                    <button 
                                        onClick={() => { setUploadedFile(null); setPrediction(null); setLogs([]); }}
                                        className="w-full text-slate-500 hover:text-white text-[10px] font-black uppercase py-2 tracking-widest"
                                    >
                                        New Analysis
                                    </button>
                                )}
                            </div>
                        </div>
                    )}
                </div>

                {/* Section 2: Log Console & Final Result (Right/Bottom) */}
                <div className="lg:col-span-7 flex flex-col gap-6 h-full min-h-0">
                    <div className="flex-1 bg-black/40 border border-slate-800 rounded-[3.5rem] flex flex-col overflow-hidden relative">
                        <div className="flex items-center justify-between p-8 border-b border-slate-800 bg-slate-900/20">
                            <div className="flex items-center gap-3">
                                <Terminal className="w-4 h-4 text-indigo-500" />
                                <span className="text-[10px] font-black uppercase tracking-[0.2em]">Batch Console</span>
                            </div>
                            <div className="flex gap-2">
                                <div className={`w-2 h-2 rounded-full ${isAnalyzing ? 'bg-indigo-500 animate-pulse' : 'bg-slate-700'}`} />
                                <div className={`w-2 h-2 rounded-full ${prediction ? 'bg-green-500' : 'bg-slate-700'}`} />
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto custom-scrollbar p-8 font-mono text-[11px] space-y-2 bg-black/20 selection:bg-indigo-500/20">
                            {logs.length === 0 ? (
                                <div className="h-full flex flex-col items-center justify-center text-slate-700 space-y-4">
                                    <Terminal className="w-12 h-12 opacity-20" />
                                    <p className="uppercase font-black text-[9px] tracking-[0.3em]">Console Offline</p>
                                </div>
                            ) : (
                                <>
                                    {logs.map(log => (
                                        <div key={log.id} className={`leading-relaxed animate-in fade-in slide-in-from-left-2 duration-300 ${
                                            log.type === 'success' ? 'text-green-400 bg-green-500/5 px-2 py-1 rounded-md' : 
                                            log.type === 'result' ? 'text-white text-base font-black border-l-4 border-indigo-500 pl-4 my-4' :
                                            log.type === 'warning' ? 'text-yellow-400 bg-yellow-400/5 px-2 py-1 rounded-md' : 
                                            log.type === 'frame' ? 'text-slate-500' : 
                                            'text-indigo-400'
                                        }`}>
                                            {log.type === 'frame' ? <span className="text-slate-700 mr-2">>>></span> : <span className="mr-2 opacity-50">ŌĆó</span>}
                                            {log.message}
                                        </div>
                                    ))}
                                    <div ref={logEndRef} />
                                </>
                            )}
                        </div>

                        {uploadProgress > 0 && (
                            <div className="absolute inset-0 z-50 bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center p-12">
                                <div className="relative w-48 h-48 mb-8">
                                    <svg className="w-full h-full transform -rotate-90">
                                        <circle cx="96" cy="96" r="80" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-slate-900" />
                                        <circle cx="96" cy="96" r="80" stroke="currentColor" strokeWidth="6" fill="transparent" strokeDasharray={502} strokeDashoffset={502 - (502 * uploadProgress) / 100} className="text-indigo-500 transition-all duration-300 stroke-round shadow-glow" />
                                    </svg>
                                    <div className="absolute inset-0 flex flex-col items-center justify-center">
                                        <span className="text-white font-black text-4xl">{uploadProgress}%</span>
                                        <span className="text-indigo-400/60 text-[8px] font-black uppercase tracking-widest mt-1">Extracted</span>
                                    </div>
                                </div>
                                <p className="text-indigo-300 font-black uppercase tracking-[0.4em] text-[10px] animate-pulse">Extracting Keypoints...</p>
                            </div>
                        )}
                    </div>
                </div>
              </div>
            </div>
          )}

          {/* Centered Results (Live Mode Only) or Banner */}
          {appMode === 'LIVE' && (
            <div className="absolute inset-x-0 bottom-12 flex justify-center pointer-events-none px-6 z-40">
                {prediction ? (
                <div className={`flex flex-col items-center justify-center p-8 rounded-[3rem] shadow-2xl border-4 backdrop-blur-3xl max-w-sm w-full text-center animate-in fade-in zoom-in slide-in-from-bottom-12 duration-500 transition-colors pointer-events-auto ${
                    isNA ? 'bg-slate-900/90 border-slate-700/50' : 'bg-indigo-600/90 border-white/30'
                }`}>
                    <div className="mb-4">
                        {isNA ? (
                            <div className="p-4 bg-slate-800 rounded-2xl"><SearchX className="w-8 h-8 text-slate-400 mx-auto" /></div>
                        ) : (
                            <div className="bg-white/20 px-4 py-1 rounded-full"><span className="text-[9px] font-black uppercase tracking-[0.3em] text-white">Match Found</span></div>
                        )}
                    </div>
                    <p className="text-[10px] font-black uppercase tracking-[0.5em] text-white/60 mb-1">
                        {prediction.word === 'ERROR' ? 'PROCESS ERROR' : (isNA ? "UNCERTAIN RESULT" : "RECOGNIZED SIGN")}
                    </p>
                    <h2 className="text-6xl font-black tracking-tighter uppercase drop-shadow-2xl text-white">
                        {prediction.word}
                    </h2>
                    {!isNA && (
                        <div className="mt-6 w-full">
                            <div className="flex justify-between items-center mb-2 text-[9px] font-bold text-white/50 uppercase tracking-widest px-2">
                                <span>Confidence</span>
                                <span>{Math.round(prediction.confidence * 100)}%</span>
                            </div>
                            <div className="h-2.5 w-full bg-black/40 rounded-full overflow-hidden border border-white/10">
                                <div className="h-full bg-white transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(255,255,255,0.5)]" style={{ width: `${prediction.confidence * 100}%` }} />
                            </div>
                        </div>
                    )}
                    <button 
                    onClick={() => { setPrediction(null); }}
                    className="mt-8 text-[10px] font-black uppercase tracking-[0.2em] text-white/40 hover:text-white transition-all flex items-center gap-2 bg-white/5 px-6 py-2 rounded-full hover:bg-white/10"
                    >
                    <RefreshCw className="w-3 h-3" />
                    Clear Result
                    </button>
                </div>
                ) : (
                    <div className={`px-10 py-4 rounded-full border-2 backdrop-blur-xl transition-all duration-500 shadow-2xl flex items-center gap-3 ${
                        viewportStatus.state === 'READY' 
                            ? 'bg-indigo-500/20 border-indigo-500/50 text-indigo-300' 
                            : (viewportStatus.state === 'RECORDING' 
                                ? 'bg-red-500/20 border-red-500/50 text-red-300 scale-110' 
                                : (viewportStatus.state === 'ANALYZING' || viewportStatus.state === 'PROCESSING_FILE'
                                    ? 'bg-blue-500/20 border-blue-500/50 text-blue-300'
                                    : 'bg-slate-900/60 border-slate-700/50 text-slate-500'))
                        }`}>
                        {(viewportStatus.state === 'ANALYZING' || viewportStatus.state === 'PROCESSING_FILE') && <RefreshCw className="w-4 h-4 animate-spin" />}
                        <span className="text-xs font-black uppercase tracking-[0.4em]">
                        {viewportStatus.instruction}
                        </span>
                    </div>
                )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

