import * as HolisticModule from '@mediapipe/holistic';
import { AppConfig } from '../types';

export interface FrameMetadata {
  pose: number;
  lh: number;
  rh: number;
}

export class VideoProcessor {
  private holistic: any;

  constructor() {
    const HolisticClass = (HolisticModule as any).Holistic || (HolisticModule as any).default?.Holistic;
    this.holistic = new HolisticClass({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`,
    });

    this.holistic.setOptions({
      modelComplexity: 1,
      smoothLandmarks: false,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
    });
  }

  /**
   * Processes a video file and returns a 64x225 sequence.
   * Normalization is critical: Centered on shoulder midpoint and scaled by shoulder width.
   */
  async processVideo(
    file: File, 
    config: AppConfig, 
    onProgress: (p: number) => void,
    onFrameLog?: (frameIdx: number, meta: FrameMetadata) => void
  ): Promise<number[][]> {
    const video = document.createElement('video');
    video.src = URL.createObjectURL(file);
    video.muted = true;
    video.playsInline = true;

    await new Promise((resolve) => {
      video.onloadedmetadata = resolve;
    });

    const targetFrames = config.model_config.target_frames; // 64
    const duration = video.duration;
    const interval = duration / targetFrames;
    const sequence: number[][] = [];

    let resolveFrame: ((result: { data: number[], meta: FrameMetadata }) => void) | null = null;
    this.holistic.onResults((results: any) => {
        const frameData: number[] = [];
        let refX = 0.5;
        let refY = 0.5;
        let shoulderScale = 1.0;

        // Use stable pose landmarks for normalization reference
        if (results.poseLandmarks && results.poseLandmarks[11] && results.poseLandmarks[12]) {
          const lS = results.poseLandmarks[11];
          const rS = results.poseLandmarks[12];
          refX = (lS.x + rS.x) / 2;
          refY = (lS.y + rS.y) / 2;
          // Scale based on shoulder width to handle different distances from camera
          shoulderScale = Math.hypot(rS.x - lS.x, rS.y - lS.y) || 0.1;
        }

        const extract = (pts: any[] | undefined, count: number) => {
          for (let i = 0; i < count; i++) {
            const p = pts ? pts[i] : null;
            if (p) {
              // Standardized relative coordinates
              frameData.push(
                (p.x - refX) / shoulderScale, 
                (p.y - refY) / shoulderScale, 
                (p.z || 0) / shoulderScale
              );
            } else {
              frameData.push(0, 0, 0);
            }
          }
        };

        // Strict order: Pose(33), LH(21), RH(21) = 75 points
        extract(results.poseLandmarks, 33);
        extract(results.leftHandLandmarks, 21);
        extract(results.rightHandLandmarks, 21);

        const meta: FrameMetadata = {
            pose: results.poseLandmarks?.length || 0,
            lh: results.leftHandLandmarks?.length || 0,
            rh: results.rightHandLandmarks?.length || 0
        };

        if (resolveFrame) resolveFrame({ data: frameData, meta });
    });

    for (let i = 0; i < targetFrames; i++) {
      const currentTime = Math.min(i * interval, duration);
      video.currentTime = currentTime;

      await new Promise((resolve) => {
        video.onseeked = resolve;
      });

      const frameResult = await new Promise<{ data: number[], meta: FrameMetadata }>((resolve) => {
        resolveFrame = resolve;
        this.holistic.send({ image: video });
      });

      sequence.push(frameResult.data);
      if (onFrameLog) onFrameLog(i, frameResult.meta);
      onProgress(Math.round(((i + 1) / targetFrames) * 100));
    }

    URL.revokeObjectURL(video.src);
    this.holistic.onResults(() => {}); 
    return sequence;
  }

  public close() {
    this.holistic.close();
  }
}

export const videoProcessor = new VideoProcessor();

import React, { useState, useEffect, useRef } from 'react';
import { Zap, RefreshCw, Database, SearchX, Upload, Play, CheckCircle2, Settings, X, Loader2, Video, VideoOff, Terminal, Activity, FileVideo, Trash2, BarChart3, Target, Info } from 'lucide-react';
import HolisticCamera from './components/HolisticCamera';
import { signEngine } from './services/SignEngine';
import { videoProcessor } from './services/VideoProcessor';
import { LandmarkStats, AppConfig, ViewportStatus, PredictionResult } from './types';

type AppMode = 'LIVE' | 'UPLOAD';

interface ProcessLog {
  id: number;
  message: string;
  type: 'info' | 'success' | 'warning' | 'frame' | 'result' | 'debug';
}

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig | null>(null);
  const [appMode, setAppMode] = useState<AppMode>('LIVE');
  const [stats, setStats] = useState<LandmarkStats>({
    face: 0, pose: 0, leftHand: 0, rightHand: 0, total: 0, activeFeatures: 0
  });
  const [fps, setFps] = useState<number>(0);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('user');
  const [isMirrored, setIsMirrored] = useState(true);
  const [viewportStatus, setViewportStatus] = useState<ViewportStatus>({ state: 'NOT_DETECTED', instruction: 'Detecting...' });
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [engineStatus, setEngineStatus] = useState<string>('Initializing...');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [uploadProgress, setUploadProgress] = useState<number>(0);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [logs, setLogs] = useState<ProcessLog[]>([]);

  const lastStatsUpdate = useRef<number>(0);
  const logEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetch('./app_config.json')
      .then(r => r.json())
      .then(setConfig);

    const interval = setInterval(() => {
      setEngineStatus(signEngine.getEngineStatus());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  const addLog = (message: string, type: ProcessLog['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-250), { id: Date.now() + Math.random(), message, type }]);
  };

  const handleSequence = async (sequence: number[][]) => {
    if (!config || appMode !== 'LIVE') return;
    setIsAnalyzing(true);
    try {
        const response = await signEngine.predict(sequence, config);
        if (response) {
            setPrediction(response.result);
            // In live mode we auto-clear the overlay but the log persists if needed
            setTimeout(() => setPrediction(null), 5000);
        }
    } catch (e) {
        setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
        setIsAnalyzing(false);
    }
  };

  const handleResults = (res: any, filtered: number[]) => {
    const now = Date.now();
    if (now - lastStatsUpdate.current < 250) return;
    lastStatsUpdate.current = now;

    setStats({
      face: res.faceLandmarks?.length || 0,
      pose: res.poseLandmarks?.length || 0,
      leftHand: res.leftHandLandmarks?.length || 0,
      rightHand: res.rightHandLandmarks?.length || 0,
      total: (res.faceLandmarks?.length || 0) + (res.poseLandmarks?.length || 0) + (res.leftHandLandmarks?.length || 0) + (res.rightHandLandmarks?.length || 0),
      activeFeatures: filtered.length
    });
  };

  const onFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setUploadedFile(e.target.files[0]);
      setPrediction(null);
      setLogs([]);
      addLog(`File attached: ${e.target.files[0].name}`, 'success');
      addLog(`Click 'Start Engine' for batch analysis.`, 'info');
    }
  };

  const handleAnalyzeVideo = async () => {
    if (!uploadedFile || !config) return;

    setIsAnalyzing(true);
    setPrediction(null);
    setLogs([]);
    addLog("System: Starting landmark extraction sequence...", "info");

    try {
      const sequence = await videoProcessor.processVideo(
        uploadedFile, 
        config, 
        (p) => setUploadProgress(p),
        (frameIdx, meta) => {
          if (frameIdx % 4 === 0) { // Log every 4th frame to reduce noise but show progress
             addLog(`Extracted Frame ${frameIdx + 1}/64: Pose detected. Hands: ${meta.lh + meta.rh > 0 ? 'YES' : 'NO'}`, 'frame');
          }
        }
      );

      addLog("System: Landmark extraction complete.", "success");
      addLog("System: Initializing ONNX session for sequence inference...", "info");

      const response = await signEngine.predict(sequence, config);

      if (response) {
        const { result, debug } = response;

        addLog("----------------------------------------", "info");
        addLog(`DATA STATS: Mean: ${debug.mean.toFixed(4)} | Min: ${debug.min.toFixed(2)} | Max: ${debug.max.toFixed(2)}`, "debug");
        addLog("TOP 3 PREDICTIONS:", "info");
        debug.top3.forEach((p, i) => {
            addLog(`${i + 1}. ${p.word} (${(p.confidence * 100).toFixed(1)}%)`, p.confidence > 0.3 ? 'success' : 'debug');
        });
        addLog("----------------------------------------", "info");

        if (result?.word === 'NA') {
          addLog("RESULT: Confidence too low for definitive match.", "warning");
          addLog("TIP: Ensure hands are fully visible throughout the sign duration.", "debug");
        } else {
          addLog(`FINAL CLASSIFICATION: ${result?.word}`, "result");
        }

        setPrediction(result);
      }

    } catch (err) {
      addLog(`Critical Error: ${err instanceof Error ? err.message : 'Processing failed'}`, 'warning');
      setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
      setIsAnalyzing(false);
      setUploadProgress(0);
    }
  };

  if (!config) return <div className="h-screen bg-slate-950 flex items-center justify-center text-indigo-400 font-black tracking-widest uppercase text-xs">SignSense BOOTING...</div>;

  const isNA = prediction?.word === 'NA' || prediction?.word === 'ERROR';

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-950 text-slate-100 font-sans selection:bg-indigo-500/30 overflow-hidden">
      <header className="absolute top-4 inset-x-4 flex items-center justify-between z-30 pointer-events-none">
        <div className="flex items-center gap-3 bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 p-2 pr-4 rounded-2xl pointer-events-auto shadow-2xl">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-600/20"><Zap className="w-5 h-5 text-white" /></div>
          <div>
            <h1 className="text-sm font-black tracking-tighter uppercase italic text-white leading-none">{config.app_settings.app_name}</h1>
            <p className="text-[9px] text-indigo-400 font-bold uppercase tracking-[0.2em]">SignX v{config.app_settings.version}</p>
          </div>
        </div>

        <div className="flex items-center gap-2 pointer-events-auto bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 p-1 rounded-2xl shadow-xl">
            <button 
                onClick={() => { setAppMode('LIVE'); setPrediction(null); setLogs([]); }}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${appMode === 'LIVE' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Video className="w-3 h-3" /> Live
            </button>
            <button 
                onClick={() => { setAppMode('UPLOAD'); setPrediction(null); }}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${appMode === 'UPLOAD' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Upload className="w-3 h-3" /> Upload
            </button>
        </div>

        <div className="flex items-center gap-2 pointer-events-auto">
          {appMode === 'LIVE' && (
            <button onClick={() => setFacingMode(f => f === 'user' ? 'environment' : 'user')} className="p-3 bg-slate-900/80 hover:bg-slate-800 border border-slate-700/50 rounded-xl transition-all shadow-xl"><RefreshCw className="w-5 h-5 text-indigo-400" /></button>
          )}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-3 lg:hidden bg-slate-900/80 border border-slate-700/50 rounded-xl"><Settings className="w-5 h-5 text-indigo-400" /></button>
        </div>
      </header>

      <main className="flex-1 relative flex overflow-hidden">
        {/* Sidebar */}
        <div className={`
          fixed lg:relative lg:flex z-50 lg:z-10 w-80 h-full border-r border-slate-800 bg-slate-950/95 lg:bg-slate-900/50 backdrop-blur-xl 
          transition-transform duration-300 ease-in-out
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
        `}>
          <div className="flex flex-col p-6 w-full">
            <div className="flex items-center justify-between mb-8">
                <h2 className="text-xs font-black uppercase tracking-[0.2em] text-slate-500">Diagnostics</h2>
                <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-500 hover:text-white"><X className="w-5 h-5"/></button>
            </div>

            <div className="space-y-6">
              <div className="bg-slate-900/60 backdrop-blur-md border border-white/5 p-5 rounded-2xl shadow-2xl">
                  <div className="flex items-center gap-2 mb-4"><Database className="w-3.5 h-3.5 text-indigo-400" /><span className="text-[10px] font-black uppercase tracking-widest text-slate-400">ENGINE STATUS</span></div>
                  <div className="space-y-4">
                     <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">Status</span><span className="text-[10px] font-bold text-indigo-300">{engineStatus}</span></div>
                     <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">Input Node</span><span className="text-[10px] font-mono text-indigo-300">1x64x75x3</span></div>
                     {appMode === 'LIVE' && <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">FPS</span><span className="text-[10px] font-bold text-indigo-400 font-mono">{fps}</span></div>}
                  </div>
               </div>

               <div className="bg-slate-900/40 p-5 rounded-2xl border border-slate-800/50">
                  <div className="flex items-center gap-2 mb-4"><Activity className="w-3.5 h-3.5 text-slate-500" /><span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Live Telemetry</span></div>
                  <div className="space-y-2">
                    <div className="flex justify-between mb-1"><span className="text-[8px] text-slate-500 uppercase">Pose Points</span><span className="text-[8px] font-bold">{stats.pose}/33</span></div>
                    <div className="h-1 w-full bg-slate-800 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${(stats.pose / 33) * 100}%` }} />
                    </div>
                    <div className="flex justify-between mb-1 mt-2"><span className="text-[8px] text-slate-500 uppercase">Hand Tracking</span><span className="text-[8px] font-bold">{stats.leftHand + stats.rightHand}/42</span></div>
                    <div className="h-1 w-full bg-slate-800 rounded-full overflow-hidden">
                        <div className="h-full bg-green-500 transition-all duration-300" style={{ width: `${((stats.leftHand + stats.rightHand) / 42) * 100}%` }} />
                    </div>
                  </div>
               </div>
            </div>
          </div>
        </div>

        <div className="flex-1 relative bg-black overflow-hidden z-0">
          {appMode === 'LIVE' ? (
            <HolisticCamera 
              enabled={true}
              config={config}
              facingMode={facingMode}
              isMirrored={isMirrored}
              prediction={prediction}
              isAnalyzing={isAnalyzing}
              onViewportStatusChange={setViewportStatus}
              onSequenceComplete={handleSequence}
              onResults={handleResults}
              onFpsUpdate={setFps}
            />
          ) : (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-950 p-6 sm:p-12">
              <div className="w-full h-full max-w-6xl grid grid-cols-1 lg:grid-cols-12 gap-8 animate-in fade-in duration-700">

                {/* Upload Zone */}
