                        <label className="block w-full group cursor-pointer h-full">
                            <div className="h-full border-2 border-dashed border-slate-800 group-hover:border-indigo-500 rounded-[3.5rem] flex flex-col items-center justify-center transition-all bg-slate-900/10 backdrop-blur-3xl hover:bg-slate-900/30 p-12 text-center">
                                <div className="w-24 h-24 bg-indigo-600/5 rounded-3xl flex items-center justify-center border border-indigo-500/10 mb-8 group-hover:scale-105 transition-transform">
                                    <FileVideo className="w-12 h-12 text-indigo-500/50" />
                                </div>
                                <h2 className="text-2xl font-black uppercase tracking-tight text-white mb-3">Load Footage</h2>
                                <p className="text-slate-500 text-sm font-bold leading-relaxed max-w-xs mx-auto mb-10">
                                    Drop a video to begin landmark extraction and sign classification.
                                </p>
                                <div className="px-12 py-5 bg-indigo-600 rounded-2xl text-white text-xs font-black uppercase tracking-widest shadow-2xl shadow-indigo-600/30">
                                    Browse Device
                                </div>
                            </div>
                            <input type="file" accept="video/*" onChange={onFileUpload} className="hidden" />
                        </label>
                    ) : (
                        <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800 p-10 rounded-[4rem] flex flex-col h-full shadow-2xl">
                            <div className="flex items-center justify-between mb-10">
                                <div className="flex items-center gap-4">
                                    <div className="p-4 bg-green-500/10 rounded-2xl"><CheckCircle2 className="w-6 h-6 text-green-500" /></div>
                                    <h3 className="text-base font-black uppercase tracking-widest">Ready</h3>
                                </div>
                                <button onClick={() => { setUploadedFile(null); setPrediction(null); setLogs([]); }} className="p-4 hover:bg-red-500/10 text-slate-500 hover:text-red-400 transition-colors rounded-2xl"><Trash2 className="w-6 h-6"/></button>
                            </div>

                            <div className="flex-1 space-y-8">
                                <div className="p-8 bg-black/40 rounded-[2.5rem] border border-slate-800/50">
                                    <p className="text-[10px] text-slate-600 font-black uppercase mb-3 tracking-widest">Source File</p>
                                    <p className="text-xl font-bold text-white truncate mb-2">{uploadedFile.name}</p>
                                    <p className="text-xs text-indigo-400 font-mono">{(uploadedFile.size / (1024 * 1024)).toFixed(2)} MB ŌĆó MP4</p>
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="p-5 bg-white/5 rounded-3xl border border-white/5">
                                        <Activity className="w-5 h-5 text-indigo-500 mb-3" />
                                        <p className="text-[10px] font-black uppercase text-slate-400">Frames</p>
                                        <p className="text-lg font-bold">64 Sampled</p>
                                    </div>
                                    <div className="p-5 bg-white/5 rounded-3xl border border-white/5">
                                        <Database className="w-5 h-5 text-indigo-500 mb-3" />
                                        <p className="text-[10px] font-black uppercase text-slate-400">Features</p>
                                        <p className="text-lg font-bold">225 Coords</p>
                                    </div>
                                </div>
                            </div>

                            <button 
                                onClick={handleAnalyzeVideo}
                                disabled={isAnalyzing}
                                className="w-full mt-10 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 text-white font-black uppercase py-7 rounded-[2.5rem] transition-all flex items-center justify-center gap-4 shadow-3xl shadow-indigo-600/30 active:scale-[0.98]"
                            >
                                {isAnalyzing ? <Loader2 className="w-6 h-6 animate-spin" /> : <Play className="w-6 h-6 fill-current" />}
                                <span className="text-sm">{isAnalyzing ? "Analyzing Sequence..." : "Start Engine"}</span>
                            </button>
                        </div>
                    )}
                </div>

                {/* Batch Terminal */}
                <div className="lg:col-span-7 flex flex-col h-full min-h-0 bg-black/40 border border-slate-800 rounded-[3.5rem] overflow-hidden relative shadow-inner">
                    <div className="flex items-center justify-between p-8 border-b border-slate-800 bg-slate-900/10">
                        <div className="flex items-center gap-4">
                            <Terminal className="w-5 h-5 text-indigo-500" />
                            <span className="text-xs font-black uppercase tracking-[0.3em] text-slate-400">Processing Console</span>
                        </div>
                        <div className="flex gap-2">
                            <div className={`w-3 h-3 rounded-full ${isAnalyzing ? 'bg-indigo-500 animate-pulse' : 'bg-slate-800'}`} />
                            <div className={`w-3 h-3 rounded-full ${prediction ? 'bg-green-500' : 'bg-slate-800'}`} />
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto custom-scrollbar p-10 font-mono text-[11px] space-y-2 bg-black/30">
                        {logs.length === 0 ? (
                            <div className="h-full flex flex-col items-center justify-center text-slate-800 opacity-40">
                                <Info className="w-16 h-16 mb-4" />
                                <p className="uppercase font-black text-[10px] tracking-[0.5em]">Waiting for stream...</p>
                            </div>
                        ) : (
                            <>
                                {logs.map(log => (
                                    <div key={log.id} className={`leading-relaxed py-0.5 border-l-2 pl-4 animate-in fade-in slide-in-from-left-4 duration-300 ${
                                        log.type === 'success' ? 'text-green-400 border-green-500/50 bg-green-500/5' : 
                                        log.type === 'result' ? 'text-white text-lg font-black border-indigo-500 bg-indigo-500/10 py-4 my-6' :
                                        log.type === 'debug' ? 'text-slate-500 border-slate-700 italic' :
                                        log.type === 'warning' ? 'text-yellow-400 border-yellow-500/50 bg-yellow-400/5' : 
                                        log.type === 'frame' ? 'text-indigo-300/60 border-indigo-500/20' : 
                                        'text-indigo-400 border-indigo-500/30'
                                    }`}>
                                        <span className="opacity-30 mr-3 text-[9px] uppercase tracking-tighter">[{log.type}]</span>
                                        {log.message}
                                    </div>
                                ))}
                                <div ref={logEndRef} />
                            </>
                        )}
                    </div>

                    {uploadProgress > 0 && (
                        <div className="absolute inset-0 z-50 bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center">
                            <div className="relative w-56 h-56 mb-10">
                                <svg className="w-full h-full transform -rotate-90">
                                    <circle cx="112" cy="112" r="90" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-slate-900" />
                                    <circle cx="112" cy="112" r="90" stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={565} strokeDashoffset={565 - (565 * uploadProgress) / 100} className="text-indigo-500 transition-all duration-300 stroke-round shadow-glow" />
                                </svg>
                                <div className="absolute inset-0 flex flex-col items-center justify-center">
                                    <span className="text-white font-black text-5xl">{uploadProgress}%</span>
                                    <span className="text-indigo-400/50 text-[10px] font-black uppercase tracking-widest mt-2">Scanning</span>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
              </div>
            </div>
          )}

          {/* Results Overlay (Live Mode Only) */}
          {appMode === 'LIVE' && prediction && (
            <div className="absolute inset-x-0 bottom-12 flex justify-center pointer-events-none px-6 z-40">
                <div className={`flex flex-col items-center justify-center p-10 rounded-[4rem] shadow-3xl border-4 backdrop-blur-3xl max-w-sm w-full text-center animate-in fade-in zoom-in slide-in-from-bottom-12 duration-500 transition-colors pointer-events-auto ${
                    isNA ? 'bg-slate-900/90 border-slate-700/50' : 'bg-indigo-600/90 border-white/30'
                }`}>
                    <div className="mb-6">
                        {isNA ? (
                            <div className="p-5 bg-slate-800 rounded-3xl"><SearchX className="w-10 h-10 text-slate-500 mx-auto" /></div>
                        ) : (
                            <div className="bg-white/20 px-6 py-2 rounded-full"><span className="text-xs font-black uppercase tracking-widest text-white">RECOGNIZED</span></div>
                        )}
                    </div>
                    <p className="text-[10px] font-black uppercase tracking-[0.6em] text-white/50 mb-2">
                        {prediction.word === 'ERROR' ? 'SYSTEM ERROR' : (isNA ? "NO MATCH" : "IDENTITY FOUND")}
                    </p>
                    <h2 className="text-7xl font-black tracking-tighter uppercase drop-shadow-2xl text-white">
                        {prediction.word}
                    </h2>
                    {!isNA && (
                        <div className="mt-8 w-full">
                            <div className="flex justify-between items-center mb-2 text-[10px] font-black text-white/40 uppercase tracking-widest px-2">
                                <span>Confidence Score</span>
                                <span>{Math.round(prediction.confidence * 100)}%</span>
                            </div>
                            <div className="h-3 w-full bg-black/40 rounded-full overflow-hidden border border-white/10">
                                <div className="h-full bg-white transition-all duration-1000 ease-out shadow-[0_0_20px_rgba(255,255,255,0.6)]" style={{ width: `${prediction.confidence * 100}%` }} />
                            </div>
                        </div>
                    )}
                </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Zap, RefreshCw, Database, SearchX, Upload, Play, CheckCircle2, Settings, X, Loader2, Video, VideoOff, Terminal, Activity, FileVideo, Trash2, BarChart3, Target, Info, Cpu, AlertCircle } from 'lucide-react';
import HolisticCamera from './components/HolisticCamera';
import { signEngine } from './services/SignEngine';
import { videoProcessor } from './services/VideoProcessor';
import { LandmarkStats, AppConfig, ViewportStatus, PredictionResult } from './types';

type AppMode = 'LIVE' | 'UPLOAD';

interface ProcessLog {
  id: number;
  message: string;
  type: 'info' | 'success' | 'warning' | 'frame' | 'result' | 'debug';
}

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig | null>(null);
  const [appMode, setAppMode] = useState<AppMode>('LIVE');
  const [stats, setStats] = useState<LandmarkStats>({
    face: 0, pose: 0, leftHand: 0, rightHand: 0, total: 0, activeFeatures: 0
  });
  const [fps, setFps] = useState<number>(0);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('user');
  const [isMirrored, setIsMirrored] = useState(true);
  const [viewportStatus, setViewportStatus] = useState<ViewportStatus>({ state: 'NOT_DETECTED', instruction: 'Detecting...' });
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [engineStatus, setEngineStatus] = useState<string>('Initializing...');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [uploadProgress, setUploadProgress] = useState<number>(0);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [logs, setLogs] = useState<ProcessLog[]>([]);

  const lastStatsUpdate = useRef<number>(0);
  const logEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetch('./app_config.json')
      .then(r => r.json())
      .then(setConfig);

    const interval = setInterval(() => {
      setEngineStatus(signEngine.getEngineStatus());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  const addLog = (message: string, type: ProcessLog['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-300), { id: Date.now() + Math.random(), message, type }]);
  };

  const handleSequence = async (sequence: number[][]) => {
    if (!config || appMode !== 'LIVE') return;
    setIsAnalyzing(true);
    try {
        const response = await signEngine.predict(sequence, config);
        if (response) {
            setPrediction(response.result);
            setTimeout(() => setPrediction(null), 5000);
        }
    } catch (e) {
        setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
        setIsAnalyzing(false);
    }
  };

  const handleResults = (res: any, filtered: number[]) => {
    const now = Date.now();
    if (now - lastStatsUpdate.current < 250) return;
    lastStatsUpdate.current = now;

    setStats({
      face: res.faceLandmarks?.length || 0,
      pose: res.poseLandmarks?.length || 0,
      leftHand: res.leftHandLandmarks?.length || 0,
      rightHand: res.rightHandLandmarks?.length || 0,
      total: (res.faceLandmarks?.length || 0) + (res.poseLandmarks?.length || 0) + (res.leftHandLandmarks?.length || 0) + (res.rightHandLandmarks?.length || 0),
      activeFeatures: filtered.length
    });
  };

  const onFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setUploadedFile(e.target.files[0]);
      setPrediction(null);
      setLogs([]);
      addLog(`[SYSTEM] New media stream loaded: ${e.target.files[0].name}`, 'success');
      addLog(`[SYSTEM] Memory allocated for 64-frame buffer.`, 'info');
    }
  };

  const handleAnalyzeVideo = async () => {
    if (!uploadedFile || !config) return;

    setIsAnalyzing(true);
    setPrediction(null);
    setLogs([]);
    addLog("--- BATCH INFERENCE START ---", "info");
    addLog("[EXTRACTOR] Initializing MediaPipe pipeline...", "info");

    try {
      const sequence = await videoProcessor.processVideo(
        uploadedFile, 
        config, 
        (p) => setUploadProgress(p),
        (frameIdx, meta) => {
          if (frameIdx % 2 === 0) { 
             addLog(`FRAME_${(frameIdx+1).toString().padStart(2, '0')}: P:${meta.pose} LH:${meta.lh} RH:${meta.rh}`, 'frame');
          }
        }
      );

      addLog("[EXTRACTOR] landmark sequence successfully generated.", "success");
      addLog("[ENGINE] Performing forward pass on ONNX model...", "info");

      const response = await signEngine.predict(sequence, config);

      if (response) {
        const { result, debug } = response;

        addLog("--- INFERENCE METRICS ---", "info");
        addLog(`TENSOR_STATS: Mean=${debug.mean.toFixed(4)} Range=[${debug.min.toFixed(2)}, ${debug.max.toFixed(2)}]`, "debug");
        addLog("PREDICTION LOGITS:", "info");
        debug.top3.forEach((p, i) => {
            const isMatch = p.word === result?.word && result?.word !== 'NA';
            addLog(`RANK_${i+1}: ${p.word.padEnd(15)} | ${(p.confidence * 100).toFixed(2)}%`, isMatch ? 'success' : 'debug');
        });

        if (result?.word === 'NA') {
          addLog("--- VALIDATION FAILED ---", "warning");
          addLog(`Peak probability (${(debug.top3[0].confidence * 100).toFixed(1)}%) is below threshold (${config.inference_logic.confidence_threshold * 100}%).`, "warning");
          addLog("Reason: Sign likely non-canonical or hand visibility too low in sequence.", "debug");
        } else {
          addLog("--- VALIDATION SUCCESS ---", "success");
          addLog(`FINAL CLASSIFIED LABEL: ${result?.word}`, "result");
        }

        setPrediction(result);
      }

    } catch (err) {
      addLog(`[FATAL] Error in processing: ${err instanceof Error ? err.message : 'Unknown'}`, 'warning');
      setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
      setIsAnalyzing(false);
      setUploadProgress(0);
    }
  };

  if (!config) return <div className="h-screen bg-slate-950 flex items-center justify-center text-indigo-400 font-black tracking-widest uppercase text-xs animate-pulse">BOOTING SIGNSENSE...</div>;

  const isNA = prediction?.word === 'NA' || prediction?.word === 'ERROR';

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-950 text-slate-100 font-sans selection:bg-indigo-500/30 overflow-hidden">
      <header className="absolute top-4 inset-x-4 flex items-center justify-between z-50 pointer-events-none">
        <div className="flex items-center gap-3 bg-slate-900/90 backdrop-blur-2xl border border-slate-700/50 p-2 pr-4 rounded-2xl pointer-events-auto shadow-2xl">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-600/30"><Zap className="w-5 h-5 text-white" /></div>
          <div>
            <h1 className="text-sm font-black tracking-tighter uppercase italic text-white leading-none">{config.app_settings.app_name}</h1>
            <p className="text-[9px] text-indigo-400 font-bold uppercase tracking-[0.2em]">SignX v{config.app_settings.version}</p>
          </div>
        </div>

        <div className="flex items-center gap-2 pointer-events-auto bg-slate-900/90 backdrop-blur-2xl border border-slate-700/50 p-1 rounded-2xl shadow-xl">
            <button 
                onClick={() => { setAppMode('LIVE'); setPrediction(null); setLogs([]); }}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase transition-all ${appMode === 'LIVE' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/40' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Video className="w-3.5 h-3.5" /> Live
            </button>
            <button 
                onClick={() => { setAppMode('UPLOAD'); setPrediction(null); }}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase transition-all ${appMode === 'UPLOAD' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/40' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Upload className="w-3.5 h-3.5" /> Batch
            </button>
        </div>

        <div className="flex items-center gap-2 pointer-events-auto">
          {appMode === 'LIVE' && (
            <button onClick={() => setFacingMode(f => f === 'user' ? 'environment' : 'user')} className="p-3 bg-slate-900/90 hover:bg-slate-800 border border-slate-700/50 rounded-xl transition-all shadow-xl"><RefreshCw className="w-5 h-5 text-indigo-400" /></button>
          )}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-3 lg:hidden bg-slate-900/90 border border-slate-700/50 rounded-xl"><Settings className="w-5 h-5 text-indigo-400" /></button>
        </div>
      </header>

      <main className="flex-1 relative flex overflow-hidden pt-20">
        {/* Persistent Sidebar */}
        <div className={`
          fixed lg:relative lg:flex z-40 lg:z-10 w-72 h-full border-r border-slate-800/50 bg-slate-950/95 lg:bg-transparent backdrop-blur-xl 
          transition-transform duration-300 ease-in-out
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
        `}>
          <div className="flex flex-col p-6 w-full space-y-6">
            <div className="flex items-center justify-between">
                <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Node Status</h2>
                <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-500 hover:text-white"><X className="w-5 h-5"/></button>
            </div>

            <div className="bg-slate-900/60 backdrop-blur-md border border-white/5 p-5 rounded-[2rem] shadow-2xl">
                <div className="flex items-center gap-2 mb-4"><Cpu className="w-3.5 h-3.5 text-indigo-400" /><span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Inference Core</span></div>
                <div className="space-y-4">
                    <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">Engine</span><span className="text-[10px] font-bold text-indigo-300">{engineStatus}</span></div>
                    <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">IO Map</span><span className="text-[10px] font-mono text-indigo-300">64x225</span></div>
                    {appMode === 'LIVE' && <div className="flex justify-between items-center"><span className="text-[9px] text-slate-500 uppercase">Input FPS</span><span className="text-[10px] font-bold text-indigo-400 font-mono">{fps}</span></div>}
                </div>
            </div>

            <div className="bg-slate-900/40 p-5 rounded-[2rem] border border-slate-800/30">
                <div className="flex items-center gap-2 mb-4"><Activity className="w-3.5 h-3.5 text-slate-500" /><span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Live Load</span></div>
                <div className="space-y-3">
                <div className="flex justify-between"><span className="text-[8px] text-slate-500 uppercase">Spatial Points</span><span className="text-[8px] font-bold">{stats.pose}/33</span></div>
                <div className="h-1 w-full bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${(stats.pose / 33) * 100}%` }} />
                </div>
                <div className="flex justify-between mt-2"><span className="text-[8px] text-slate-500 uppercase">Temporal Buffer</span><span className="text-[8px] font-bold">100%</span></div>
                <div className="h-1 w-full bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full bg-green-500 transition-all duration-300" style={{ width: '100%' }} />
                </div>
                </div>
            </div>
          </div>
        </div>

        {/* Dynamic Main Workspace */}
        <div className="flex-1 relative bg-black overflow-hidden z-0">
          {appMode === 'LIVE' ? (
            <HolisticCamera 
              enabled={true}
              config={config}
              facingMode={facingMode}
              isMirrored={isMirrored}
              prediction={prediction}
              isAnalyzing={isAnalyzing}
              onViewportStatusChange={setViewportStatus}
              onSequenceComplete={handleSequence}
              onResults={handleResults}
              onFpsUpdate={setFps}
            />
          ) : (
            <div className="absolute inset-0 flex flex-col bg-slate-950 p-6 sm:p-10">
              <div className="w-full h-full flex flex-col lg:grid lg:grid-cols-12 gap-8 animate-in fade-in duration-700 max-w-[1600px] mx-auto overflow-hidden">

                {/* Panel 1: Controls & Preview (Left Side) */}
                <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-y-auto custom-scrollbar pr-1">
                    {!uploadedFile ? (
                        <label className="block w-full group cursor-pointer flex-1">
                            <div className="h-full border-2 border-dashed border-slate-800 group-hover:border-indigo-500 rounded-[3rem] flex flex-col items-center justify-center transition-all bg-slate-900/10 backdrop-blur-3xl hover:bg-slate-900/30 p-12 text-center">
                                <div className="w-24 h-24 bg-indigo-600/5 rounded-[2.5rem] flex items-center justify-center border border-indigo-500/10 mb-8 group-hover:scale-105 transition-transform shadow-2xl">
                                    <FileVideo className="w-10 h-10 text-indigo-400/50" />
                                </div>
                                <h2 className="text-2xl font-black uppercase tracking-tight text-white mb-3">Load Video</h2>
                                <p className="text-slate-500 text-sm font-bold leading-relaxed max-w-xs mx-auto mb-10">
                                    Batch mode allows for high-accuracy analysis of pre-recorded sequences.
                                </p>
                                <div className="px-12 py-5 bg-indigo-600 rounded-2xl text-white text-[11px] font-black uppercase tracking-[0.2em] shadow-2xl shadow-indigo-600/40">
                                    Choose File
                                </div>
                            </div>
                            <input type="file" accept="video/*" onChange={onFileUpload} className="hidden" />
                        </label>
                    ) : (
                        <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800/60 p-10 rounded-[4rem] flex flex-col h-full shadow-2xl">
                            <div className="flex items-center justify-between mb-10">
                                <div className="flex items-center gap-4">
                                    <div className="p-4 bg-green-500/10 rounded-2xl shadow-lg"><CheckCircle2 className="w-6 h-6 text-green-500" /></div>
                                    <h3 className="text-base font-black uppercase tracking-widest text-slate-200">Ready</h3>
                                </div>
                                <button onClick={() => { setUploadedFile(null); setPrediction(null); setLogs([]); }} className="p-4 hover:bg-red-500/10 text-slate-500 hover:text-red-400 transition-colors rounded-2xl"><Trash2 className="w-6 h-6"/></button>
                            </div>

                            <div className="flex-1 space-y-8">
                                <div className="p-8 bg-black/40 rounded-[3rem] border border-slate-800/50 shadow-inner">
                                    <p className="text-[10px] text-slate-600 font-black uppercase mb-3 tracking-widest">Metadata</p>
                                    <p className="text-xl font-bold text-white truncate mb-2">{uploadedFile.name}</p>
                                    <p className="text-xs text-indigo-400 font-mono tracking-tighter">{(uploadedFile.size / (1024 * 1024)).toFixed(2)} MB ŌĆó RAW STREAM</p>
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="p-6 bg-white/5 rounded-[2.5rem] border border-white/5 text-center">
                                        <Activity className="w-6 h-6 text-indigo-500 mx-auto mb-3" />
                                        <p className="text-[10px] font-black uppercase text-slate-500">Target</p>
                                        <p className="text-base font-black text-white">64 FR</p>
                                    </div>
                                    <div className="p-6 bg-white/5 rounded-[2.5rem] border border-white/5 text-center">
                                        <Target className="w-6 h-6 text-indigo-500 mx-auto mb-3" />
                                        <p className="text-[10px] font-black uppercase text-slate-500">Features</p>
                                        <p className="text-base font-black text-white">225 D</p>
                                    </div>
                                </div>
                            </div>

                            <button 
                                onClick={handleAnalyzeVideo}
                                disabled={isAnalyzing}
                                className="w-full mt-10 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 text-white font-black uppercase py-8 rounded-[2.5rem] transition-all flex items-center justify-center gap-4 shadow-3xl shadow-indigo-600/40 active:scale-[0.97]"
                            >
                                {isAnalyzing ? <Loader2 className="w-7 h-7 animate-spin" /> : <Play className="w-7 h-7 fill-current" />}
                                <span className="text-sm tracking-widest">{isAnalyzing ? "Processing..." : "Start Batch Analysis"}</span>
                            </button>
                        </div>
                    )}
                </div>

                {/* Panel 2: Big Batch Terminal (Main Focus) */}
                <div className="lg:col-span-8 flex flex-col h-full bg-black/50 border border-slate-800/80 rounded-[4rem] overflow-hidden relative shadow-2xl">
                    <div className="flex items-center justify-between p-10 border-b border-slate-800/50 bg-slate-900/10">
                        <div className="flex items-center gap-5">
                            <div className="p-3 bg-indigo-500/10 rounded-2xl"><Terminal className="w-6 h-6 text-indigo-400" /></div>
                            <div>
                                <h3 className="text-sm font-black uppercase tracking-[0.3em] text-white">Batch Processing Console</h3>
                                <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">Real-time landmark telemetry</p>
                            </div>
                        </div>
                        <div className="flex items-center gap-4">
                            {isAnalyzing && (
                                <div className="flex items-center gap-2 bg-indigo-500/20 px-4 py-2 rounded-full border border-indigo-500/30">
                                    <div className="w-2 h-2 bg-indigo-500 rounded-full animate-ping" />
                                    <span className="text-[9px] font-black uppercase text-indigo-400 tracking-widest">Active Inference</span>
                                </div>
                            )}
                            <div className={`w-3 h-3 rounded-full shadow-[0_0_10px_rgba(0,0,0,0.5)] ${prediction ? 'bg-green-500' : 'bg-slate-800'}`} />
                        </div>
                    </div>

                    {/* Enhanced Log Feed */}
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-12 font-mono text-[11px] space-y-3 bg-black/20">
                        {logs.length === 0 ? (
                            <div className="h-full flex flex-col items-center justify-center text-slate-800 opacity-30 text-center">
                                <Info className="w-20 h-20 mb-6" />
                                <p className="uppercase font-black text-xs tracking-[0.6em] max-w-xs">Console Idle - Load file to begin</p>
                            </div>
                        ) : (
                            <div className="flex flex-col gap-1.5">
                                {logs.map(log => (
                                    <div key={log.id} className={`group leading-relaxed py-1.5 border-l-4 pl-6 animate-in fade-in slide-in-from-left-6 duration-500 hover:bg-white/5 transition-colors rounded-r-lg ${
                                        log.type === 'success' ? 'text-green-400 border-green-500/60 bg-green-500/5' : 
                                        log.type === 'result' ? 'text-white text-2xl font-black border-indigo-500 bg-indigo-500/20 py-8 my-10 shadow-2xl' :
                                        log.type === 'debug' ? 'text-slate-400 border-slate-700 italic opacity-80' :
                                        log.type === 'warning' ? 'text-yellow-400 border-yellow-500/60 bg-yellow-400/5' : 
                                        log.type === 'frame' ? 'text-indigo-300/40 border-indigo-500/10' : 
                                        'text-indigo-400 border-indigo-500/40'
                                    }`}>
                                        <div className="flex items-center gap-4">
                                            <span className="opacity-20 text-[8px] font-bold uppercase tracking-tighter w-12">{log.type}</span>
                                            <span className="flex-1">{log.message}</span>
                                        </div>
                                    </div>
                                ))}
                                <div ref={logEndRef} className="h-20" />
                            </div>
                        )}
                    </div>

                    {/* Landmark Extraction Overlay */}
                    {uploadProgress > 0 && (
                        <div className="absolute inset-0 z-50 bg-slate-950/90 backdrop-blur-md flex flex-col items-center justify-center p-12">
                            <div className="relative w-64 h-64 mb-12">
                                <svg className="w-full h-full transform -rotate-90 filter drop-shadow-[0_0_20px_rgba(99,102,241,0.3)]">
                                    <circle cx="128" cy="128" r="110" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-slate-900" />
                                    <circle cx="128" cy="128" r="110" stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={691} strokeDashoffset={691 - (691 * uploadProgress) / 100} className="text-indigo-500 transition-all duration-300 stroke-round shadow-glow" />
                                </svg>
                                <div className="absolute inset-0 flex flex-col items-center justify-center">
                                    <span className="text-white font-black text-6xl tracking-tighter">{uploadProgress}%</span>
                                    <span className="text-indigo-400/50 text-[10px] font-black uppercase tracking-[0.3em] mt-3">Sequence Map</span>
                                </div>
                            </div>
                            <div className="flex items-center gap-3 bg-indigo-600/10 px-8 py-3 rounded-full border border-indigo-500/30">
                                <Activity className="w-4 h-4 text-indigo-400 animate-pulse" />
                                <p className="text-indigo-300 font-black uppercase tracking-[0.4em] text-xs">Processing Landmark Tensors</p>
                            </div>
                        </div>
                    )}
                </div>
              </div>
            </div>
          )}

          {/* Real-time Recognition HUD (Live Only) */}
          {appMode === 'LIVE' && prediction && (
            <div className="absolute inset-x-0 bottom-12 flex justify-center pointer-events-none px-6 z-40">
                <div className={`flex flex-col items-center justify-center p-12 rounded-[5rem] shadow-3xl border-4 backdrop-blur-3xl max-w-sm w-full text-center animate-in fade-in zoom-in slide-in-from-bottom-12 duration-500 transition-colors pointer-events-auto ${
                    isNA ? 'bg-slate-900/95 border-slate-700/60' : 'bg-indigo-600/95 border-white/40 shadow-indigo-600/50'
                }`}>
                    <div className="mb-8">
                        {isNA ? (
                            <div className="p-6 bg-slate-800 rounded-[2.5rem] border border-slate-700"><AlertCircle className="w-10 h-10 text-slate-500 mx-auto" /></div>
                        ) : (
                            <div className="bg-white/25 px-8 py-2 rounded-full border border-white/20"><span className="text-xs font-black uppercase tracking-[0.4em] text-white">RECOGNIZED</span></div>
                        )}
                    </div>
                    <p className="text-[10px] font-black uppercase tracking-[0.6em] text-white/50 mb-2">
                        {prediction.word === 'ERROR' ? 'SYSTEM_FAIL' : (isNA ? "LOW_CONFIDENCE" : "SIGN_IDENTIFIED")}
                    </p>
                    <h2 className="text-7xl font-black tracking-tighter uppercase drop-shadow-2xl text-white">
                        {prediction.word}
                    </h2>
                    {!isNA && (
                        <div className="mt-10 w-full px-4">
                            <div className="flex justify-between items-center mb-3 text-[10px] font-black text-white/40 uppercase tracking-widest">
                                <span>Engine Reliability</span>
                                <span>{Math.round(prediction.confidence * 100)}%</span>
                            </div>
                            <div className="h-3 w-full bg-black/50 rounded-full overflow-hidden border border-white/10">
                                <div className="h-full bg-white transition-all duration-1000 ease-out shadow-[0_0_30px_rgba(255,255,255,0.7)]" style={{ width: `${prediction.confidence * 100}%` }} />
                            </div>
                        </div>
                    )}
                </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Zap, RefreshCw, Database, SearchX, Upload, Play, CheckCircle2, Settings, X, Loader2, Video, VideoOff, Terminal, Activity, FileVideo, Trash2, BarChart3, Target, Info, Cpu, AlertCircle, ChevronRight } from 'lucide-react';
import HolisticCamera from './components/HolisticCamera';
import { signEngine } from './services/SignEngine';
import { videoProcessor } from './services/VideoProcessor';
import { LandmarkStats, AppConfig, ViewportStatus, PredictionResult } from './types';

type AppMode = 'LIVE' | 'UPLOAD';

interface ProcessLog {
  id: number;
  message: string;
  type: 'info' | 'success' | 'warning' | 'frame' | 'result' | 'debug';
}

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig | null>(null);
  const [appMode, setAppMode] = useState<AppMode>('LIVE');
  const [stats, setStats] = useState<LandmarkStats>({
    face: 0, pose: 0, leftHand: 0, rightHand: 0, total: 0, activeFeatures: 0
  });
  const [fps, setFps] = useState<number>(0);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('user');
  const [isMirrored, setIsMirrored] = useState(true);
  const [viewportStatus, setViewportStatus] = useState<ViewportStatus>({ state: 'NOT_DETECTED', instruction: 'Detecting...' });
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [engineStatus, setEngineStatus] = useState<string>('Initializing...');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [uploadProgress, setUploadProgress] = useState<number>(0);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [logs, setLogs] = useState<ProcessLog[]>([]);

  const lastStatsUpdate = useRef<number>(0);
  const logEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetch('./app_config.json')
      .then(r => r.json())
      .then(setConfig);

    const interval = setInterval(() => {
      setEngineStatus(signEngine.getEngineStatus());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  const addLog = (message: string, type: ProcessLog['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-300), { id: Date.now() + Math.random(), message, type }]);
  };

  const handleSequence = async (sequence: number[][]) => {
    if (!config || appMode !== 'LIVE') return;
    setIsAnalyzing(true);
    try {
        const response = await signEngine.predict(sequence, config);
        if (response) {
            setPrediction(response.result);
            setTimeout(() => setPrediction(null), 5000);
        }
    } catch (e) {
        setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
        setIsAnalyzing(false);
    }
  };

  const handleResults = (res: any, filtered: number[]) => {
    const now = Date.now();
    if (now - lastStatsUpdate.current < 250) return;
    lastStatsUpdate.current = now;

    setStats({
      face: res.faceLandmarks?.length || 0,
      pose: res.poseLandmarks?.length || 0,
      leftHand: res.leftHandLandmarks?.length || 0,
      rightHand: res.rightHandLandmarks?.length || 0,
      total: (res.faceLandmarks?.length || 0) + (res.poseLandmarks?.length || 0) + (res.leftHandLandmarks?.length || 0) + (res.rightHandLandmarks?.length || 0),
      activeFeatures: filtered.length
    });
  };

  const onFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setUploadedFile(e.target.files[0]);
      setPrediction(null);
      setLogs([]);
      addLog(`[SYSTEM] New media stream loaded: ${e.target.files[0].name}`, 'success');
      addLog(`[SYSTEM] Buffer ready for extraction.`, 'info');
    }
  };

  const handleAnalyzeVideo = async () => {
    if (!uploadedFile || !config) return;

    setIsAnalyzing(true);
    setPrediction(null);
    setLogs([]);
    addLog(">>> INFERENCE START", "info");

    try {
      const sequence = await videoProcessor.processVideo(
        uploadedFile, 
        config, 
        (p) => setUploadProgress(p),
        (frameIdx, meta) => {
          if (frameIdx % 4 === 0) { 
             addLog(`FRM_${frameIdx}: P:${meta.pose} H:${meta.lh + meta.rh}`, 'frame');
          }
        }
      );

      addLog(">>> EXTRACTION SUCCESS", "success");
      const response = await signEngine.predict(sequence, config);

      if (response) {
        const { result, debug } = response;

        addLog(">>> TENSOR ANALYTICS", "debug");
        addLog(`╬╝: ${debug.mean.toFixed(4)} | RNG: [${debug.min.toFixed(1)}, ${debug.max.toFixed(1)}]`, "debug");

        debug.top3.forEach((p, i) => {
            const isMatch = p.word === result?.word && result?.word !== 'NA';
            addLog(`${i+1}. ${p.word} (${(p.confidence * 100).toFixed(1)}%)`, isMatch ? 'success' : 'info');
        });

        if (result?.word === 'NA') {
          addLog(">>> LOW CONFIDENCE WARNING", "warning");
        } else {
          addLog(`>>> FINAL: ${result?.word}`, "result");
        }

        setPrediction(result);
      }

    } catch (err) {
      addLog(`[ERR] ${err instanceof Error ? err.message : 'Processing failed'}`, 'warning');
      setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
      setIsAnalyzing(false);
      setUploadProgress(0);
    }
  };

  if (!config) return <div className="h-screen bg-slate-950 flex items-center justify-center text-indigo-400 font-black tracking-widest uppercase text-xs">BOOTING...</div>;

  const isNA = prediction?.word === 'NA' || prediction?.word === 'ERROR';

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-950 text-slate-100 font-sans selection:bg-indigo-500/30 overflow-hidden">
      <header className="absolute top-4 inset-x-4 flex items-center justify-between z-50 pointer-events-none">
        <div className="flex items-center gap-2 bg-slate-900/90 backdrop-blur-2xl border border-slate-700/50 p-1.5 pr-4 rounded-xl pointer-events-auto shadow-2xl">
          <div className="p-1.5 bg-indigo-600 rounded-lg shadow-lg shadow-indigo-600/30"><Zap className="w-4 h-4 text-white" /></div>
          <div>
            <h1 className="text-xs font-black tracking-tighter uppercase italic text-white leading-none">{config.app_settings.app_name}</h1>
          </div>
        </div>

        <div className="flex items-center gap-1.5 pointer-events-auto bg-slate-900/90 backdrop-blur-2xl border border-slate-700/50 p-1 rounded-xl shadow-xl">
            <button 
                onClick={() => { setAppMode('LIVE'); setPrediction(null); setLogs([]); }}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${appMode === 'LIVE' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/40' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Video className="w-3 h-3" /> Live
            </button>
            <button 
                onClick={() => { setAppMode('UPLOAD'); setPrediction(null); }}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${appMode === 'UPLOAD' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/40' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Upload className="w-3 h-3" /> Upload
            </button>
        </div>

        <div className="flex items-center gap-1.5 pointer-events-auto">
          {appMode === 'LIVE' && (
            <button onClick={() => setFacingMode(f => f === 'user' ? 'environment' : 'user')} className="p-2.5 bg-slate-900/90 hover:bg-slate-800 border border-slate-700/50 rounded-xl transition-all shadow-xl"><RefreshCw className="w-4 h-4 text-indigo-400" /></button>
          )}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2.5 lg:hidden bg-slate-900/90 border border-slate-700/50 rounded-xl"><Settings className="w-4 h-4 text-indigo-400" /></button>
        </div>
      </header>

      <main className="flex-1 relative flex overflow-hidden">
        {/* Compact Sidebar */}
        <div className={`
          fixed lg:relative lg:flex z-40 lg:z-10 w-64 h-full border-r border-slate-800/50 bg-slate-950/95 lg:bg-transparent backdrop-blur-xl 
          transition-transform duration-300 ease-in-out
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
        `}>
          <div className="flex flex-col p-4 w-full space-y-4 pt-20">
            <h2 className="text-[9px] font-black uppercase tracking-widest text-slate-600 ml-2">Diagnostics</h2>

            <div className="bg-slate-900/60 border border-white/5 p-4 rounded-xl shadow-xl">
                <div className="flex items-center gap-2 mb-3"><Cpu className="w-3 h-3 text-indigo-400" /><span className="text-[9px] font-black uppercase tracking-widest text-slate-400">Core</span></div>
                <div className="space-y-2">
                    <div className="flex justify-between items-center"><span className="text-[8px] text-slate-500 uppercase">State</span><span className="text-[9px] font-bold text-indigo-300">{engineStatus}</span></div>
                    <div className="flex justify-between items-center"><span className="text-[8px] text-slate-500 uppercase">Map</span><span className="text-[9px] font-mono text-indigo-300">64x225</span></div>
                </div>
            </div>

            <div className="bg-slate-900/40 p-4 rounded-xl border border-slate-800/30">
                <div className="flex items-center gap-2 mb-3"><Activity className="w-3 h-3 text-slate-500" /><span className="text-[9px] font-black uppercase tracking-widest text-slate-500">Live Load</span></div>
                <div className="space-y-2">
                  <div className="h-1 w-full bg-slate-800 rounded-full overflow-hidden">
                      <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${(stats.pose / 33) * 100}%` }} />
                  </div>
                  <div className="h-1 w-full bg-slate-800 rounded-full overflow-hidden">
                      <div className="h-full bg-green-500 transition-all duration-300" style={{ width: `${((stats.leftHand + stats.rightHand) / 42) * 100}%` }} />
                  </div>
                </div>
            </div>
          </div>
        </div>

        <div className="flex-1 relative bg-black overflow-hidden z-0">
          {appMode === 'LIVE' ? (
            <HolisticCamera 
              enabled={true}
              config={config}
              facingMode={facingMode}
              isMirrored={isMirrored}
              prediction={prediction}
              isAnalyzing={isAnalyzing}
              onViewportStatusChange={setViewportStatus}
              onSequenceComplete={handleSequence}
              onResults={handleResults}
              onFpsUpdate={setFps}
            />
          ) : (
            <div className="absolute inset-0 flex flex-col bg-slate-950 p-4 sm:p-8 pt-20">
              <div className="w-full h-full flex flex-col lg:grid lg:grid-cols-12 gap-6 max-w-[1400px] mx-auto overflow-hidden">

                {/* Compact Upload Area */}
                <div className="lg:col-span-4 flex flex-col gap-4 min-h-0">
                    {!uploadedFile ? (
                        <label className="block w-full group cursor-pointer flex-1">
                            <div className="h-full border-2 border-dashed border-slate-800 group-hover:border-indigo-500 rounded-2xl flex flex-col items-center justify-center transition-all bg-slate-900/10 backdrop-blur-3xl hover:bg-slate-900/30 p-8 text-center">
                                <div className="w-16 h-16 bg-indigo-600/5 rounded-2xl flex items-center justify-center border border-indigo-500/10 mb-6 group-hover:scale-105 transition-transform">
                                    <FileVideo className="w-8 h-8 text-indigo-400/50" />
                                </div>
                                <h2 className="text-lg font-black uppercase tracking-tight text-white mb-2">Upload Sign</h2>
                                <p className="text-slate-600 text-[10px] font-bold leading-relaxed max-w-xs mx-auto mb-8">
                                    Process video sequences for high-precision recognition.
                                </p>
                                <div className="px-8 py-3 bg-indigo-600 rounded-lg text-white text-[10px] font-black uppercase tracking-widest shadow-xl">
                                    Browse Files
                                </div>
                            </div>
                            <input type="file" accept="video/*" onChange={onFileUpload} className="hidden" />
                        </label>
                    ) : (
                        <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800/60 p-6 rounded-2xl flex flex-col h-full shadow-2xl">
                            <div className="flex items-center justify-between mb-6">
                                <h3 className="text-xs font-black uppercase tracking-widest text-slate-400">Source Stream</h3>
                                <button onClick={() => { setUploadedFile(null); setPrediction(null); setLogs([]); }} className="p-2 text-slate-600 hover:text-red-400 transition-colors"><Trash2 className="w-4 h-4"/></button>
                            </div>

                            <div className="flex-1 space-y-4">
                                <div className="p-4 bg-black/40 rounded-xl border border-slate-800/50">
                                    <p className="text-sm font-bold text-white truncate">{uploadedFile.name}</p>
                                    <p className="text-[9px] text-indigo-400 font-mono mt-1">{(uploadedFile.size / (1024 * 1024)).toFixed(2)} MB</p>
                                </div>

                                <div className="grid grid-cols-2 gap-3">
                                    <div className="p-4 bg-white/5 rounded-xl border border-white/5">
                                        <Activity className="w-4 h-4 text-indigo-500 mb-2" />
                                        <p className="text-[8px] font-black uppercase text-slate-500">Buffer</p>
                                        <p className="text-xs font-black text-white">64 FR</p>
                                    </div>
                                    <div className="p-4 bg-white/5 rounded-xl border border-white/5">
                                        <Target className="w-4 h-4 text-indigo-500 mb-2" />
                                        <p className="text-[8px] font-black uppercase text-slate-500">Nodes</p>
                                        <p className="text-xs font-black text-white">225 D</p>
                                    </div>
                                </div>
                            </div>

                            <button 
                                onClick={handleAnalyzeVideo}
                                disabled={isAnalyzing}
                                className="w-full mt-6 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 text-white font-black uppercase py-4 rounded-xl transition-all flex items-center justify-center gap-3 shadow-xl active:scale-[0.98]"
                            >
                                {isAnalyzing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Play className="w-4 h-4 fill-current" />}
                                <span className="text-[10px] tracking-widest">{isAnalyzing ? "Processing..." : "Run Engine"}</span>
                            </button>
                        </div>
                    )}
                </div>

                {/* Compact Terminal Area */}
                <div className="lg:col-span-8 flex flex-col h-full bg-black/50 border border-slate-800/80 rounded-2xl overflow-hidden relative">
                    <div className="flex items-center justify-between p-4 border-b border-slate-800/50 bg-slate-900/10">
                        <div className="flex items-center gap-3">
                            <Terminal className="w-4 h-4 text-indigo-500" />
                            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Terminal Output</span>
                        </div>
                        <div className={`w-2 h-2 rounded-full ${isAnalyzing ? 'bg-indigo-500 animate-pulse' : 'bg-slate-800'}`} />
                    </div>

                    <div className="flex-1 overflow-y-auto custom-scrollbar p-6 font-mono text-[10px] space-y-1.5 bg-black/20">
                        {logs.length === 0 ? (
                            <div className="h-full flex flex-col items-center justify-center text-slate-800 opacity-30">
                                <Info className="w-12 h-12 mb-3" />
                                <p className="uppercase font-black text-[9px] tracking-[0.4em]">Idle</p>
                            </div>
                        ) : (
                            <div className="flex flex-col gap-1">
                                {logs.map(log => (
                                    <div key={log.id} className={`leading-relaxed py-1 border-l-2 pl-3 animate-in fade-in slide-in-from-left-2 duration-300 ${
                                        log.type === 'success' ? 'text-green-400 border-green-500/40 bg-green-500/5' : 
                                        log.type === 'result' ? 'text-white text-base font-black border-indigo-500 bg-indigo-500/10 py-3 my-2 shadow-lg' :
                                        log.type === 'debug' ? 'text-slate-500 border-slate-700 italic' :
                                        log.type === 'warning' ? 'text-yellow-400 border-yellow-500/40 bg-yellow-400/5' : 
                                        log.type === 'frame' ? 'text-slate-600 border-indigo-500/10' : 
                                        'text-indigo-400 border-indigo-500/30'
                                    }`}>
                                        <span className="flex items-center gap-2">
                                            {log.type === 'result' && <ChevronRight className="w-4 h-4 text-indigo-400" />}
                                            {log.message}
                                        </span>
                                    </div>
                                ))}
                                <div ref={logEndRef} className="h-10" />
                            </div>
                        )}
                    </div>

                    {uploadProgress > 0 && (
                        <div className="absolute inset-0 z-50 bg-slate-950/90 backdrop-blur-sm flex flex-col items-center justify-center">
                            <div className="relative w-40 h-40">
                                <svg className="w-full h-full transform -rotate-90">
                                    <circle cx="80" cy="80" r="70" stroke="currentColor" strokeWidth="3" fill="transparent" className="text-slate-900" />
                                    <circle cx="80" cy="80" r="70" stroke="currentColor" strokeWidth="5" fill="transparent" strokeDasharray={440} strokeDashoffset={440 - (440 * uploadProgress) / 100} className="text-indigo-500 transition-all duration-300 stroke-round" />
                                </svg>
                                <div className="absolute inset-0 flex flex-col items-center justify-center">
                                    <span className="text-white font-black text-3xl">{uploadProgress}%</span>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
              </div>
            </div>
          )}

          {/* Unified Sleek Result Label (Compact) */}
          {prediction && (
            <div className="absolute inset-x-0 bottom-8 flex justify-center pointer-events-none px-6 z-40">
                <div className={`flex items-center gap-6 px-8 py-3 rounded-full shadow-2xl border-2 backdrop-blur-xl animate-in fade-in zoom-in slide-in-from-bottom-8 duration-500 pointer-events-auto transition-colors ${
                    isNA ? 'bg-slate-900/95 border-slate-700/60' : 'bg-indigo-600/95 border-white/30 shadow-indigo-600/40'
                }`}>
                    <div className="flex flex-col">
                        <span className="text-[8px] font-black uppercase tracking-[0.4em] text-white/50 leading-none mb-1">
                            {prediction.word === 'ERROR' ? 'SYSTEM_FAIL' : (isNA ? "UNCERTAIN" : "RECOGNIZED")}
                        </span>
                        <h2 className="text-2xl font-black tracking-tight uppercase text-white leading-none">
                            {prediction.word}
                        </h2>
                    </div>

                    {!isNA && (
                        <div className="flex items-center gap-3 border-l border-white/20 pl-6">
                            <div className="flex flex-col">
                                <span className="text-[8px] font-black uppercase text-white/40 tracking-widest mb-1">Confidence</span>
                                <div className="flex items-center gap-2">
                                    <div className="h-1.5 w-16 bg-black/30 rounded-full overflow-hidden">
                                        <div className="h-full bg-white transition-all duration-1000" style={{ width: `${prediction.confidence * 100}%` }} />
                                    </div>
                                    <span className="text-[10px] font-bold text-white">{Math.round(prediction.confidence * 100)}%</span>
                                </div>
                            </div>
                        </div>
                    )}

                    <button 
                        onClick={() => setPrediction(null)}
                        className="ml-4 p-1.5 hover:bg-white/10 rounded-full transition-colors"
                    >
                        <X className="w-3.5 h-3.5 text-white/50" />
                    </button>
                </div>
            </div>
          )}

          {/* Viewport Status Banner (Live Only) */}
          {appMode === 'LIVE' && !prediction && (
              <div className="absolute inset-x-0 bottom-8 flex justify-center pointer-events-none z-40">
                  <div className={`px-8 py-2.5 rounded-full border-2 backdrop-blur-xl transition-all duration-500 shadow-xl flex items-center gap-3 ${
                      viewportStatus.state === 'READY' 
                          ? 'bg-indigo-500/10 border-indigo-500/40 text-indigo-400' 
                          : (viewportStatus.state === 'RECORDING' 
                              ? 'bg-red-500/20 border-red-500/50 text-red-400 scale-105' 
                              : 'bg-slate-900/60 border-slate-800 text-slate-500')
                  }`}>
                      <span className="text-[10px] font-black uppercase tracking-[0.4em]">
                          {viewportStatus.instruction}
                      </span>
                  </div>
              </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Zap, RefreshCw, Database, SearchX, Upload, Play, CheckCircle2, Settings, X, Loader2, Video, Terminal, Activity, FileVideo, Trash2, Cpu, AlertCircle, ChevronRight } from 'lucide-react';
import HolisticCamera from './components/HolisticCamera';
import { signEngine } from './services/SignEngine';
import { videoProcessor } from './services/VideoProcessor';
import { LandmarkStats, AppConfig, ViewportStatus, PredictionResult } from './types';

type AppMode = 'LIVE' | 'UPLOAD';

interface ProcessLog {
  id: number;
  message: string;
  type: 'info' | 'success' | 'warning' | 'frame' | 'result' | 'debug';
}

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig | null>(null);
  const [appMode, setAppMode] = useState<AppMode>('LIVE');
  const [stats, setStats] = useState<LandmarkStats>({
    face: 0, pose: 0, leftHand: 0, rightHand: 0, total: 0, activeFeatures: 0
  });
  const [fps, setFps] = useState<number>(0);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('user');
  const [isMirrored, setIsMirrored] = useState(true);
  const [viewportStatus, setViewportStatus] = useState<ViewportStatus>({ state: 'NOT_DETECTED', instruction: 'Detecting...' });
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [engineStatus, setEngineStatus] = useState<string>('Initializing...');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [uploadProgress, setUploadProgress] = useState<number>(0);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [logs, setLogs] = useState<ProcessLog[]>([]);

  const lastStatsUpdate = useRef<number>(0);
  const logEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetch('./app_config.json')
      .then(r => r.json())
      .then(setConfig);

    const interval = setInterval(() => {
      setEngineStatus(signEngine.getEngineStatus());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  const addLog = (message: string, type: ProcessLog['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-300), { id: Date.now() + Math.random(), message, type }]);
  };

  const handleSequence = async (sequence: number[][]) => {
    if (!config || appMode !== 'LIVE') return;
    setIsAnalyzing(true);
    try {
        const response = await signEngine.predict(sequence, config);
        if (response) {
            setPrediction(response.result);
            setTimeout(() => setPrediction(null), 5000);
        }
    } catch (e) {
        setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
        setIsAnalyzing(false);
    }
  };

  const handleResults = (res: any, filtered: number[]) => {
    const now = Date.now();
    if (now - lastStatsUpdate.current < 250) return;
    lastStatsUpdate.current = now;

    setStats({
      face: res.faceLandmarks?.length || 0,
      pose: res.poseLandmarks?.length || 0,
      leftHand: res.leftHandLandmarks?.length || 0,
      rightHand: res.rightHandLandmarks?.length || 0,
      total: (res.faceLandmarks?.length || 0) + (res.poseLandmarks?.length || 0) + (res.leftHandLandmarks?.length || 0) + (res.rightHandLandmarks?.length || 0),
      activeFeatures: filtered.length
    });
  };

  const onFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setUploadedFile(e.target.files[0]);
      setPrediction(null);
      setLogs([]);
      addLog(`[SYSTEM] Video source updated: ${e.target.files[0].name}`, 'success');
    }
  };

  const handleAnalyzeVideo = async () => {
    if (!uploadedFile || !config) return;

    setIsAnalyzing(true);
    setPrediction(null);
    setLogs([]);
    addLog(">>> INITIALIZING BATCH INFERENCE", "info");

    try {
      const sequence = await videoProcessor.processVideo(
        uploadedFile, 
        config, 
        (p) => setUploadProgress(p),
        (frameIdx, meta) => {
          if (frameIdx % 10 === 0) { 
             addLog(`CHECKPOINT FRM_${frameIdx}: POSE:${meta.pose} HANDS:${meta.lh + meta.rh}`, 'frame');
          }
        }
      );

      addLog(">>> SEQUENCE EXTRACTION COMPLETE", "success");
      const response = await signEngine.predict(sequence, config);

      if (response) {
        const { result, debug } = response;
        addLog(`>>> ENGINE ANALYTICS: Mean=${debug.mean.toFixed(4)} Range=[${debug.min.toFixed(1)}, ${debug.max.toFixed(1)}]`, "debug");

        debug.top3.forEach((p, i) => {
            const isMatch = p.word === result?.word && result?.word !== 'NA';
            addLog(`${i+1}. ${p.word} (${(p.confidence * 100).toFixed(1)}%)`, isMatch ? 'success' : 'info');
        });

        if (result?.word === 'NA') {
          addLog(">>> WARNING: LOW CONFIDENCE MATCH", "warning");
        } else {
          addLog(`>>> FINAL CLASSIFICATION: ${result?.word}`, "result");
        }
        setPrediction(result);
      }
    } catch (err) {
      addLog(`[FATAL] ${err instanceof Error ? err.message : 'Processing failed'}`, 'warning');
      setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
      setIsAnalyzing(false);
      setUploadProgress(0);
    }
  };

  if (!config) return <div className="h-screen bg-slate-950 flex items-center justify-center text-indigo-400 font-black tracking-widest uppercase text-xs">BOOTING...</div>;

  const isNA = prediction?.word === 'NA' || prediction?.word === 'ERROR';

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-950 text-slate-100 font-sans selection:bg-indigo-500/30 overflow-hidden">
      <header className="absolute top-4 inset-x-4 flex items-center justify-between z-50 pointer-events-none">
        <div className="flex items-center gap-2 bg-slate-900/95 backdrop-blur-xl border border-slate-800 p-1.5 pr-4 rounded-xl pointer-events-auto shadow-2xl">
          <div className="p-1.5 bg-indigo-600 rounded-lg shadow-lg"><Zap className="w-4 h-4 text-white" /></div>
          <h1 className="text-[10px] font-black uppercase tracking-widest text-white italic">{config.app_settings.app_name}</h1>
        </div>

        <div className="flex items-center gap-1.5 pointer-events-auto bg-slate-900/95 backdrop-blur-xl border border-slate-800 p-1 rounded-xl shadow-xl">
            <button 
                onClick={() => { setAppMode('LIVE'); setPrediction(null); setLogs([]); }}
                className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all flex items-center gap-2 ${appMode === 'LIVE' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Video className="w-3 h-3" /> Live
            </button>
            <button 
                onClick={() => { setAppMode('UPLOAD'); setPrediction(null); }}
                className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all flex items-center gap-2 ${appMode === 'UPLOAD' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Upload className="w-3 h-3" /> Upload
            </button>
        </div>

        <div className="flex items-center gap-1.5 pointer-events-auto">
          {appMode === 'LIVE' && (
            <button onClick={() => setFacingMode(f => f === 'user' ? 'environment' : 'user')} className="p-2.5 bg-slate-900/95 hover:bg-slate-800 border border-slate-800 rounded-xl transition-all shadow-xl"><RefreshCw className="w-4 h-4 text-indigo-400" /></button>
          )}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2.5 lg:hidden bg-slate-900/95 border border-slate-800 rounded-xl"><Settings className="w-4 h-4 text-indigo-400" /></button>
        </div>
      </header>

      <main className="flex-1 relative flex overflow-hidden">
        {/* Sleek Minimalist Sidebar */}
        <div className={`
          fixed lg:relative lg:flex z-40 lg:z-10 w-60 h-full border-r border-slate-800/50 bg-slate-950/95 lg:bg-transparent backdrop-blur-xl 
          transition-transform duration-300 ease-in-out
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
        `}>
          <div className="flex flex-col p-4 w-full space-y-1 pt-20">
            <h2 className="text-[8px] font-black uppercase tracking-[0.3em] text-slate-600 mb-2 px-2">Diagnostic Stream</h2>

            <div className="flex items-center justify-between px-3 py-2 border-b border-slate-900 hover:bg-white/5 transition-colors">
                <span className="text-[9px] text-slate-500 uppercase font-bold">Engine</span>
                <span className={`text-[9px] font-black px-2 py-0.5 rounded ${engineStatus === 'READY (75-KP)' ? 'text-green-400 bg-green-400/10' : 'text-indigo-400 bg-indigo-400/10'}`}>{engineStatus}</span>
            </div>
            <div className="flex items-center justify-between px-3 py-2 border-b border-slate-900 hover:bg-white/5 transition-colors">
                <span className="text-[9px] text-slate-500 uppercase font-bold">Latency</span>
                <span className="text-[10px] font-mono text-slate-300">{appMode === 'LIVE' ? `${fps} FPS` : 'BATCH'}</span>
            </div>
            <div className="flex items-center justify-between px-3 py-2 border-b border-slate-900 hover:bg-white/5 transition-colors">
                <span className="text-[9px] text-slate-500 uppercase font-bold">Tensor Map</span>
                <span className="text-[10px] font-mono text-slate-300">64x225</span>
            </div>

            <h2 className="text-[8px] font-black uppercase tracking-[0.3em] text-slate-600 mb-2 mt-6 px-2">Landmark Health</h2>
            <div className="px-3 py-2 space-y-3">
              <div className="space-y-1">
                <div className="flex justify-between text-[8px] text-slate-500 uppercase font-bold"><span>Pose</span><span>{stats.pose}/33</span></div>
                <div className="h-1 w-full bg-slate-900 rounded-full overflow-hidden"><div className="h-full bg-indigo-500 transition-all" style={{ width: `${(stats.pose / 33) * 100}%` }} /></div>
              </div>
              <div className="space-y-1">
                <div className="flex justify-between text-[8px] text-slate-500 uppercase font-bold"><span>Hands</span><span>{stats.leftHand + stats.rightHand}/42</span></div>
                <div className="h-1 w-full bg-slate-900 rounded-full overflow-hidden"><div className="h-full bg-green-500 transition-all" style={{ width: `${((stats.leftHand + stats.rightHand) / 42) * 100}%` }} /></div>
              </div>
            </div>
          </div>
        </div>

        <div className="flex-1 relative bg-black overflow-hidden z-0">
          {appMode === 'LIVE' ? (
            <HolisticCamera 
              enabled={true}
              config={config}
              facingMode={facingMode}
              isMirrored={isMirrored}
              prediction={prediction}
              isAnalyzing={isAnalyzing}
              onViewportStatusChange={setViewportStatus}
              onSequenceComplete={handleSequence}
              onResults={handleResults}
              onFpsUpdate={setFps}
            />
          ) : (
            <div className="absolute inset-0 flex flex-col bg-slate-950 p-4 sm:p-6 pt-20 overflow-hidden">
              <div className="w-full h-full flex flex-col lg:grid lg:grid-cols-12 gap-4 max-w-[1500px] mx-auto overflow-hidden">

                {/* Upload Control Sidebar */}
                <div className="lg:col-span-3 flex flex-col gap-4 min-h-0">
                    {!uploadedFile ? (
                        <label className="block w-full group cursor-pointer flex-1">
                            <div className="h-full border border-dashed border-slate-800 group-hover:border-indigo-500 rounded-xl flex flex-col items-center justify-center transition-all bg-slate-900/20 hover:bg-slate-900/40 p-6 text-center">
                                <FileVideo className="w-10 h-10 text-indigo-500/50 mb-4" />
                                <h2 className="text-xs font-black uppercase text-white mb-2">Select Video</h2>
                                <div className="px-6 py-2 bg-indigo-600 rounded-lg text-white text-[9px] font-black uppercase tracking-widest">Browse</div>
                            </div>
                            <input type="file" accept="video/*" onChange={onFileUpload} className="hidden" />
                        </label>
                    ) : (
                        <div className="bg-slate-900/40 border border-slate-800 p-4 rounded-xl flex flex-col h-full">
                            <div className="flex items-center justify-between mb-4 pb-2 border-b border-slate-800">
                                <span className="text-[9px] font-black uppercase text-indigo-400">File Info</span>
                                <button onClick={() => { setUploadedFile(null); setPrediction(null); setLogs([]); }} className="text-slate-600 hover:text-red-400"><Trash2 className="w-3.5 h-3.5"/></button>
                            </div>

                            <div className="flex-1 space-y-3">
                                <div className="p-3 bg-black/40 rounded-lg border border-slate-800/50">
                                    <p className="text-[10px] font-bold text-white truncate">{uploadedFile.name}</p>
                                    <p className="text-[8px] text-slate-500 mt-1 uppercase">{(uploadedFile.size / (1024 * 1024)).toFixed(2)} MB</p>
                                </div>
                                <div className="flex items-center gap-2 text-[9px] font-bold text-slate-500 px-1 uppercase"><Activity className="w-3 h-3" /> 64 Frame Target</div>
                                <div className="flex items-center gap-2 text-[9px] font-bold text-slate-500 px-1 uppercase"><Database className="w-3 h-3" /> Normalized Input</div>
                            </div>

                            <button 
                                onClick={handleAnalyzeVideo}
                                disabled={isAnalyzing}
                                className="w-full mt-6 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 text-white font-black uppercase py-3 rounded-lg transition-all flex items-center justify-center gap-2 active:scale-[0.98]"
                            >
                                {isAnalyzing ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Play className="w-3.5 h-3.5 fill-current" />}
                                <span className="text-[9px] tracking-widest">{isAnalyzing ? "RUNNING..." : "RUN ENGINE"}</span>
                            </button>
                        </div>
                    )}
                </div>

                {/* Main Console Output */}
                <div className="lg:col-span-9 flex flex-col h-full bg-black/40 border border-slate-800/80 rounded-xl overflow-hidden relative">
                    <div className="flex items-center justify-between p-3 border-b border-slate-800 bg-slate-900/10">
                        <div className="flex items-center gap-2">
                            <Terminal className="w-3.5 h-3.5 text-indigo-500" />
                            <span className="text-[9px] font-black uppercase tracking-widest text-slate-500">Log Stream</span>
                        </div>
                        <div className={`w-2 h-2 rounded-full ${isAnalyzing ? 'bg-indigo-500 animate-pulse' : 'bg-slate-800'}`} />
                    </div>

                    <div className="flex-1 overflow-y-auto custom-scrollbar p-4 font-mono text-[10px] space-y-1 bg-black/20">
                        {logs.length === 0 ? (
                            <div className="h-full flex flex-col items-center justify-center opacity-20">
                                <p className="uppercase font-black text-[9px] tracking-[0.4em]">Ready to Process</p>
                            </div>
                        ) : (
                            <div className="flex flex-col">
                                {logs.map(log => (
                                    <div key={log.id} className={`py-0.5 border-l-2 pl-3 ${
                                        log.type === 'success' ? 'text-green-400 border-green-500/40 bg-green-500/5' : 
                                        log.type === 'result' ? 'text-white text-sm font-black border-indigo-500 bg-indigo-500/10 py-2 my-2' :
                                        log.type === 'debug' ? 'text-slate-500 border-slate-700 italic' :
                                        log.type === 'warning' ? 'text-yellow-400 border-yellow-500/40' : 
                                        log.type === 'frame' ? 'text-slate-700 border-indigo-500/5' : 
                                        'text-indigo-400 border-indigo-500/20'
                                    }`}>
                                        <span className="flex items-center gap-2">
                                            {log.type === 'result' && <ChevronRight className="w-3 h-3 text-indigo-400" />}
                                            {log.message}
                                        </span>
                                    </div>
                                ))}
                                <div ref={logEndRef} className="h-4" />
                            </div>
                        )}
                    </div>

                    {uploadProgress > 0 && (
                        <div className="absolute bottom-0 inset-x-0 h-1 bg-slate-900"><div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${uploadProgress}%` }} /></div>
                    )}
                </div>
              </div>
            </div>
          )}

          {/* Minimal Recognition Pill Label */}
          {prediction && (
            <div className="absolute inset-x-0 bottom-8 flex justify-center pointer-events-none px-6 z-40">
                <div className={`flex items-center gap-4 px-6 py-2 rounded-full shadow-2xl border backdrop-blur-xl animate-in fade-in zoom-in duration-300 pointer-events-auto ${
                    isNA ? 'bg-slate-900/95 border-slate-700' : 'bg-indigo-600/95 border-white/20'
                }`}>
                    <div className="flex flex-col">
                        <span className="text-[7px] font-black uppercase tracking-[0.3em] text-white/50 leading-none mb-1">
                            {prediction.word === 'ERROR' ? 'FAIL' : (isNA ? "UNCERTAIN" : "RECOGNIZED")}
                        </span>
                        <h2 className="text-xl font-black tracking-tight uppercase text-white leading-none">
                            {prediction.word}
                        </h2>
                    </div>

                    {!isNA && (
                        <div className="flex items-center gap-3 border-l border-white/20 pl-4">
                            <div className="flex flex-col">
                                <div className="flex items-center gap-2">
                                    <span className="text-[9px] font-bold text-white">{Math.round(prediction.confidence * 100)}%</span>
                                    <div className="h-1 w-12 bg-black/30 rounded-full overflow-hidden">
                                        <div className="h-full bg-white transition-all duration-1000" style={{ width: `${prediction.confidence * 100}%` }} />
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    <button onClick={() => setPrediction(null)} className="ml-2 p-1 hover:bg-white/10 rounded-full transition-colors"><X className="w-3 h-3 text-white/50" /></button>
                </div>
            </div>
          )}

          {/* Status Instructions (Live Only) */}
          {appMode === 'LIVE' && !prediction && (
              <div className="absolute inset-x-0 bottom-8 flex justify-center pointer-events-none z-40">
                  <div className={`px-6 py-2 rounded-full border backdrop-blur-xl shadow-xl flex items-center gap-2 ${
                      viewportStatus.state === 'READY' ? 'bg-indigo-500/10 border-indigo-500/40 text-indigo-400' : (viewportStatus.state === 'RECORDING' ? 'bg-red-500/20 border-red-500/40 text-red-400' : 'bg-slate-900/60 border-slate-800 text-slate-500')
                  }`}>
                      <span className="text-[9px] font-black uppercase tracking-[0.2em]">{viewportStatus.instruction}</span>
                  </div>
              </div>
          )}
        </div>
      </main>
    </div>
  );
};

