import * as ort from 'onnxruntime-web';
import { PredictionResult, AppConfig } from "../types";

const ORT_VERSION = '1.20.0';
const CDN_URL = `https://cdn.jsdelivr.net/npm/onnxruntime-web@${ORT_VERSION}/dist/`;

ort.env.wasm.wasmPaths = CDN_URL;
ort.env.wasm.numThreads = 1;
ort.env.wasm.simd = false;
ort.env.wasm.proxy = false; 

export interface InferenceDebugInfo {
  min: number;
  max: number;
  mean: number;
  top5: { word: string; confidence: number }[];
}

export class SignEngine {
  private session: ort.InferenceSession | null = null;
  private isModelLoaded = false;
  private isInitializing = true;
  private initializationError: string | null = null;

  constructor() {
    this.initLocalModel();
  }

  private async initLocalModel() {
    try {
      console.log("SignEngine: Loading model...");
      const response = await fetch('./models/model.onnx');
      if (!response.ok) {
        throw new Error(`ONNX model not found at ./models/model.onnx`);
      }
      const modelBuffer = await response.arrayBuffer();
      const modelUint8 = new Uint8Array(modelBuffer);
      this.session = await ort.InferenceSession.create(modelUint8, {
        executionProviders: ['wasm'],
        graphOptimizationLevel: 'all'
      });
      this.isModelLoaded = true;
      console.log("SignEngine: Ready. Input shape:", this.session.inputNames[0], this.session.inputNames);
    } catch (e: any) {
      this.initializationError = e.message || "Init failed";
      console.error("SignEngine Error:", e);
      this.isModelLoaded = false;
    } finally {
      this.isInitializing = false;
    }
  }

  private softmax(arr: number[]): number[] {
    const maxLogit = Math.max(...arr);
    const exps = arr.map(x => Math.exp(x - maxLogit));
    const sumExps = exps.reduce((a, b) => a + b, 0);
    return exps.map(x => x / (sumExps || 1));
  }

  async predict(sequence: number[][], config: AppConfig): Promise<{ result: PredictionResult | null; debug: InferenceDebugInfo } | null> {
    if (!this.isModelLoaded || !this.session) return null;

    try {
      const targetFrames = config.model_config.target_frames; // 64
      const landmarkCount = 75; 
      const coordCount = 3;
      const totalFeatures = landmarkCount * coordCount; // 225

      const flattened = new Float32Array(targetFrames * totalFeatures);
      let sum = 0;
      let min = Infinity;
      let max = -Infinity;

      for (let i = 0; i < targetFrames; i++) {
        if (sequence[i]) {
          flattened.set(sequence[i], i * totalFeatures);
          for (let val of sequence[i]) {
            sum += val;
            if (val < min) min = val;
            if (val > max) max = val;
          }
        }
      }

      const mean = sum / flattened.length;

      // Ensure we match the exact input shape from config
      const shape = config.model_config.input_shape || [1, targetFrames, landmarkCount, coordCount];
      const tensor = new ort.Tensor('float32', flattened, shape);
      const inputName = this.session.inputNames[0];
      const feeds: Record<string, ort.Tensor> = { [inputName]: tensor };

      const results = await this.session.run(feeds);
      const outputName = this.session.outputNames[0];
      const outputTensor = results[outputName];

      const outputData = Array.from(outputTensor.data as Float32Array);
      const probs = this.softmax(outputData);

      // Get Top 5
      const indexedProbs = probs.map((p, i) => ({ word: config.model_config.labels[i] || `Label_${i}`, confidence: p }));
      indexedProbs.sort((a, b) => b.confidence - a.confidence);
      const top5 = indexedProbs.slice(0, 5);

      const maxPred = top5[0];

      const debug: InferenceDebugInfo = {
        min, max, mean, top5
      };

      if (maxPred.confidence >= config.inference_logic.confidence_threshold) {
        return {
          result: maxPred,
          debug
        };
      } else {
        return {
          result: { word: 'NA', confidence: maxPred.confidence },
          debug
        };
      }
    } catch (err) {
      console.error("SignEngine Prediction Loop Error:", err);
    }
    return null;
  }

  public getEngineStatus() {
    if (this.isInitializing) return 'BOOTING...';
    if (this.initializationError) return 'INIT FAILED';
    return this.isModelLoaded ? 'READY (75-KP)' : 'OFFLINE';
  }
}

