import React, { useState, useEffect, useRef } from 'react';
import { Zap, RefreshCw, Database, SearchX, Upload, Play, CheckCircle2, Settings, X, Loader2, Video, Terminal, Activity, FileVideo, Trash2, Cpu, AlertCircle, ChevronRight, Info, RotateCcw } from 'lucide-react';
import HolisticCamera from './components/HolisticCamera';
