          )}

          {/* Unified Sleek Result Pill */}
          {prediction && (
            <div className="absolute inset-x-0 bottom-6 flex justify-center pointer-events-none px-6 z-40">
                <div className={`flex items-center gap-4 px-5 py-2 rounded-full shadow-2xl border backdrop-blur-xl animate-in fade-in slide-in-from-bottom-4 duration-300 pointer-events-auto ${
                    isNA ? 'bg-slate-900/95 border-slate-700' : 'bg-indigo-600/95 border-white/20'
                }`}>
