                            <div className="h-1 w-10 bg-black/40 rounded-full overflow-hidden">
                                <div className="h-full bg-white transition-all duration-1000" style={{ width: `${prediction.confidence * 100}%` }} />
                            </div>
                        </div>
                    )}
                    <button onClick={() => setPrediction(null)} className="ml-1 p-0.5 hover:bg-white/10 rounded-full transition-colors"><X className="w-3 h-3 text-white/40" /></button>
                </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

