                                {logs.map(log => (
                                    <div key={log.id} className={`py-0.5 border-l-2 pl-3 transition-all duration-300 ${
                                        log.type === 'success' ? 'text-green-400 border-green-500/40 bg-green-500/5' : 
                                        log.type === 'result' ? 'text-white text-sm font-black border-indigo-500 bg-indigo-500/10 py-3 my-2 shadow-[inset_0_0_20px_rgba(79,70,229,0.1)]' :
                                        log.type === 'debug' ? 'text-slate-500 italic' :
                                        log.type === 'warning' ? 'text-red-400 border-red-500/40 bg-red-500/5' : 
