                    </div>

                    {uploadProgress > 0 && (
                        <div className="absolute bottom-0 inset-x-0 h-1 bg-slate-900">
                            <div className="h-full bg-indigo-500 transition-all duration-300 shadow-[0_0_15px_#4f46e5]" style={{ width: `${uploadProgress}%` }} />
                        </div>
