              </div>
            </div>
          )}

          {/* Minimal Prediction Pill */}
          {prediction && (
            <div className="absolute inset-x-0 bottom-6 flex justify-center pointer-events-none px-6 z-40">
                <div className={`flex items-center gap-4 px-5 py-2.5 rounded-full shadow-2xl border backdrop-blur-xl animate-in fade-in slide-in-from-bottom-4 duration-300 pointer-events-auto ${
                    isNA ? 'bg-slate-900/95 border-slate-700' : 'bg-indigo-600/95 border-white/20'
                }`}>
                    <div className="flex flex-col">
                        <span className="text-[6px] font-black uppercase tracking-[0.4em] text-white/50 leading-none mb-1">
                            {prediction.word === 'ERROR' ? 'FAIL' : (isNA ? "UNCERTAIN" : "RESULT")}
                        </span>
                        <h2 className="text-lg font-black tracking-tight uppercase text-white leading-none">
                            {prediction.word}
                        </h2>
                    </div>

                    {!isNA && (
                        <div className="flex items-center gap-3 border-l border-white/20 pl-4">
                            <span className="text-[10px] font-bold text-white/90">{Math.round(prediction.confidence * 100)}%</span>
                            <div className="h-1.5 w-12 bg-black/40 rounded-full overflow-hidden">
                                <div className="h-full bg-white transition-all duration-1000" style={{ width: `${prediction.confidence * 100}%` }} />
                            </div>
                        </div>
                    )}
                    <button onClick={() => setPrediction(null)} className="ml-1 p-0.5 hover:bg-white/10 rounded-full transition-colors"><X className="w-3.5 h-3.5 text-white/40" /></button>
                </div>
            </div>
          )}

          {/* Status HUD (Live Only) */}
          {appMode === 'LIVE' && !prediction && (
              <div className="absolute inset-x-0 bottom-8 flex justify-center pointer-events-none z-40">
                  <div className={`px-5 py-1.5 rounded-full border backdrop-blur-xl shadow-xl flex items-center gap-2 transition-all duration-300 ${
                      viewportStatus.state === 'READY' ? 'bg-indigo-500/10 border-indigo-500/40 text-indigo-400' : (viewportStatus.state === 'RECORDING' ? 'bg-red-500/20 border-red-500/40 text-red-400' : 'bg-slate-900/60 border-slate-800 text-slate-500')
                  }`}>
                      <span className="text-[9px] font-black uppercase tracking-[0.3em]">{viewportStatus.instruction}</span>
                  </div>
              </div>
          )}
        </div>
      </main>
    </div>
  );
};

