import * as HolisticModule from '@mediapipe/holistic';
import { AppConfig } from '../types';

export interface FrameMetadata {
  pose: number;
  lh: number;
  rh: number;
  refX: number;
  refY: number;
  scale: number;
}

export class VideoProcessor {
  private holistic: any;

  constructor() {
    const HolisticClass = (HolisticModule as any).Holistic || (HolisticModule as any).default?.Holistic;
    this.holistic = new HolisticClass({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`,
    });

    this.holistic.setOptions({
      modelComplexity: 1,
      smoothLandmarks: false,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
    });
  }

  async processVideo(
    file: File, 
    config: AppConfig, 
    onProgress: (p: number) => void,
    onFrameLog?: (frameIdx: number, meta: FrameMetadata) => void
  ): Promise<number[][]> {
    const video = document.createElement('video');
    video.src = URL.createObjectURL(file);
    video.muted = true;
    video.playsInline = true;

    await new Promise((resolve) => {
      video.onloadedmetadata = resolve;
    });

    const targetFrames = config.model_config.target_frames;
    const duration = video.duration;
    const interval = duration / targetFrames;
    const sequence: number[][] = [];

    let resolveFrame: ((result: { data: number[], meta: FrameMetadata }) => void) | null = null;
    this.holistic.onResults((results: any) => {
        const frameData: number[] = [];
        let refX = 0, refY = 0, refZ = 0, scaleFactor = 1.0;
        const epsilon = 1e-8;

        // STEP 1: CALCULATE CANONICAL NORMALIZATION (Matches Training)
        if (results.poseLandmarks && results.poseLandmarks[11] && results.poseLandmarks[12]) {
          const lS = results.poseLandmarks[11], rS = results.poseLandmarks[12];
          refX = (lS.x + rS.x) / 2;
          refY = (lS.y + rS.y) / 2;
          refZ = (lS.z + rS.z) / 2;

          const shoulderWidth = Math.sqrt(
            Math.pow(lS.x - rS.x, 2) + 
            Math.pow(lS.y - rS.y, 2) + 
            Math.pow((lS.z || 0) - (rS.z || 0), 2)
          );
          scaleFactor = 1.0 / (shoulderWidth + epsilon);
        }

        const extract = (pts: any[] | undefined, count: number) => {
          for (let i = 0; i < count; i++) {
            const p = pts ? pts[i] : null;
            if (p) {
              frameData.push(
                (p.x - refX) * scaleFactor, 
                (p.y - refY) * scaleFactor, 
                ((p.z || 0) - refZ) * scaleFactor
              );
            } else {
              frameData.push(0, 0, 0);
            }
          }
        };

        // STEP 2: EXTRACT 75 KEYPOINTS (Pose: 33, LH: 21, RH: 21)
        extract(results.poseLandmarks, 33);
        extract(results.leftHandLandmarks, 21);
        extract(results.rightHandLandmarks, 21);

        const meta: FrameMetadata = {
            pose: results.poseLandmarks?.length || 0,
            lh: results.leftHandLandmarks?.length || 0,
            rh: results.rightHandLandmarks?.length || 0,
            refX,
            refY,
            scale: 1.0 / scaleFactor // Displaying the actual width for debug
        };

        if (resolveFrame) resolveFrame({ data: frameData, meta });
    });

    for (let i = 0; i < targetFrames; i++) {
      video.currentTime = Math.min(i * interval, duration);
      await new Promise((resolve) => { video.onseeked = resolve; });
      const frameResult = await new Promise<{ data: number[], meta: FrameMetadata }>((resolve) => {
        resolveFrame = resolve;
        this.holistic.send({ image: video });
      });
      sequence.push(frameResult.data);
      if (onFrameLog) onFrameLog(i, frameResult.meta);
      onProgress(Math.round(((i + 1) / targetFrames) * 100));
    }

    // STEP 3: SEQUENCE PADDING (Repeat last frame if necessary)
    while (sequence.length < targetFrames) {
        sequence.push([...sequence[sequence.length - 1]]);
    }

    URL.revokeObjectURL(video.src);
    this.holistic.onResults(() => {}); 
    return sequence;
  }
}

export const videoProcessor = new VideoProcessor();

import React, { useEffect, useRef, useState } from 'react';
import * as HolisticModule from '@mediapipe/holistic';
import * as CameraModule from '@mediapipe/camera_utils';
import * as DrawingModule from '@mediapipe/drawing_utils';
import { HolisticResults, AppConfig, ViewportStatus, PredictionResult, SessionState } from '../types';

interface HolisticCameraProps {
  enabled: boolean;
  config: AppConfig;
  facingMode: 'user' | 'environment';
  isMirrored: boolean;
  prediction: PredictionResult | null;
  isAnalyzing: boolean;
  onViewportStatusChange: (status: ViewportStatus) => void;
  onResults: (results: HolisticResults, filteredPoints: number[]) => void;
  onSequenceComplete: (sequence: number[][]) => void;
  onFpsUpdate: (fps: number) => void;
}

const HolisticCamera: React.FC<HolisticCameraProps> = ({ 
  enabled, config, facingMode, isMirrored, prediction, isAnalyzing, 
  onViewportStatusChange, onResults, onSequenceComplete, onFpsUpdate 
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<{ type: string; message: string } | null>(null);
  const [sessionState, setSessionState] = useState<SessionState>('IDLE');

  const sessionStateRef = useRef<SessionState>('IDLE');
  const lastViewportStateRef = useRef<string>('');
  const sequenceBuffer = useRef<number[][]>([]);
  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);
  const cameraInstanceRef = useRef<any>(null);
  const holisticInstanceRef = useRef<any>(null);

  const checkHandActivity = (results: any): boolean => {
    if (!results.poseLandmarks) return false;
    const lS = results.poseLandmarks[11];
    const rS = results.poseLandmarks[12];
    if (!lS || !rS) return false;
    const threshold = Math.min(lS.y, rS.y) + 0.1;
    return !!((results.leftHandLandmarks && results.leftHandLandmarks.some((p: any) => p.y < threshold)) || 
              (results.rightHandLandmarks && results.rightHandLandmarks.some((p: any) => p.y < threshold)));
  };

  const alignSequenceLength = (sequence: number[][], target: number): number[][] => {
    if (sequence.length === 0) return Array(target).fill(Array(225).fill(0));
    if (sequence.length >= target) {
      const start = Math.floor((sequence.length - target) / 2);
      return sequence.slice(start, start + target);
    }
    const aligned = [...sequence];
    const lastFrame = sequence[sequence.length - 1];
    while (aligned.length < target) { aligned.push([...lastFrame]); }
    return aligned;
  };

  const checkViewportLogic = (poseLandmarks: any[] | undefined): ViewportStatus => {
    if (!poseLandmarks || poseLandmarks.length === 0) return { state: 'NOT_DETECTED', instruction: 'Detecting User...' };
    const lS = poseLandmarks[11], rS = poseLandmarks[12];
    if (!lS || !rS) return { state: 'NOT_DETECTED', instruction: 'Show Full Torso' };
    const shoulderScale = Math.hypot(rS.x - lS.x, rS.y - lS.y);
    if (shoulderScale > 0.65) return { state: 'TOO_CLOSE', instruction: 'MOVE BACK' };
    if (shoulderScale < 0.05) return { state: 'TOO_FAR', instruction: 'MOVE CLOSER' };
    if (sessionStateRef.current === 'RECORDING') return { state: 'RECORDING', instruction: 'RECORDING...' };
    if (isAnalyzing) return { state: 'ANALYZING', instruction: 'ANALYZING...' };
    return { state: 'READY', instruction: 'READY' };
  };

  useEffect(() => {
    if (!enabled) {
        if (cameraInstanceRef.current) cameraInstanceRef.current.stop();
        if (holisticInstanceRef.current) holisticInstanceRef.current.close();
        cameraInstanceRef.current = null;
        holisticInstanceRef.current = null;
        setSessionState('IDLE');
        sessionStateRef.current = 'IDLE';
        return;
    }

    const active = { current: true };
    const HolisticClass = (HolisticModule as any).Holistic || (HolisticModule as any).default?.Holistic;
    const POSE_CONNECTIONS = (HolisticModule as any).POSE_CONNECTIONS || (HolisticModule as any).default?.POSE_CONNECTIONS;
    const HAND_CONNECTIONS = (HolisticModule as any).HAND_CONNECTIONS || (HolisticModule as any).default?.HAND_CONNECTIONS;
    const drawConnectors = (DrawingModule as any).drawConnectors || (DrawingModule as any).default?.drawConnectors;
    const drawLandmarks = (DrawingModule as any).drawLandmarks || (DrawingModule as any).default?.drawLandmarks;

    const holistic = new HolisticClass({ locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}` });
    holisticInstanceRef.current = holistic;
    holistic.setOptions({ modelComplexity: 1, smoothLandmarks: true, minDetectionConfidence: 0.5, minTrackingConfidence: 0.5 });

    holistic.onResults((results: any) => {
      if (!active.current || !enabled) return;
      const viewport = checkViewportLogic(results.poseLandmarks);
      if (viewport.state !== lastViewportStateRef.current) {
          lastViewportStateRef.current = viewport.state;
          onViewportStatusChange(viewport);
      }

      const frameData: number[] = [];
      let refX = 0, refY = 0, refZ = 0, scaleFactor = 1.0;
      const epsilon = 1e-8;

      // STEP 1: CALCULATE CANONICAL NORMALIZATION
      if (results.poseLandmarks && results.poseLandmarks[11] && results.poseLandmarks[12]) {
        const lS = results.poseLandmarks[11], rS = results.poseLandmarks[12];
        refX = (lS.x + rS.x) / 2;
        refY = (lS.y + rS.y) / 2;
        refZ = (lS.z + rS.z) / 2;

        const shoulderWidth = Math.sqrt(
          Math.pow(lS.x - rS.x, 2) + 
          Math.pow(lS.y - rS.y, 2) + 
          Math.pow((lS.z || 0) - (rS.z || 0), 2)
        );
        scaleFactor = 1.0 / (shoulderWidth + epsilon);
      }

      const extractSection = (landmarks: any[] | undefined, expectedCount: number) => {
        for (let i = 0; i < expectedCount; i++) {
          const p = landmarks ? landmarks[i] : null;
          if (p) {
            frameData.push(
                (p.x - refX) * scaleFactor, 
                (p.y - refY) * scaleFactor, 
                ((p.z || 0) - refZ) * scaleFactor
            );
          } else {
            frameData.push(0, 0, 0);
          }
        }
      };

      // STEP 2: EXTRACT 75 KEYPOINTS
      extractSection(results.poseLandmarks, 33);
      extractSection(results.leftHandLandmarks, 21);
      extractSection(results.rightHandLandmarks, 21);

      const handsActive = checkHandActivity(results);
      if (sessionStateRef.current === 'IDLE' && handsActive && viewport.state === 'READY') {
        sessionStateRef.current = 'RECORDING';
        setSessionState('RECORDING');
        sequenceBuffer.current = [frameData];
      } else if (sessionStateRef.current === 'RECORDING') {
        sequenceBuffer.current.push(frameData);
        if (!handsActive || sequenceBuffer.current.length >= 100) {
          if (sequenceBuffer.current.length > 5) { 
            sessionStateRef.current = 'ANALYZING';
            setSessionState('ANALYZING');
            onSequenceComplete(alignSequenceLength([...sequenceBuffer.current], config.model_config.target_frames));
            setTimeout(() => { sessionStateRef.current = 'IDLE'; setSessionState('IDLE'); sequenceBuffer.current = []; }, config.inference_logic.prediction_cooldown_ms);
          } else {
            sessionStateRef.current = 'IDLE'; setSessionState('IDLE'); sequenceBuffer.current = [];
          }
        }
      }

      onResults(results, frameData);
      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current >= 1000) {
        onFpsUpdate(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0; lastTimeRef.current = now;
      }

      const canvasCtx = canvasRef.current?.getContext('2d');
      if (!canvasCtx || !canvasRef.current) return;
      canvasCtx.save();
      canvasCtx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      if (isMirrored) { canvasCtx.scale(-1, 1); canvasCtx.translate(-canvasRef.current.width, 0); }
      canvasCtx.drawImage(results.image, 0, 0, canvasRef.current.width, canvasRef.current.height);
      const drawSet = (pts: any[], conn: any, color: string) => {
        if (!pts) return;
        drawConnectors(canvasCtx, pts, conn, { color, lineWidth: 1.5 });
        drawLandmarks(canvasCtx, pts, { color, lineWidth: 2, radius: 2 });
      };
      drawSet(results.poseLandmarks, POSE_CONNECTIONS, config.visual_config.colors.pose);
      drawSet(results.leftHandLandmarks, HAND_CONNECTIONS, config.visual_config.colors.hands);
      drawSet(results.rightHandLandmarks, HAND_CONNECTIONS, config.visual_config.colors.hands);
      canvasCtx.restore();
      if (isLoading) setIsLoading(false);
    });

    const CameraClass = (CameraModule as any).Camera || (CameraModule as any).default?.Camera;
    cameraInstanceRef.current = new CameraClass(videoRef.current!, {
      onFrame: async () => { 
        if (videoRef.current && active.current && enabled && holisticInstanceRef.current) {
          try { await holisticInstanceRef.current.send({ image: videoRef.current }); } catch (e) {}
        }
      },
      width: 1280, height: 720, facingMode
    });
    cameraInstanceRef.current.start().catch(() => { setError({ type: 'HARDWARE', message: 'Camera access error.' }); setIsLoading(false); });

    return () => { active.current = false; if (cameraInstanceRef.current) cameraInstanceRef.current.stop(); if (holisticInstanceRef.current) holisticInstanceRef.current.close(); };
  }, [config, facingMode, isMirrored, enabled]);

  return (
    <div className={`relative w-full h-full bg-black overflow-hidden transition-all duration-300 ${sessionState === 'RECORDING' ? 'ring-2 ring-red-500 ring-inset' : ''}`}>
      {isLoading && enabled && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-950">
          <div className="w-8 h-8 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"/>
          <p className="text-indigo-400 font-bold uppercase tracking-widest text-[8px]">Loading Vision System...</p>
        </div>
      )}
      {sessionState === 'RECORDING' && (
          <div className="absolute top-20 left-1/2 -translate-x-1/2 z-30 flex items-center gap-2 bg-slate-900/90 px-3 py-1.5 rounded-full border border-red-500/30">
              <span className="w-2 h-2 bg-red-500 rounded-full animate-pulse" />
              <span className="text-white text-[8px] font-black uppercase tracking-widest">Recording</span>
          </div>
      )}
      <video ref={videoRef} className="hidden" playsInline muted />
      <canvas ref={canvasRef} className={`w-full h-full object-cover ${!enabled ? 'hidden' : ''}`} width={1280} height={720} />
    </div>
  );
};

