import * as HolisticModule from '@mediapipe/holistic';
import { AppConfig } from '../types';

export class VideoProcessor {
  private holistic: any;

  constructor() {
    const HolisticClass = (HolisticModule as any).Holistic || (HolisticModule as any).default?.Holistic;
    this.holistic = new HolisticClass({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`,
    });

    this.holistic.setOptions({
      modelComplexity: 1,
      smoothLandmarks: false,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
    });
  }

  async processVideo(
    file: File, 
    config: AppConfig, 
    onProgress: (p: number) => void,
    onStepLog: (msg: string, type: 'info'|'success'|'warning'|'frame'|'result'|'debug') => void
  ): Promise<number[][]> {
    const video = document.createElement('video');
    video.src = URL.createObjectURL(file);
    video.muted = true;
    video.playsInline = true;

    onStepLog("ŌÜÖ’ĖÅ ACTION 3: BOOTING FRAME EXTRACTION ENGINE", "info");

    await new Promise((resolve) => {
      video.onloadedmetadata = resolve;
    });

    const targetFrames = 64; 
    const duration = video.duration;
    const interval = duration / targetFrames;
    const sequence: number[][] = [];

    let totalMissingL = 0;
    let totalMissingR = 0;
    let sampleScale = 0;
    let sampleMidpoint = { x: 0, y: 0 };

    let resolveFrame: ((result: { data: number[] }) => void) | null = null;

    this.holistic.onResults((results: any) => {
        const frameData: number[] = [];
        let refX = 0, refY = 0, refZ = 0, scaleFactor = 1.0;
        const epsilon = 1e-8;

        // ACTION 4.1 & 4.2: Compute Shoulder Metrics
        if (results.poseLandmarks && results.poseLandmarks[11] && results.poseLandmarks[12]) {
          const lS = results.poseLandmarks[11], rS = results.poseLandmarks[12];
          refX = (lS.x + rS.x) / 2;
          refY = (lS.y + rS.y) / 2;
          refZ = (lS.z + rS.z) / 2;

          const shoulderDistance = Math.sqrt(
            Math.pow(lS.x - rS.x, 2) + 
            Math.pow(lS.y - rS.y, 2) + 
            Math.pow((lS.z || 0) - (rS.z || 0), 2)
          );

          // ACTION 4.3: scale = 1 / shoulder_dist
          scaleFactor = shoulderDistance > epsilon ? 1.0 / shoulderDistance : 1.0;

          if (sampleScale === 0) {
            sampleScale = scaleFactor;
            sampleMidpoint = { x: refX, y: refY };
          }
        }

        // ACTION 1, 2, 4.4: Normalize and Zero-Pad
        // Pose (33)
        for (let i = 0; i < 33; i++) {
          const p = results.poseLandmarks ? results.poseLandmarks[i] : null;
          if (p) {
            frameData.push((p.x - refX) * scaleFactor, (p.y - refY) * scaleFactor, ((p.z || 0) - refZ) * scaleFactor);
          } else {
            frameData.push(0, 0, 0);
          }
        }

        // Left Hand (21)
        if (!results.leftHandLandmarks) totalMissingL++;
        for (let i = 0; i < 21; i++) {
          const p = (results.leftHandLandmarks && results.leftHandLandmarks[i]) ? results.leftHandLandmarks[i] : null;
          if (p) {
            frameData.push((p.x - refX) * scaleFactor, (p.y - refY) * scaleFactor, ((p.z || 0) - refZ) * scaleFactor);
          } else {
            frameData.push(0, 0, 0); // Action 2: Zeros for missing hands
          }
        }

        // Right Hand (21)
        if (!results.rightHandLandmarks) totalMissingR++;
        for (let i = 0; i < 21; i++) {
          const p = (results.rightHandLandmarks && results.rightHandLandmarks[i]) ? results.rightHandLandmarks[i] : null;
          if (p) {
            frameData.push((p.x - refX) * scaleFactor, (p.y - refY) * scaleFactor, ((p.z || 0) - refZ) * scaleFactor);
          } else {
            frameData.push(0, 0, 0); // Action 2: Zeros for missing hands
          }
        }

        if (resolveFrame) resolveFrame({ data: frameData });
    });

    for (let i = 0; i < targetFrames; i++) {
      video.currentTime = Math.min(i * interval, duration);
      await new Promise((resolve) => { video.onseeked = resolve; });
      const frameResult = await new Promise<{ data: number[] }>((resolve) => {
        resolveFrame = resolve;
        this.holistic.send({ image: video });
      });
      sequence.push(frameResult.data);
      onProgress(Math.round(((i + 1) / targetFrames) * 100));
    }

    onStepLog(`Ō£ö ACTION 4: NORMALIZATION SAMPLE`, "success");
    onStepLog(`   Ōå│ Shoulder Midpoint: (${sampleMidpoint.x.toFixed(3)}, ${sampleMidpoint.y.toFixed(3)})`, "debug");
    onStepLog(`   Ōå│ Global Scale Factor: ${sampleScale.toFixed(3)}`, "debug");

    onStepLog(`Ō£ö ACTION 2: IMPUTATION AUDIT`, "info");
    onStepLog(`   Ōå│ Zero-filled Left Hand: ${totalMissingL} frames`, "debug");
    onStepLog(`   Ōå│ Zero-filled Right Hand: ${totalMissingR} frames`, "debug");

    // ACTION 6: Pad Sequence (Repeat Last Frame)
    if (sequence.length > 0 && sequence.length < targetFrames) {
      const needed = targetFrames - sequence.length;
      onStepLog(`ŌÜÖ’ĖÅ ACTION 6: TEMPORAL PADDING`, "info");
      onStepLog(`   Ōå│ Detected: ${sequence.length} frames`, "debug");
      onStepLog(`   Ōå│ Repeating last frame ${needed} times to reach ${targetFrames}`, "debug");
      const lastValidFrame = [...sequence[sequence.length - 1]];
      while (sequence.length < targetFrames) {
          sequence.push(lastValidFrame);
      }
    }

    URL.revokeObjectURL(video.src);
    this.holistic.onResults(() => {}); 
    return sequence;
  }
}

