          addLog("ŌÜĀ’ĖÅ PREDICTION: NA (BELOW CONFIDENCE THRESHOLD)", "warning");
        } else {
          addLog(`­¤ÆÄ FINAL RECOGNITION: ${result?.word}`, "result");
        }
        setPrediction(result);
      }
    } catch (err) {
      addLog(`ŌØī PIPELINE CRASH: ${err instanceof Error ? err.message : 'Unknown exception'}`, 'warning');
      setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
      setIsAnalyzing(false);
      setUploadProgress(0);
    }
  };

