import * as HolisticModule from '@mediapipe/holistic';
import { AppConfig } from '../types';

export class VideoProcessor {
  private holistic: any;

  constructor() {
    const HolisticClass = (HolisticModule as any).Holistic || (HolisticModule as any).default?.Holistic;
    this.holistic = new HolisticClass({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`,
    });

    this.holistic.setOptions({
      modelComplexity: 1,
      smoothLandmarks: false,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
    });
  }

  async processVideo(
    file: File, 
    config: AppConfig, 
    onProgress: (p: number) => void,
    onStepLog: (msg: string, type: 'info'|'success'|'warning'|'frame'|'result'|'debug') => void
  ): Promise<number[][]> {
    const video = document.createElement('video');
    video.src = URL.createObjectURL(file);
    video.muted = true;
    video.playsInline = true;

    onStepLog("ŌÜÖ’ĖÅ BOOTING PER-FRAME 3D NORMALIZATION PIPELINE", "info");

    await new Promise((resolve) => {
      video.onloadedmetadata = resolve;
    });

    const targetFrames = 64; 
    const duration = video.duration;
    const interval = duration / targetFrames;
    const rawResults: any[] = [];

    let resolveFrame: ((result: any) => void) | null = null;
    this.holistic.onResults((results: any) => {
        if (resolveFrame) resolveFrame(results);
    });

    // STEP 1: Collect 64 Frames (Raw)
    onStepLog(`­¤ō” STEP 1: COLLECTING ${targetFrames} RAW FRAMES`, "info");
    for (let i = 0; i < targetFrames; i++) {
      video.currentTime = Math.min(i * interval, duration);
      await new Promise((resolve) => { video.onseeked = resolve; });
      const results = await new Promise<any>((resolve) => {
        resolveFrame = resolve;
        this.holistic.send({ image: video });
      });
      rawResults.push(results);
      onProgress(Math.round(((i + 1) / targetFrames) * 100));
      if (i % 16 === 0) onStepLog(`   Ōå│ Frame ${i} extracted...`, "frame");
    }

    // STEP 2 & 3: Apply Per-Frame 3D Normalization
    onStepLog(`­¤öä STEP 2: APPLYING INDEPENDENT 3D NORMALIZATION PER FRAME`, "info");
    const normalizedSequence: number[][] = rawResults.map((results, fIdx) => {
        const frameData: number[] = [];
        let refX = 0, refY = 0, refZ = 0, scaleFactor = 1.0;
        const epsilon = 1e-8;

        // Calculate 3D Midpoint and 3D Euclidean Distance for THIS frame
        if (results.poseLandmarks && results.poseLandmarks[11] && results.poseLandmarks[12]) {
            const lS = results.poseLandmarks[11];
            const rS = results.poseLandmarks[12];

            refX = (lS.x + rS.x) / 2;
            refY = (lS.y + rS.y) / 2;
            refZ = (lS.z + rS.z) / 2;

            // 3D Euclidean distance calculation
            const dist3D = Math.sqrt(
                Math.pow(lS.x - rS.x, 2) + 
                Math.pow(lS.y - rS.y, 2) +
                Math.pow((lS.z || 0) - (rS.z || 0), 2)
            );

            scaleFactor = dist3D > epsilon ? 1.0 / dist3D : 1.0;
        }

        // Apply normalization to the 75 keypoints in this frame
        // Pose (33)
        for (let i = 0; i < 33; i++) {
            const p = results.poseLandmarks ? results.poseLandmarks[i] : null;
            if (p) { frameData.push((p.x - refX) * scaleFactor, (p.y - refY) * scaleFactor, ((p.z || 0) - refZ) * scaleFactor); }
            else { frameData.push(0, 0, 0); }
        }
        // Left Hand (21)
        for (let i = 0; i < 21; i++) {
            const p = (results.leftHandLandmarks && results.leftHandLandmarks[i]) ? results.leftHandLandmarks[i] : null;
            if (p) { frameData.push((p.x - refX) * scaleFactor, (p.y - refY) * scaleFactor, ((p.z || 0) - refZ) * scaleFactor); }
            else { frameData.push(0, 0, 0); }
        }
        // Right Hand (21)
        for (let i = 0; i < 21; i++) {
            const p = (results.rightHandLandmarks && results.rightHandLandmarks[i]) ? results.rightHandLandmarks[i] : null;
            if (p) { frameData.push((p.x - refX) * scaleFactor, (p.y - refY) * scaleFactor, ((p.z || 0) - refZ) * scaleFactor); }
            else { frameData.push(0, 0, 0); }
        }

        if (fIdx === 0) {
            onStepLog(`­¤ōÉ Frame 0 Audit: Ref[${refX.toFixed(4)},${refY.toFixed(4)},${refZ.toFixed(4)}] Scale: ${scaleFactor.toFixed(4)}`, "debug");
        }

        return frameData;
    });

    // STEP 4: Pad (Repeat Last Frame)
    if (normalizedSequence.length > 0 && normalizedSequence.length < targetFrames) {
      const needed = targetFrames - normalizedSequence.length;
      onStepLog(`ŌÜÖ’ĖÅ STEP 3: PADDING SEQUENCE (+${needed} frames)`, "info");
      const lastFrame = [...normalizedSequence[normalizedSequence.length - 1]];
      while (normalizedSequence.length < targetFrames) {
          normalizedSequence.push(lastFrame);
      }
    }

    onStepLog("Ō£ģ PER-FRAME NORMALIZATION COMPLETE", "success");
    URL.revokeObjectURL(video.src);
    this.holistic.onResults(() => {}); 
    return normalizedSequence;
  }
}

